CREATE TABLE IF NOT EXISTS `jay_songs` (
  `id` INT NOT NULL AUTO_INCREMENT COMMENT '主键 ID',
  `sn` VARCHAR(50) DEFAULT NULL COMMENT '序号',
  `song_no` VARCHAR(50) DEFAULT NULL COMMENT '歌曲编号',
  `song_name` VARCHAR(255) NOT NULL COMMENT '歌曲名称',
  `composer` VARCHAR(100) DEFAULT NULL COMMENT '作曲人',
  `lyricist` VARCHAR(100) DEFAULT NULL COMMENT '作词人',
  `arranger` VARCHAR(100) DEFAULT NULL COMMENT '编曲人',
  `style` VARCHAR(100) DEFAULT NULL COMMENT '音乐风格',
  `synopsis` TEXT DEFAULT NULL COMMENT '简介',
  `album_no` VARCHAR(50) DEFAULT NULL COMMENT '专辑编号',
  `album_release_date` DATE DEFAULT NULL COMMENT '专辑发行日期',
  `album_name` VARCHAR(255) DEFAULT NULL COMMENT '专辑名称',
  `lyrics` TEXT DEFAULT NULL COMMENT '歌词',
  `created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_song_name` (`song_name`),
  KEY `idx_album_name` (`album_name`),
  KEY `idx_composer` (`composer`),
  KEY `idx_lyricist` (`lyricist`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='周杰伦歌曲表';


