INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (1, '1', '01', '可爱女人', '周杰伦', '徐若瑄', '周杰伦', 'R&B（节奏蓝调）', '这首歌是周杰伦早期典型的R&B作品，旋律流畅，带有慵懒的转音和节奏感', '一', '2000-11-01', 'JAY', '想要有直升机 想要和你飞到宇宙去 想要和你融化在一起 融化在银河里 我每天每天每天在想想想想着你 这样的甜蜜 让我开始相信命运 感谢地心引力 让我碰到你 漂亮的让我面红的可爱女人 温柔的让我心疼的可爱女人 透明的让我感动的可爱女人 坏坏的让我疯狂的可爱女人 世界这样大而我而我只是只小小小的蚂蚁 但我要尽全力全力全力保护你', '2025-10-29 20:21:10', '2025-10-30 20:54:45');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (2, '2', '02', '完美主义', '周杰伦', '方文山', '洪敬尧', 'Hip-Hop/Rap（嘻哈/说唱）', '这首歌以强烈的说唱为主，节奏感强，歌词展现了周杰伦对自己音乐的坚持，是典型的嘻哈风格', '一', '2000-11-01', 'JAY', '如果说怀疑 可以造句 如果说分离 能够翻译 如果这一切 真的可以 我想要将我的寂寞封闭 然后在这里 不限日期 然后将过去 慢慢温习　让我爱上你 那场悲剧 是你完美演出的一场戏 宁愿心碎哭泣 再狠狠忘记 你爱过我的证据 让晶莹的泪滴 闪烁成回忆 伤人的美丽 你的完美主义太彻底 让我连恨都难以下笔 将真心抽离写成日记 像是一场默剧 你的完美主义太彻底 分手的话像语言暴力 我已我无能为力再提起 决定中断熟悉', '2025-10-29 20:21:10', '2025-10-30 20:54:45');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (3, '3', '03', '星晴', '周杰伦', '周杰伦', '洪敬尧', '流行摇滚 (Pop Rock)', '旋律轻快、清新，以吉他为主要伴奏，是一首非常经典的流行情歌，带有摇滚元素', '一', '2000-11-01', 'JAY', '一步两步三步四步 望著天 手牵手 一颗两颗三颗四颗 连成线 看星星 一步两步三步四步 望著天 手牵手 　一颗两颗三颗四颗 连成线 看星 　乘著风 游荡在蓝天边 一片云掉落在我面前 　捏成你的形状 随风跟著我 一口一口吃掉忧愁 　载著你 彷佛载著阳光 不管到哪里都是晴天 　蝴蝶自在飞 花也布满天 一朵一朵因你而香 　试图让夕阳飞翔 带领你我环绕大自然 　迎著风 开始共渡每一天 　　手牵手 一步两步三步四步 望著天 　看星星 一颗两颗三颗四颗 连成线 背著背默默许下心愿 　　看远方的星否听的见 　看远方的星如果听的见 　它一定实现', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (4, '4', '04', '娘子', '周杰伦', '方文山', '周杰伦', '中国风 (Chinese Style)', '这首歌被认为是周杰伦“中国风”的开山之作之一，融合了传统五声音阶和现代R&B节奏，歌词意境古典', '一', '2000-11-01', 'JAY', 'Rap~ 娘子 娘子却依旧每日 折一枝杨柳，你在那里 在小村外的溪边河口 默默等著我，娘子依旧每日折一枝杨柳，你在那里 在小村外的溪边 默默等着 娘子，一壶好酒 再来一碗热粥 配上几斤的牛肉，　　我说店小二 三两银够不够，景色入秋 漫天黄沙凉过，塞北的客栈人多 牧草有没有 我马儿有些瘦，世事看透 江湖上潮起潮落 什么恩怨过错，在多年以后 还是让人难过 心伤透，娘子她人在江南等我 泪不休 语沉默，娘子却依旧每日折一枝杨柳，在小村外的溪边河口，默默的在等著我，家乡的爹娘早已苍老了轮廓， 娘子我欠你太多，天涯尽头 满脸风霜落寞，近乡情怯的我 相思寄红豆，相思寄红豆 无能为力的在人海中漂泊，心伤透，娘子她人在江南等我，泪不休 语沉默', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (5, '5', '05', '斗牛', '周杰伦', '方文山', '洪敬尧', 'Hip-Hop/Rap Rock（嘻哈/说唱摇滚）', '节奏强劲，带有说唱和摇滚元素，主题热血，充满力量感', '一', '2000-11-01', 'JAY', '有什么不妥 有话就直说，别窝在角落 不爽就反驳，到底跩什么 懂不懂篮球，有种不要走 三对三斗牛，三分球它在空中停留，所有人看著我 抛物线进球，单手过人运球 篮下妙传出手，漂亮的假动作 帅呆了我，全场盯人防守 篮下禁区游走，快攻抢篮板球 得分都靠我，你拿了球不投 又不会掩护我，　　选你这种队友 瞎透了我，Rap~说你说 分数怎么停留，一直在停留谁让它停留的，为什么 我女朋友 场外加油，你却还让我出糗，你说啊 你怎么抄我球，你说啊 你怎么打我手，你说 是不是你不想活，说 你怎么面对我，甩开球我满腔的怒火，我想揍你已经很久 别想走，说 你眼睛看着我，别发抖 你给我抬起头，有话去对医药箱说 别怪我', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (6, '6', '06', '黑色幽默', '周杰伦', '周杰伦', '钟兴民', 'R&B/流行 (R&B/Pop)', '旋律忧郁，情感深沉，属于抒情R&B，探讨了爱情中的无奈与自我欺骗', '一', '2000-11-01', 'JAY', '难过 是因为闷了很久，是因为想了太多，是心理起了作用，你说 苦笑常常陪着你，在一起有点勉强，　　该不该现在休了我，不想太多，我想一定是我听错弄错搞错，拜托 我想是你的脑袋有问题，随便说说，　　其实我早已经猜透看透不想多说，只是我怕眼泪撑不住，不懂 你的黑色幽默，想通 却又再考倒我，　　说散 你想很久了吧？我不想拆穿你，当作 是你开的玩笑，想通 却又再考倒我，说散 你想很久了吧？，　　败给你的黑色幽默，我的认真败给黑色幽默', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (7, '7', '07', '伊斯坦堡', '周杰伦', '徐若瑄', '洪敬尧', '世界音乐/流行 (World Music/Pop)', '运用了中东音乐元素（如乌德琴音色），营造出异域风情，属于世界音乐与流行的结合', '一', '2000-11-01', 'JAY', '走过了很多地方，我来到伊斯坦堡，就像是童话故事，有教堂有城堡，每天忙碌地寻找，到底什么我想要，却发现迷了路怎么找也找不着，心血来潮起个大早，怎么我也睡不着，昨晚梦里你来找，我才，原来我只想要你，陪我去吃汉堡，说穿了其实我的愿望就怎么小，就怎么每天祈祷我的心跳你知道，　杵在伊斯坦堡，却只想你和汉堡，我想要你的微笑每天都能看到，我知道这里很美但家乡的你更美', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (8, '8', '08', '印地安老斑鸠', '周杰伦', '方文山', '洪敬尧', 'Jazz/Hip-Hop (爵士/嘻哈)', '这首歌风格独特，带有爵士的慵懒和即兴感，配合说唱，展现了周杰伦玩音乐的趣味性', '一', '2000-11-01', 'JAY', '沙漠之中怎么会有泥鳅，话说完飞过一只海鸥，大峡谷的风呼啸而过，是谁说没有，有一条热昏头的响尾蛇，无力的躺在干枯的河，在等待雨季来临变沼泽，灰狼啃食著水鹿的骨头，秃鹰盘旋死盯着腐肉，草原上两只敌对野牛，在远方决斗，在一处被废弃的白蛦丘，站着一只饿昏的老斑鸠，印地安老斑鸠 腿短毛不多，几天都没有喝水也能活，脑袋瓜有一点秀逗，猎物死了它比谁都难过，印地安斑鸠 会学人开口，仙人掌怕羞 蜥蝪横著走，这里什么奇怪的事都有，包括像猫的狗，印地安老斑鸠 平常话不多，除非是乌鸦抢了它的窝，它在灌木丛旁邂逅，一只令它心仪的母斑鸠，Rap~ 牛仔红蕃 在小镇 背对背决斗，一只灰狼 问候我 谁是神枪手，巫师 他念念 有词的 对酋长，下诅咒 还我骷髅头 这故事，告诉我 印地安 的传说 还真是，瞎透了 什么都有', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (9, '9', '09', '龙卷风', '周杰伦', '徐若瑄', '钟兴民', '流行/抒情摇滚 (Pop/Ballad Rock)', '旋律抓耳，情感爆发力强，是典型的流行抒情摇滚，带有电子元素', '一', '2000-11-01', 'JAY', '爱像一阵风 吹完它就走，这样的节奏 谁都无可奈何，没有你以後 我灵魂失控，黑云在降落 我被它拖着走，静静悄悄默默离开，陷入了危险边缘 Baby~，我的世界已狂风暴雨，Wu~，爱情来的太快就像龙卷风，离不开暴风圈来不及逃，我不能再想 我不能再想，我不 我不 我不能，爱情走的太快 就像龙卷风，不能承受 我已无处可躲，我不要再想 我不要再想，我不 我不 我不要再想你，不知不觉 你已经离开我，不知不觉 我跟了这节奏，後知後觉 又过了一个秋，後知後觉 我该好好生活', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (10, '10', '10', '反方向的钟', '周杰伦', '方文山', '周杰伦', 'R&B/迷幻流行 (R&B/Alternative Pop)', '节奏缓慢，带有迷幻和忧郁的氛围，是典型的R&B抒情曲', '一', '2000-11-01', 'JAY', '迷迷蒙蒙 你给的梦 出现裂缝 隐隐作痛，怎么沟通 你都没空 说我不懂 说了没用，他的笑容 有何不同 在你心中 我不再受宠，我的天空 是雨是风 还是彩虹 你在操纵，恨自己真的没用 情绪激动，一颗心到现在还在抽痛，还为分手前那句抱歉 在感动，穿梭时间的画面的钟 从反方向 开始移动，回到当初爱你的时空 停格内容 不忠，所有回忆对着我进攻 我的伤口 被你拆封，誓言太沉重泪被纵容 脸上汹涌 失控，Rap~城市霓虹 不安跳动 染红夜空，过去种种 像一场梦 不敢去碰 一想就痛，心碎内容 每一秒钟 都有不同 你不懂，连一句珍重 也有苦衷 也不想送，寒风中 废墟烟囱 停止转动 一切落空，在人海中 盲目跟从 别人的梦 全面放纵，恨没有用 疗伤止痛 不在感动 没有梦，痛不知轻重 泪水鲜红 全面放纵', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (11, '11', '01', '爱在西元前', '周杰伦', '方文山', '林迈可', '中国风 (Chinese Style)', '以美索不达米亚文明为背景，旋律优美，编曲融合古典与现代，是标志性的中国风情歌', '二', '2001-09-18', '范特西', '古巴比伦王颁布了汉摩拉比法典，刻在黑色的玄武岩距今已经三千七百多年，你在橱窗前 凝视碑文的字眼，我却在旁静静欣赏你那张我深爱的脸，祭司 神殿 征战 弓箭 是谁的从前，喜欢在人潮中你只属于我的那画面，经过苏美女神身边 我以女神之名许愿，思念像底格里斯河般的漫延，当古文明只剩下难解的语言，传说就成了永垂不朽的诗篇，我给你的爱写在西元前 深埋在美索不达米亚平原，几十个世纪后出土发现 泥板上的字迹依然清晰可见，我给你的爱写在西元前 深埋在美索不达米亚平原，用楔形文字刻下了永远 那已风化千年的誓言，一切又重演，我感到很疲倦离家乡还是很远，害怕再也不能回到你身边，爱在西元前 爱在西元前', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (12, '12', '02', '爸我回来了', '周杰伦', '周杰伦', '钟兴民', 'Hip-Hop/Rap Rock (嘻哈/说唱摇滚)', '主题沉重，批判社会暴力，节奏强烈，说唱部分极具冲击力', '二', '2001-09-18', '范特西', '我听说通常在战争后就会换来和平，为什么看到我的爸爸一直打我妈妈，就因为喝醉酒 他就能拿我妈出气，我真的看不下去 以为我较细汉，从小到大只有妈妈的温暖 为什么我爸爸 那么凶，如果真的我有一双翅膀 两双翅膀，随时出发 偷偷出发 我一定带我妈走，从前的教育 别人的家庭，别人的爸爸种种的暴力因素一定都会有原因，但是呢 妈跟我都没有错亏我叫你一声爸～爸我回来了，不要再这样打我妈妈 我说的话 你甘会听？，不要再这样打我妈妈 难道你手 不会痛吗？，其实我回家就想要阻止一切 让家庭回到过去甜甜，温馨的欢乐香味 虽然这是我编造出来的事实，有点讽刺 有点酸性 但它却在这快乐社会发生产生共鸣，产生共鸣来阻止一切暴力 眼泪随着音符吸入血液情绪，从小到大你叫我学习你把你当榜样 好多的假像，妈妈常说乖～听你爸的话 你叫我怎么跟你像，不要再这样打我妈妈 我说的话 你甘会听？，不要再这样打我妈妈 难道你手 不会痛吗？，12345678 12345678，我叫你爸 你打我妈 这样对吗 干嘛这样，何必让酒牵鼻子走 瞎，说都说不听 听 痛是我们在痛 痛', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (13, '13', '03', '简单爱', '周杰伦', '徐若瑄', '林迈可', '流行/民谣摇滚 (Pop/Folk Rock)', '旋律简单清新，以木吉他为主，描绘纯真爱情，是轻快的流行摇滚', '二', '2001-09-18', '范特西', '说不上为什麽 我变得很主动，若爱上一个人 什麽都会值得去做，我想大声宣布 对你依依不舍，连隔壁邻居都猜到我现在的感受，河边的风 在吹着头发飘动，牵着你的手 一阵莫名感动，我想带你 回我的外婆家，一起看着日落 一直到我们都睡着，我想就这样牵着你的手不放开，爱能不能够永远单纯没有悲哀，我想带你骑单车 我想和你看棒球，想这样没担忧 唱着歌 一直走，我想就这样牵着你的手不放开，爱可不可以简简单单没有伤害，你靠着我的肩膀 你在我胸口睡着，像这样的生活 我爱你 你爱我，想 简 简 单 单 爱，想 简 简 单 单 爱，我想大声宣布 对你依依不舍，连隔壁邻居都猜到我现在的感受，河边的风 在吹着头发飘动，牵着你的手 一阵莫名感动，我想带你 回我的外婆家，一起看着日落 一直到我们都睡着，我想就这样牵着你的手不放开，爱能不能够永远单纯没有悲哀，我想带你骑单车 我想和你看棒球，想这样没担忧 唱着歌 一直走，我想就这样牵着你的手不放开，爱可不可以简简单单没有伤害，你靠着我的肩膀 你在我胸口睡着，像这样的生活 我爱你 你爱我，想 简 简 单 单 爱，想 简 简 单 单 爱，我想就这样牵着你的手不放开，爱能不能够永远单纯没有悲哀，我想带你骑单车 我想和你看棒球，想这样没担忧 唱着歌 一直走，我想就这样牵着你的手不放开，爱可不可以简简单单没有伤害，你靠着我的肩膀 你在我胸口睡着，像这样的生活 我爱你 你爱我', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (14, '14', '04', '忍者', '周杰伦', '方文山', '林迈可', '中国风/电子 (Chinese Style/Electronic)', '以日本忍者为题材，运用电子音效和中国五声音阶，节奏感强，风格独特', '二', '2001-09-18', '范特西', '居酒屋里的小神龛，离铺满鹅卵石的玄关，差不多一米宽的信仰，我坐着喝味噌汤 在旁观看 庭园假山，京都的夜晚 有一种 榻榻米 的稻香 叫做禅，那里～神社许愿 闪过一个画面，　这里～忍者蒙着脸 在角落吹暗箭，心里～幕府又重现，从前老东京那条山手线 像一出怀旧的默片，呵～～～ 呵～～～ 嘿～～～，呵～～～ 呵～～～ 嘿～～～，伊贺流忍者的想法 嘿～ 只会用武士刀比划 嘿～，我一个人在家 乖乖的学插花 (是 是 是 我知道），一二三四 樱花落满地 有一种神秘 凝结了空气，一二三四 黑夜里偷袭 去攻击 烟雾当武器，一二三四 忍者的物语 要切断过去 忠心是唯一，一二三四 隐身要彻底 要忘记 什么是自己', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (15, '15', '05', '开不了口', '周杰伦', '徐若瑄', '洪敬尧', '抒情流行 (Ballad Pop)', '旋律温柔动人，是周杰伦最经典的抒情慢歌之一，以钢琴和弦乐为主', '二', '2001-09-18', '范特西', '才离开没多久就开始 担心今天的你过的好不好，整个画面是你 想你想的睡不着，嘴嘟嘟那可爱的模样 还有在你身上香香的味道，我的快乐是你 想你想的都会笑，没有你在 我有多难熬（没有你在我有多难熬多烦恼），没有你烦 我有多烦恼（没有你烦我有多烦恼多难熬），穿过云层 我试着努力向你奔跑，爱才送到 你却已在别人怀抱，就是开不了口让她知道，我一定会呵护着你也逗你笑，你对我有多重要 我后悔没让你知道，安静的听你撒娇 看你睡着一直到老，就是开不了口让她知道，就是那么简单几句我办不到，整颗心悬在半空 我只能够远远看着，这些我都做得到 但那个人已经不是我', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (16, '16', '06', '上海一九四三', '周杰伦', '方文山', '林迈可', '中国风 (Chinese Style)', '以民国时期的上海为背景，旋律婉转，充满怀旧气息，是叙事性极强的中国风代表作', '二', '2001-09-18', '范特西', '泛黄的春联还残留在墙上，依稀可见几个字岁岁平安，在我没回去过的老家米缸，爷爷用楷书写一个满，黄金葛爬满了雕花的门窗，夕阳斜斜映在斑驳的砖墙，铺着榉木板的屋内还弥漫，姥姥当年酿的豆瓣酱，我对着黑白照片开始想象，爸和妈当年的模样，说着一口吴侬软语的姑娘缓缓走过外滩，消失的 旧时光 一九四三，在回忆 的路上 时间变好慢，老街坊 小弄堂，是属于那年代白墙黑瓦的淡淡的忧伤，消失的 旧时光 一九四三，回头看 的片段 有一些风霜，老唱盘 旧皮箱，装满了明信片的铁盒里藏着一片玫瑰花瓣', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (17, '17', '07', '对不起', '周杰伦', '方文山', '洪敬尧', 'R&B/流行 (R&B/Pop)', '节奏轻快，带有R&B的转音和律动，是一首道歉主题的流行情歌', '二', '2001-09-18', '范特西', '广场一枚铜币 悲伤的很隐秘，它在许愿池里轻轻叹息，太多的我爱你 让它喘不过气已经，失去意义，戒指在哭泣 静静躺在抽屉，它所拥有的只剩下回忆，相爱还有别离 像无法被安排的雨，随时准备来袭，我怀念起国小的课桌椅，怀念着用铅笔写日记，记录哪最原始的美丽，记录第一次遇见的你（Jay Chou），如果我遇见你是一场悲剧，我想我这辈子注定一个人演戏，最后再一个人慢慢的回忆，没有了过去 我将往事抽离，如果我遇见你是一场悲剧，我可以让生命就这样毫无意义，或许再最后能听到你一句，轻轻的叹息 后悔着对不起，如果我遇见你是一场悲剧，我轻轻的叹息 后悔着对不起', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (18, '18', '08', '威廉古堡', '周杰伦', '方文山', '洪敬尧', '哥特摇滚/电子 (Gothic Rock/Electronic)', '营造出神秘、阴森的古堡氛围，带有欧洲童话色彩，风格奇幻', '二', '2001-09-18', '范特西', '藤蔓植物 爬满了伯爵的坟墓，古堡里一片荒芜 长满杂草的泥土，不会骑扫把的胖女巫 用拉丁文念咒语啦啦呜，她养的黑猫笑起来像哭 啦啦啦呜 用水晶球替人占卜，她说下午三点阳光射进教堂的角度，能知道你前世是狼人还是蝙蝠，古堡主人威廉二世满脸的络腮胡，习惯 在吸完血后开始打呼，管家是一只会说法语举止优雅的猪，吸血前会念约翰福音做为弥补，拥有一双蓝色眼睛的凯瑟琳公主，专吃 有AB血型的公老鼠，恍恍惚惚 是谁的脚步，银制茶壶 装蟑螂蜘蛛，辛辛苦苦 全家怕日出，白色蜡烛 温暖了空屋', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (19, '19', '09', '双截棍', '周杰伦', '方文山', '钟兴民', '新金属/说唱摇滚 (Nu-Metal/Rap Rock)', '这首歌融合了重金属吉他、说唱和中国传统武术元素，节奏狂野，极具颠覆性', '二', '2001-09-18', '范特西', '岩烧店的烟味弥漫 隔壁是国术馆，店里面的妈妈桑 茶道 有三段，教拳脚武术的老板 练铁沙掌 耍杨家枪，硬底子功夫最擅长 还会金钟罩铁步衫，他们儿子我习惯 从小就耳濡目染，什么刀枪跟棍棒 我都耍的有模有样，什么兵器最喜欢 双截棍柔中带刚，想要去河南嵩山 学少林跟武当，干什么（客） 干什么（客） 呼吸吐纳心自在，干什么（客） 干什么（客） 气沉丹田手心开，干什么（客） 干什么（客） 日行千里系沙袋，飞檐走壁莫奇怪 去去就来，一个马步向前 一记左钩拳 右钩拳，一句惹毛我的人有危险 一再重演，一根我不抽的烟 一放好多年 它一直在身边，干什么（客） 干什么（客） 我打开任督二脉，干什么（客） 干什么（客） 东亚病夫的招牌，干什么（客） 干什么（客） 已被我一脚踢开，快使用双截棍 哼哼哈兮 快使用双截棍 哼哼哈兮，习武之人切记 仁者无敌 是谁在练太极 风生水起，快使用双截棍 哼哼哈兮 快使用双截棍 哼哼哈兮，如果我有轻功 飞檐走壁 为人耿直不屈 一身正气，快使用双截棍 哼，我用手刀防御 哼，漂亮的回旋踢', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (20, '20', '10', '安静', '周杰伦', '周杰伦', '钟兴民', '抒情流行/钢琴 ballad (Ballad Pop/Piano Ballad)', '旋律简单而深刻，以吉他和钢琴为主，情感真挚，是经典的情歌慢板', '二', '2001-09-18', '范特西', '只剩下钢琴陪我谈了一天，睡着的大提琴 安静的旧旧的 我想你已表现的非常明白，我懂我也知道 你没有舍不得，你说你也会难过我不相信，牵着你陪着我 也只是曾经，希望他是真的比我还要爱你，我才会逼自己离开，　你要我说多难堪 我根本不想分开，为什么还要我用微笑来带过，我没有这种天份 包容你也接受他，不用担心的太多 我会一直好好过，你已经远远离开 我也会慢慢走开，为什么我连分开都迁就着你，我真的没有天份 安静的没这么快，我会学着放弃你 是因为我太爱你', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (21, '21', '01', '半兽人', '周杰伦', '方文山', '林迈可', '新金属/电子摇滚 (Nu-Metal/Electro Rock)', '为游戏《魔兽争霸III》创作，充满力量感，融合了电子音效、重型吉他和说唱，营造出奇幻战场的氛围', '三', '2002-07-19', '八度空间', '再也没有纯白的灵魂，自人类堕落为半兽人，我开始使用第一人称，记录眼前所有的发生，嗜血森林醒来的早晨，任何侵略都成为可能，我用古老的咒语重温，吟 唱灵魂序曲寻根，面对魔界的邪吻 不被污染的转身，维持纯白的象征 然后还原为（人），让我们半兽人的灵魂翻滚，收起残忍回忆兽化的过程，让我们半兽人的眼神单纯，而非贪婪着永恒只对暴力忠诚，停止忿恨永无止尽的战争，让我们半兽人的灵魂单纯，对远古存在的神用谦卑的身份，泪沸腾 风异常的冰冷，马蹄声 让人睡不安稳，我在等 灵魂序曲完成，带领族人写下祈祷文，那城镇 无谓的在牺牲，战火焚 祭坛开始下沉，我在等觉悟后的族人，往南方 大地重新开垦', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (22, '22', '02', '半岛铁盒', '周杰伦', '周杰伦', '林迈可', 'R&B/另类流行 (R&B/Alternative Pop)', '旋律迷幻，节奏慵懒，带有叙事性和实验色彩，是周杰伦标志性的R&B抒情风格', '三', '2002-07-19', '八度空间', '（读者:呀,小姐请问一下是没有卖半岛铁盒?，店员:有呀。你从前面右转的第二排架上就有啊。，读者:好,谢谢。，店员:不会。），走廊灯关上 书包放，走到房间窗外望，回想刚买的书，一本名叫半岛铁盒，放在床边堆好多，第一页 第六页 第七页 序，我永远都想不到陪我看这书的你会要走，不再是 不再有 现在已经看不到，铁盒的钥匙孔 透了光 看见它锈了好久，好旧好旧 外面的灰尘包围了我，好暗好暗 铁盒的钥匙我找不到，放在糖果旁的是我很想回忆的甜，然而过滤了你和我沦落而成美，沉在盒子里的是你给我的快乐，我很想记得可是我记不得，为什么这样子，你拉着我说你有些犹豫，怎么这样子，雨还没停你就撑伞要走，已经习惯不去阻止你，过好一阵子 你就会回来，印象中的爱情好像，顶不住那时间，为什么这样子，你看着我说你已经决定，我拉不住你，他的手应该比我更暖，铁盒的序 变成了日记，变成了空气 演化成回忆，印象中的爱情好像顶不住那时间，所以你弃权.', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (23, '23', '03', '暗号', '周杰伦', '许世昌', '林迈可', 'R&B/流行 (R&B/Pop)', '典型的抒情R&B，旋律流畅，情感内敛，以钢琴和弦乐衬托', '三', '2002-07-19', '八度空间', '我想要的 想做的 你比谁都了，你想说的 想给的 我全都知道，未接来电 没留言，一定是你孤单想念，任何人都猜不到，这是我们的暗号，他们猜 随便猜 不重要，连上彼此的讯号，才有个依靠，有太多人 太多事，夹在我们之间咆哮，杂讯太多讯号，就连风吹都要干扰，可是你不想 一直走在黑暗地下道，想吹风 想自由 想要一起手牵手，去看海 绕世界流浪，我害怕你心碎没人帮你擦眼泪，别管那是非 只要我们感觉对，我害怕你心碎没人帮你擦眼泪，别离开身边 拥有你我的世界才能完美，你说你想逃开松手，爱太累爱得不自由，因为我给不起最简单的承诺，你停止收讯号 我开始搜寻不到，到底有谁知道 是几点钟方向，你才会收到暗号', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (24, '24', '04', '龙拳', '周杰伦', '方文山', '洪敬尧', '中国风/摇滚 (Chinese Style/Rock)', '将中国五声音阶与摇滚强力节奏结合，歌词充满民族自豪感，气势磅礴', '三', '2002-07-19', '八度空间', '以敦煌为圆心的东北东，这民族的海岸线像一支弓，那长城像五千年来待射的梦，我用手臂拉开这整个土地的重，蒙古高原南下的风写些什么内容，汉字到底懂不懂一样肤色和脸孔，跨越黄河东 登上泰山顶峰，我向西 引北风 晒成一身古铜，渴望着血脉相通 无限个千万弟兄，我把天地拆封 将长江水掏空，人在古老河床蜕变中，我右拳打开了天化身为龙，把山河重新移动填平裂缝，将东方的日出调整了时空，回到洪荒 去支配 去操纵，我右拳打开了天化身为龙，那大地心脏汹涌不安跳动，全世界的表情只剩下一种，等待英雄 我就是那条龙', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (25, '25', '05', '火车叨位去', '周杰伦', '方文山', '洪敬尧', '台语流行/民谣 (Taiwanese Pop/Folk)', '用闽南语演唱，旋律忧伤，带有台湾本土的民谣气息，讲述离乡背井的思念', '三', '2002-07-19', '八度空间', '让我讲庄脚ㄟ路边蝉躲在树枝，七月天闹热ㄟ唱戏ㄒーㄌㄚㄙㄡㄈㄚㄇー，听我讲风景这呢水火车叨位去，拿纸笔写歌思念你ㄒーㄌㄚㄙㄡㄈㄚㄇー，车过山洞变成暗瞑，但是连咪都ㄟ，过去按怎你走那个当时，没留半张批纸，加字过去像溪边ㄟ田蝇，龙是逗阵飞ㄟ日子，这时我想离水ㄟ鱼，放抹记剩最后一口气，过去你迷人ㄟ气质，放抹记，龙是笑容酸甘呀甜，返去故事到这为止，你那ㄟ全然龙没讯息，我亲像一只蜂找没蜜，将过去一张一张ㄟ撕，这日历马撕到何时才有你ㄟ字，你那全然龙没讯息，像往南方燕子断翅，不曾搁返来巢看历边，为啥咪铁支路直直火车叨位去', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (26, '26', '06', '分裂（大陆版：离开）', '周杰伦', '周杰伦', '钟兴民', '离开）', '结构复杂，情绪递进强烈，从压抑的独白到爆发的嘶吼，极具艺术性和实验性', '三', '2002-07-19', '八度空间', '坐着我的摩托车 载你缓缓的离开，考不上的好学校 可以不微笑就走，把手慢慢交给我 放下心中的困惑，雨点从两旁划过 割开两种精神的我，经过老伯的家 篮框变得好高，爬过的那棵树 又何时变得渺小，这样也好 开始没人注意到（你）我，等雨变强之前 我们将会分化软弱，趁时间没发觉让我载着你离开，没有了证明 没有了空虚，基于两种立场我会罩着你，趁时间没发觉让我载着你离开，这不是顽固这不是逃避，没人抱着你走 才快乐', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (27, '27', '07', '爷爷泡的茶', '周杰伦', '方文山', '林迈可', '中国风/轻摇滚 (Chinese Style/Light Rock)', '以茶文化为主题，节奏轻快，融合中国乐器与现代编曲，充满生活气息', '三', '2002-07-19', '八度空间', '爷爷泡的茶 有一种味道叫做家，陆羽泡的茶 像幅泼墨的山水画，山泉在地表蜿蜒，从很久很久以前我有一张稚气的脸，泉水渗透进矿层岩 爷爷栽种的樟木树苗上面，犹记得那年在一个雨天，那七岁的我躲在屋檐 却一直想去荡秋千，爷爷抽着烟 说唐朝陆羽写茶经三卷流传了，千年 那天 我翻阅字典 查什么字眼 形容一件事很遥远，天边是否在海角对面，知道九岁才知道浪费时间，这茶桌樟木的横切面 年轮有二十三圈，镜头的另一边跳接我成熟的脸，经过这些年 爷爷的手茧 泡在水里会有茶色蔓延，啦啦~ 啦啦~ 啦啦啦啦啦~，啦啦~ 啦啦~ 啦啦啦啦啦~，啦啦~ 啦啦~啦啦啦啦啦~，爷爷泡的茶 有一种味道叫做家，（没法挑剔它 口感味觉还不差），陆羽泡的茶 听说名和利都不拿，（他牵着一匹瘦马就走遍天涯），爷爷泡的茶 有一种味道叫做家，（他满头白发 喝茶时不准说话），陆羽泡的茶 像幅泼墨的山水画，（唐朝千年的风沙 现在还在刮），爷爷泡的茶 有一种味道叫做家，陆羽泡的茶 听说名和利都不拿，爷爷泡的茶 有一种味道叫做家，陆羽泡的茶 像幅泼墨的山水画', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (28, '28', '08', '回到过去', '周杰伦', '刘畊宏', '林迈可', '流行/节奏蓝调 (Pop/R&B)', '轻快的R&B曲风，探讨文化差异下的爱情，带有幽默感', '三', '2002-07-19', '八度空间', '一盏黄黄旧旧的灯，时间在旁闷不吭声，寂寞下手毫无分寸，不懂得轻重之分，沉默支撑跃过陌生，静静看着凌晨黄昏，你的身影，失去平衡，慢慢下沉，黑暗已在空中盘旋，该往哪我看不见，也许爱在梦的另一端，无法存活在真实的空间，想回到过去，试着抱你在怀里，羞怯的脸带有一点稚气，想看你看的世界，想在你梦的画面，只要靠在一起，就能感觉甜蜜，想回到过去，试着让故事继续，至少不再让你离我而去，分散时间的注意，这次会抱得更紧，这样挽留不知，还来不来得及，想回到过去，思绪不断，阻挡着回忆播放，盲目的追寻，仍然空空荡荡，灰蒙蒙的夜晚，睡意又不知躲到哪去，一转身孤单，已躺在身旁，想回到过去，试着抱你在怀里，羞怯的脸带有一点稚气，想看你看的世界，想在你梦的画面，只要靠在一起，就能感觉甜蜜，想回到过去，试着让故事继续，至少不再让你离我而去，分散时间的注意，这次会抱得更紧，这样挽留不知，还来不来得及，想回到过去，沉默支撑跃过陌生，静静看着凌晨黄昏，失去平衡，慢慢下沉，你的身影，想回到过去', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (29, '29', '09', '米兰的小铁匠', '周杰伦', '方文山', '洪敬尧', '世界音乐/民谣 (World Music/Folk)', '灵感来自意大利民谣，使用手风琴等乐器，营造出欧洲小镇的浪漫风情', '三', '2002-07-19', '八度空间', '跑遍了牧场又绕过了村庄，他就站在街角的旧报摊，眼睛盯着隔壁里的橱窗，一把吉他 远远欣赏，木炭 一箩筐，木炭 一直放，木炭 剩一半，火炉烫小铁匠 存钱买期望 在流汗，巴洛克建筑的街道旁，一家烟雾缭绕的酒馆，波兰的吟唱诗人在弹唱，小铁匠在门外，进不去在苦恼，他的铜板还太少，他真的真的想知道，(那首来自东欧的民谣和弦到底什么调)，米兰的天空刚破晓(那马蹄铁还要敲多少吉他才能买得到)，他真的真的想知道(他不知道怎么办才好睡不着)，他将那扑满打破了(小小愿望就快实现了他在笑)，（咩~）', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (30, '30', '10', '最后的战役', '周杰伦', '方文山', '钟兴民', '史诗摇滚/说唱 (Epic Rock/Rap)', '以战争为背景，编曲宏大，说唱与副歌的悲壮旋律结合，充满戏剧张力', '三', '2002-07-19', '八度空间', '机枪扫射声中我们寻找遮蔽的战壕，儿时沙雕的城堡毁坏了重新盖就好，可是你那件染血布满弹孔的军外套，却就连祷告手都举不好，在硝烟中想起冰棒汽水的味道，和那些无所事事一整个夏天的年少，我放下枪回忆去年一起毕业的学校，而眼泪一直都忘记要掉，嘲笑的声音在风中不断被练习，这树林间充满了敌意，部队弃守阵地你坚持要我也离去，我怎么能放弃，我留着陪你 强忍着泪滴，有些事真的来不及回不去，你脸在抽搐 就快没力气，家乡事 不准我再提，我留着陪你 最后的距离，是你的侧脸倒在我的怀里，你慢慢睡去 我摇不醒你，泪水在战壕里 决了堤，在硝烟中想起冰棒汽水的味道，和那些无所事事一整个夏天的年少，我放下枪回忆去年一起毕业的学校，而眼泪一直都忘记要掉，嘲笑的声音在风中不断被练习，这树林间充满了敌意，部队弃守阵地你坚持要我也离去，我怎么能放弃，我留着陪你 强忍着泪滴，有些事真的来不及回不去，你脸在抽搐 就快没力气，家乡事不准我再提，我留着陪你 最后的距离，是你的侧脸 倒在我的怀里，你慢慢睡去我摇不醒你，泪水在战壕里 决了堤', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (31, '31', '01', '以父之名', '周杰伦', '黄俊郎', '洪敬尧', '古典说唱/歌剧摇滚 (Orchestral Rap/Opera Rock)', '融合意大利歌剧采样、古典弦乐与说唱，叙事宏大，被誉为华语说唱的巅峰之作', '四', '2003-07-31', '叶惠美', '微凉的晨露 沾湿黑礼服 石板路有雾 父在低诉，无奈的觉悟 只能更残酷 一切都为了 通往圣堂的路，吹不散的雾 隐没了意图 谁轻柔踱步 停驻，还来不及哭 穿过的子弹就带走温度，我们每个人都有罪 犯着不同的罪 我能决定谁对 谁又该要沉睡，争论不能解决 在永无止境的夜 关掉你的嘴 唯一的恩惠，挡在前面的人都有罪 后悔也无路可退 以父之名判决 那感觉没有适合词汇，就像边笑边掉泪 凝视着完全的黑 阻挡悲剧蔓延的悲剧会让我沉醉，低头亲吻我的左手 换取被宽恕的承诺 老旧管风琴在角落 一直一直一直伴奏，黑色帘幕被风吹动 阳光无言的穿透 洒向那群被我驯服后的兽，沉默的喊叫沉默的喊叫 孤单开始发酵 不停对着我嘲笑，回忆逐渐延烧 曾经纯真的画面 残忍的温柔出现 脆弱时间到 我们一起来祷告，仁慈的父我已坠入看不见罪的国度 请原谅我的自负，没人能说没人可说好难承受 荣耀的背后刻着一道孤独，闭上双眼我又看见当年那梦的画面 天空是蒙蒙的雾，父亲牵着我的双手轻轻走过 清晨那安安静静的石板路，(仁慈的父我已坠入看不见罪的国度请原谅我我的自负刻着一道孤独)，那斑驳的家徽我擦拭了一夜孤独的光辉我才懂的感觉，烛光不不停的摇晃猫头鹰在窗棂上对着远方眺望，通向大厅的长廊一样说不出的沧桑，没有喧嚣只有宁静围绕我慢慢睡着天刚刚破晓', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (32, '32', '02', '懦夫', '周杰伦', '周杰伦', '周杰伦', '抒情摇滚/另类摇滚 (Ballad Rock/Alternative Rock)', '情绪压抑、爆发力强，是周杰伦少有的以纯粹摇滚方式表达内心挣扎的作品', '四', '2003-07-31', '叶惠美', '周围的人群堵住了我的出口 想爬起来我只能说真的好难，防火巷传来的枪声把我从天堂叫醒 一名白种人褐色头发在我面前倒下，从他的手里那半包看到不少我荒唐的影子，从他的眼球看到发抖的我 是那么的丑陋于是，检起地上他那第二个纽扣 提醒自己该开始懂事不被软性药物控制，在我的眼里懂得拒绝才能存活下来，活着 不是用来演一出糜烂的黑色喜剧，说不 我很后悔当初没有这样的肯定 说不 不代表懦夫，真不该睁不开别让我的地球变暗 互相残杀的动物真美，被期待被覆盖蜕变的公式我学不来 我闻不到腐烂的香味，说不 我很后悔当时没有这样的肯定，说不 不代表懦夫 你应该很骄傲，我看不起人们无知的好奇作祟心态 去亲近死神你 了吗很了吗，肮脏的香味我吸了太多太多 腐败的视野我看了太多太多，瞳孔放大不代表就能看得更多 难怪大人们说我们永远长不大，那一块我梦里的干净的天空 那一块我梦里的干净的天空，是否玩大风吹也许就能看到 是否玩大风吹也许就能看到，真不该睁不开别让我的地球变暗(街角的消防栓上的红色油漆反射出儿时天真的嬉戏模样)，被期待被覆盖蜕变的公式我学不来(难道这不是我要的天堂景象 沉沦假象 你只会感到更加沮丧)', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (33, '33', '03', '晴天', '周杰伦', '周杰伦', '周杰伦', '流行摇滚/校园民谣 (Pop Rock/School Folk)', '旋律极其抓耳，是校园爱情的经典代表，以吉他为主，清新中带着感伤', '四', '2003-07-31', '叶惠美', '故事的小黄花，从出生那年就飘着，童年的荡秋千，随记忆一直晃到现在，ㄖㄙㄙㄒㄉㄒㄌㄙㄌㄒㄒㄒㄒㄌㄒㄌㄙ，ㄨㄡㄡーㄡーㄚㄡㄚーーーーㄚーㄚㄡ，ㄟ，吹着前奏望着天空，我想起花瓣试着掉落，为你翘课的那一天，花落的那一天，教室的那一间，我怎么看不见，消失的下雨天，我好想再淋一遍，没想到失去的勇气我还留着，好想再问一遍，你会等待还是离开，刮风这天我试过握着你手，但偏偏雨渐渐大到我看你不见，还要多久我才能在你身边，等到放晴的那天也许我会比较好一点，从前从前有个人爱你很久，但偏偏风渐渐把距离吹得好远，好不容易又能再多爱一天，但故事的最后你好像还是说了拜拜，为你翘课的那一天，花落的那一天，教室的那一间，我怎么看不见，消失的下雨天，我好想再淋一遍，没想到失去的勇气我还留着，好想再问一遍，你会等待还是离开，刮风这天我试过握着你手，但偏偏雨渐渐大到我看你不见，还要多久我才能在你身边，等到放晴的那天也许我会比较好一点，从前从前有个人爱你很久，偏偏风渐渐把距离吹得好远，好不容易又能再多爱一天，但故事的最后你好像还是说了拜拜，刮风这天我试过握着你手，但偏偏雨渐渐大到我看你不见，还要多久我才能够在你身边，等到放晴那天也许我会比较好一点，从前从前有个人爱你很久，但偏偏雨渐渐把距离吹得好远，好不容易又能再多爱一天，但故事的最后你好像还是说了拜', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (34, '34', '04', '三年二班', '周杰伦', '方文山', '洪敬尧', '爵士/嘻哈 (Jazz/Hip-Hop)', '以乒乓球为题材，节奏轻快，加入爵士鼓点和即兴说唱，趣味十足', '四', '2003-07-31', '叶惠美', '（训导处报道训导处报道 三年二班 周杰伦 马上到训导处来），眼睛你要擦亮 记住我的模样 表情不用太紧张，我是 三年二班 我专心打球的侧脸还满好看，黑板是吸收知识的地方 只是教室的阴光，那颜色我不太喜欢 没有操场的自然，为何比较漂 亮的都是在隔壁班 还有考卷的答案，我刚好都不会算 没关系 再继续努力 没关系，为什么上课时举手很难 为什么拿线上宝物简单，为什么女生不喜欢太胖 为什么别人手机在响，正手发长球的打法只是初级乒乓 反手短打再狠狠杀球是高级乒乓，回转技巧乒乓 前场速攻乒乓 对墙壁 在练习 乒乓 乒乓，这第一名到底要多强(不用问 一定有人向你挑战)，到底还要过多少关(不用怕 告诉他们谁是男子汉)，可不可以不要这个奖(不想问 我只想要留一点汗)，我当我自己的裁判(不想说 选择对手跟要打的仗)，（全体师生注意，今天要表扬一位同学，他为校争光，我们要向他看齐！），我不想 就这样一直走 每天都遇上 充满敌意那种眼光，等机会 就是要打倒对方 这种结果我不要 这虚荣的骄傲，这目的很好笑 我其实都知道 你只是想炫耀，我永远做不到 你永远赢不了 我永远做不到 你永远赢不了 永远都赢不了，走乡下 寻找哪有花香(为什么这么简单你做不到)，坐车厢 朝着南下方向(为什么 这种速度你追不到)，鸟飞翔 穿过了这条小巷(为什么 这么简单你做不到)，仔细想 这种生活安详(为什么 这种速度你追不到) 不好笑 不好笑 不好笑，我不想 就这样一直走 每天都遇上 充满敌意那种眼光，等机会 就是要打倒对方 这种结果我不要 虚荣的骄傲', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (35, '35', '05', '东风破', '周杰伦', '方文山', '林迈可', '中国风 (Chinese Style)', '公认的“三古三新”中国风典范（古辞赋、古旋律、古乐器；新唱法、新编曲、新概念），奠定了周氏中国风的成熟模板', '四', '2003-07-31', '叶惠美', '一盏离愁孤单伫立在窗口，我在门后假装你人还没走，旧地如重游月圆更寂寞，夜半清醒的烛火，不忍苛责我，一壶漂泊浪迹天涯难入喉，你走之后酒暖回忆思念瘦，水向东流 时间怎么偷，花开就一次成熟 我却错过，谁在用琵琶弹奏一曲东风破，岁月在墙上剥落看见小时候，犹记得那年我们都还很年幼，而如今琴声幽幽我的等候你没听过，谁再用琵琶弹奏一曲东风破，枫叶将故事染色结局我看透，篱笆外的古道我牵着你走过，荒烟漫草的年头 就连分手都很沉默', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (36, '36', '06', '你听得到', '周杰伦', '曾郁婷', '林迈可', '流行/抒情 (Pop/Ballad)', '温暖的抒情流行曲，旋律柔和，表达暗恋的细腻情感', '四', '2003-07-31', '叶惠美', '有谁能比我知道 你的温柔像羽毛，秘密躺在我怀抱 只有你能听得到，还有没有人知道 你的微笑像拥抱，多想藏着你的好 只有我看得到，站在屋顶只对风说 不想被左右，本来讨厌下雨的天空 直到听见有人说爱我，坐在电影院的二楼 看人群走过，怎么那一天的我们 都默默的微笑很久，我想我是太过依赖 在挂电话的刚才，坚持学单纯的小孩 静静看守这份爱，知道不能太依赖 怕你会把我宠坏，你的香味一直徘徊 我舍不得离开', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (37, '37', '07', '同一种调调', '周杰伦', '方文山', '钟兴民', '放克/迪斯科 (Funk/Disco)', '节奏感极强，复古舞曲风格，充满律动和玩乐气息', '四', '2003-07-31', '叶惠美', '全身纯白色的那雕像石膏 颜色干净没有压力的很讨好，我坐在客厅模仿雕像思考 却彷佛听到同样想法的困扰，针叶林树梢 穿过绿色隧道 一股神秘在敲，我们都拥有着相同的 大脑 一样的嗜好，门上流苏线条在摇晃炫耀 但是如果没有风它也办不到，我知道共同的默契很重要 那骄傲才不会寂寞的很无聊，书框的城堡 很欧洲情调，对着这张海报 我们在远距离欣赏与微笑，默契无法伪造 我们同一种调调，不关心天气预报 因为那无关紧要，想打球下大雨照跳 只收看音乐频道，渴望在天空一角 做记号 那里蓝色最好，我很了 默契无法伪造 我们同一种调调，凡事都自己主导 决定穿什么外套，有专属的铃声讯号 从不跟别人比较，只喝过冰过的饮料 很少笑 吃全麦的面包，rap:快疯掉 情绪偏离轨道 快疯掉 我睡不着快 疯掉 表情开我玩笑，快疯掉 我受不了这样也好 如果身份对调 我的烦恼 你也会感同身受 的知道，闷闷的很干燥 快疯掉 快疯掉', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (38, '38', '08', '她的睫毛', '周杰伦', '方文山', '周杰伦', 'R&B/流行 (R&B/Pop)', '轻快甜美的R&B小品，旋律俏皮，描绘恋爱中的心动瞬间', '四', '2003-07-31', '叶惠美', '亲爱的有些事总没办法教 表错情的感觉有一点糟 赖着不走 会让人 很感冒，以上这道理我全都了 我将不该犯的错都默背好 仔细观察她的喜好，而我紧绷的外表 像上紧后的发条 等她的答案揭晓，她的睫毛弯的嘴角无预警的对我笑 没有预兆出乎预料竟然先对我示好，她的睫毛弯的嘴角用眼神对我拍照 我戒不掉她的微笑洋溢幸福的味道，有些事没办法教 表错情的感觉有一点糟 赖着不走 会让人 很感冒，以上这道理我全都了 恋爱的方式无法拿笔来抄 也没有规则可以取巧，被动的缘分很不可靠 喜欢的对象要自己挑，她粉嫩清秀的外表 像是多汁的水蜜桃谁都想咬，她嘴上亮丽的唇膏 有一股自信的骄傲我看得到，rap:她的睫毛 弯的嘴角 无预警的对我笑 没有预兆 出乎预料 竟然先对我示好，她的睫毛 弯的嘴角 用眼神对我拍照 我戒不掉 她的微笑 洋溢幸福的味道', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (39, '39', '09', '爱情悬崖', '周杰伦', '徐若瑄', '钟兴民', '流行摇滚 (Pop Rock)', '情感浓烈，副歌爆发力强，是典型的抒情摇滚情歌', '四', '2003-07-31', '叶惠美', '你说我像一个小孩 总爱让你猜 我说你才像个小孩，总要我说才明白 有些事太快 失去了等待 障碍 没了期待，我们的爱 怎么才自然 每次沟通不来 就要离开就说不要爱，我掉进爱情悬崖 跌太深爬不出来 下降的速度太快 来不及踏上未来，你的爱反复徘徊 打乱我的呼吸节拍 该怎么逃开 我控制不来，我掉进爱情悬崖 回想起你的可爱 傻傻的还在等待 以为你还会回来，你的脸慢慢离开 时间快将我掩埋 消失的太快 我负荷不来', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (40, '40', '10', '梯田', '周杰伦', '周杰伦', '周杰伦', '嘻哈/社会批判说唱 (Hip-Hop/Social Commentary Rap)', '以环保为主题，说唱犀利，批判过度开发，节奏感强', '四', '2003-07-31', '叶惠美', '文山啊 等你写完词 我都出下一张专辑罗 没关系 慢慢来 这首歌我自己来，说到中学时期 家乡的一片片梯田 是我看过最美的绿 地于是也因此让我得了最佳摄影，莫名其妙在画面中的我 不会写词都像个诗人 坐着公车上学的我，看着窗外的牛啃草 是一种说不出的自由自在，hoi ya e ya 那鲁湾 na e na ya hei 哦～我亲爱的牛儿啊，hoi ya e ya 那鲁湾 na e na ya hei 哦～跑到哪儿去啦，面店旁的小水沟 留着我们长大的梦 绕过天真 跳至收割期，人们的汗水夹杂着满足与欢喜 是我现在最舍不得的画面 面，也是我另一项参展作品 靠着回忆 画成油画 拿到奖状 有个啥用，鼓励你多去回忆是吧 哼 我真想撕掉换回自然，怎么梯田不见 多了几家饭店 住在里面看西洋片，几只水牛 却变成画 挂在墙壁上 象征人们蒸蒸日上，一堆游客 偶尔想看看窗外的观光景点 但只看到 比你住的再高一层的饭店，hoi ya e ya 娜鲁湾 na e na ya hei 哦～我亲爱的牛儿啊，hoi ya e ya 娜鲁湾 na e na ya hei 哦～跑到哪儿去啦，因地制宜 综合利用 利用对还是不对 自私的人类 狼不狼狈，破坏自然的生态会不会很累 你说为了艺术要砍下一棵树，酱 对还是不对 你说为了装饰 请问干我啥事，是不是只能用相机纪录自然 拿相片给下一代 下一代回味，可怜可悲森林绿地都已成纪录片 闻不到绿意盎然 只享受到乌烟瘴气，我不能教育你们 我不是你们老师 我不是校长，也不能给你们一巴掌...掌...长...长...长篇大论，你们并不想听 我知道 但我没办法 我就是要写，你们可能永远不能体会 显微镜底下的我们 会更现实更自私 这种艺术真的很难领悟', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (41, '41', '11', '双刀', '周杰伦', '方文山', '钟兴民', '中国风/电子摇滚 (Chinese Style/Electro Rock)', '运用二胡采样和电子音效，营造武侠氛围，节奏强劲', '四', '2003-07-31', '叶惠美', '透过镜头重新剪接历史给人的想象 八厘米纪录片的桥段隔着距离欣赏，正邪对立的两方我握紧拳头开始习惯 以牙还牙的手段，风 盘旋烟雾弥漫 我虔诚点的香 在祈祷着平安，从天台向下俯瞰暴力在原地打转 上一代解决的答案是微笑不抵抗，被雨淋湿的的唐装那股叹息很东方 我看不惯尊严受伤家族如此不堪，风 缓缓绕过武馆 正上方的月亮 那颜色中国黄，透过透过镜头重新剪接历史给人想象 八厘米纪录片 的桥段 在播放，隔着距离欣赏正邪对立的两方 我握紧拳头开始习惯 那以牙还牙以牙还牙手段，恐惧来自退让，rap:双刀的正前方我杀气不转弯 背对我的力量 它自己却受伤，双刀的右下方我挥刀去了断 将恩怨全看穿 丹凤眼的目光', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (42, '42', '01', '我的地盘', '周杰伦', '方文山', '洪敬尧', '广告曲/流行说唱 (Commercial/Pop Rap)', '为移动通信广告创作，节奏轻快，口号性强，融合说唱与流行', '五', '2004-08-03', '七里香', '在我地盘这你就得听我的，把音乐收割用听觉找快乐，开始在雕刻我个人的特色，未来难预测坚持当下的选择，在我地盘这你就得听我的，节奏在招惹我跟街舞亲热，我灌溉原则培养一种独特，观念不及格其他全部是垃圾，用态度扩张地盘到底什么意思怎么一回事，广场的鸽子占领头版的报纸，一种全新的解释标题关于这座城市，关于一种学习考试和年轻就该有的本事，动感地带的交通标志到底离我有几公尺，我说老师我是不是真的不懂事，听我念饶舌歌词 欣赏我打拳的样子，我站在教室 练拳方式 你的样子 线条一致，隔壁的小姑娘 公开表演需要勇气，别人玩线上游戏 我偏耍猴戏，我用形意 猴拳在练习，引你注意 如果觉得有趣，不要吝啬示个好意，青春是干净的纯白，像一遍绿地的窗外，我将记忆的门打开，把所有发生的事记下来，那弹钢琴的孩子 正用他们的手指，弹奏未来的历史 我用手机传中文字，那传输的速度绝对会让你们竖起大拇指，生活不该有公式 我可以随性跳芭蕾舞，照节拍 手放开 静下来，像一只天鹅把脚尖掂起来，讲究快餐的这年代也可以很天真的说爱', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (43, '43', '02', '七里香', '周杰伦', '方文山', '钟兴民', '流行/抒情摇滚 (Pop/Ballad Rock)', '旋律优美如诗，以吉他和弦乐为主，是周杰伦最经典的浪漫情歌之一', '五', '2004-08-03', '七里香', '窗外的麻雀，在电线杆上多嘴，你说这一句，很有夏天的感觉，手中的铅笔，在纸上来来回回，我用几行字形容你是我的谁，秋刀鱼的滋味，猫跟你都想了解，初恋的香味就这样被我们寻回，那温暖的阳光，像刚摘的鲜艳草莓，你说你舍不得吃掉这一种感觉，雨下整夜，我的爱溢出就像雨水，院子落叶，跟我的思念厚厚一叠，几句是非，也无法将我的热情冷却，你出现在我诗的每一页，雨下整夜，我的爱溢出就像雨水，窗台蝴蝶，像诗里纷飞的美丽章节，我接着写，把永远爱你写进诗的结尾，你是我唯一想要的了解，雨下整夜，我的爱溢出就像雨水，院子落叶，跟我的思念厚厚一叠，几句是非，也无法将我的热情冷却，你出现在我诗的每一页，那饱满的稻穗，幸福了这个季节，而你的脸颊像田里熟透的蕃茄，你突然，对我说，七里香的名字很美，我此刻却只想亲吻你倔强的嘴，雨下整夜，我的爱溢出就像雨水，院子落叶，跟我的思念厚厚一叠，几句是非，也无法将我的热情冷却，你出现在我诗的每一页，整夜，我的爱溢出就像雨水，窗台蝴蝶，像诗里纷飞的美丽章节，我接着写，把永远爱你写进诗的结尾，你是我唯一想要的了解', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (44, '44', '03', '借口', '周杰伦', '周杰伦', '钟兴民', 'R&B/抒情 (R&B/Ballad)', '情感真挚的R&B情歌，探讨爱情中的矛盾与无奈', '五', '2004-08-03', '七里香', '翻着我们的照片，想念若隐若现，去年的冬天，我们笑得很甜，看着你哭泣的脸，对着我说再见，来不及听见，你已走得很远，也许你已经放弃我，也许已经很难回头，我知道是自己错过，请再给我一个理由，说你不爱我，就算是我不懂，能不能原谅我，请不要把分手当作你的请求，我知道坚持要走是你受伤的借口，请你回头，我会陪你一直走到最后，就算没有结果，我也能够承受，我知道你的痛，是我给的承诺，你说给过我纵容，沉默是因为包容，如果要走请你记得我，翻着我们的照片，想念若隐若现，去年的冬天，我们笑得很甜，看着你哭泣的脸，对着我说再见，来不及听见，你已走得很远，也许你已经放弃我，也许已经很难回头，我知道是自己错过，请再给我一个理由，说你不爱我，就算是我不懂，能不能原谅我，请不要把分手当作你的请求，我知道坚持要走是你受伤的借口，请你回头，我会陪你一直走到最后，就算没有结果，我也能够承受，我知道你的痛，是我给的承诺，你说给过我纵容，沉默是因为包容，如果要走请你记得我，如果要走，请你记得我，如果难过，请你忘了我', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (45, '45', '04', '外婆', '周杰伦', '周杰伦', '钟兴民', '嘻哈/叙事说唱 (Hip-Hop/Narrative Rap)', '为表达对家人的爱而作，说唱真挚，节奏舒缓，充满人情味', '五', '2004-08-03', '七里香', '今天是外婆生日，我换上复古西装，载着外婆开着拉风的古董车兜兜兜风，车里放着她的最爱，找回属于是她的时代，往大稻埕码头开去，把所有和外公的往事静静回忆，外婆她脸上的涟漪，美丽但藏不住压抑，失去了爱情只盼望亲情，弥补回应，大人们以为出门之前，桌上放六百就算是孝敬，一天到晚拼了命，赚钱少了关怀有什么意义，外婆她的期待，慢慢变成无奈，大人们始终不明白，她要的是陪伴，而不是六百块，比你给的还简单，外婆她的无奈，无法变成期待，只有爱才能够明白，走在淡水河畔，听着她的最爱，把温暖放回口袋，记得去年外婆的生日，表哥带我和外婆参加，她最最重视的颁奖典礼，结果却拿不到半个奖，不知该笑不笑，我对着镜头傻笑，只觉得自己可笑，我难过，却不是因为没有得奖而难过，我失落，是因为看到外婆失落而失落，大人们根本不能体会，表哥他的用心，好像随他们高兴就可以彻底的否定，否定我的作品，决定在于心情，想坚持风格他们就觉得还欧颗，没惊喜没有改变，我已经听了三年，我告诉外婆我没输不需要改变，表哥说不要觉得可惜，这只是一场游戏，只要外婆觉得好听，那才是一种鼓励，外婆露出了笑容说她以我为荣，浅浅的笑容，就让我感到比得奖它还要光荣，外婆她的期待，慢慢变成无奈，大人们始终不明白，她要的是陪伴，而不是六百块，比你给的还简单，外婆她的无奈，无法期待，只有爱才能够明白，走在淡水河畔，听着她的最爱，把温暖放回口袋，外婆她的期待，慢慢变成无奈，大人们始终不明白，她要的是陪伴，而不是六百块，比你给的还简单，外婆她的无奈，无法变成期待，只有爱才能够明白，走在淡水河畔，听着她的最爱，把温暖放回口袋', '2025-10-29 20:21:10', '2025-10-30 20:54:46');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (46, '46', '05', '将军', '周杰伦', '黄俊郎', '洪敬尧', '中国风/电子 (Chinese Style/Electronic)', '与南拳妈妈合唱，融合戏曲元素与电子节拍，主题围绕网络游戏', '五', '2004-08-03', '七里香', '（你往下走好不好？错咧！错咧怎么咧？ 你走吧？没错了吗走！），时间的箭头，都指向你铩羽而归的地方，你会前进，但终究还是得要习惯投降，想当然而，第六步是你最大的致命伤，我按兵不动，出于习惯，凡事沉默的酝酿，当头炮纯粹出于我礼貌的开场，屏风马神华内敛，才能以柔克刚，第二十六着炮五进四，只是在试探性衡量，三十三招车二平七的出手，你恐怕就暗箭难防，这一场不流血的仗，只有自尊会受伤，成王败寇的规则，跟现实没啥两样，提着鸟笼的老头，站在一旁拍我肩膀，我猜他想的应该和我一样，看我我手指放松，我目光如龙当敌人失控，我战法无穷我攻势如风，用单车入宫，碾过你懊丧的脸孔，看我我手指放松，我目光如龙当敌人失控，我左右开弓我气势如虹，将炮马尽用，兵临城下想逃都没用，我对着潮汐推敲什么是以静制动，山林间迷雾，能不能当障眼法的内容，月转星移的轨迹跟临军布阵相同，风林火山是不是用兵之重，到最后必然是我运筹帷幄，你最后放弃抵抗，我仰望着夕阳，你低头黯然离场，听我说胜败是兵家之常，你不用放在心上，是因为我只适合无双，看我我手指放松，我目光如龙当敌人失控，我战法无穷我攻势如风，用单车入宫，碾过你懊丧的脸孔，看我我手指放松，我目光如龙当敌人失控，我左右开弓我气势如虹，将炮马尽用，兵临城下想逃都没用，看我我手指放松（阳光从树叶细缝），我目光如龙当敌人失控（露出了笑容），我战法无穷我攻势如风（温暖了），用单车入宫（我的美梦），碾过你懊丧的脸孔（只有笼里的画眉），看我我手指放松（仰望着天空），我目光如龙当敌人失控（却从来），我左右开弓我气势如虹（没有人懂），将炮马尽用，（哎哎 你往哪走 baby 将军~）', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (47, '47', '06', '搁浅', '周杰伦', '方文山', '钟兴民', '抒情摇滚 (Ballad Rock)', '情感层层递进，从压抑到爆发，是失恋后悔的经典抒情摇滚', '五', '2004-08-03', '七里香', '久未放晴的天空，依旧留着你的笑容，哭过却无法掩埋歉疚，风筝在阴天搁浅，想念还在等待救援，我拉着线复习你给的温柔，曝晒在一旁的寂寞，笑我给不起承诺，怎么会怎么会你竟原谅了我，我只能永远读着对白，读着我给你的伤害，我原谅不了我，就请你当作我已不在，我睁开双眼看着空白，忘记你对我的期待，读完了依赖，我很快就离开，久未放晴的天空，依旧留着你的笑容，哭过却无法掩埋歉疚，风筝在阴天搁浅，想念还在等待救援，我拉着线复习你给的温柔，暴晒在一旁的寂寞，笑我给不起承诺，怎么会怎么会你竟原谅了我，我只能永远读着对白，读到我给你的伤害，我原谅不了我，就请你当作我已不在，我睁开双眼看着空白，忘记你对我的期待，读完了依赖，我很快就...，我只能永远读着对白，读到我给你的伤害，我原谅不了我，就请你当作我已不在，我睁开双眼看着空白，忘记你对我的期待，读完了依赖，我很快就离开', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (48, '48', '07', '乱舞春秋', '周杰伦', '刘畊宏', '蔡科俊', '中国风/摇滚 (Chinese Style/Rock)', '以三国为背景，节奏狂野，说唱与摇滚结合，充满历史英雄气概', '五', '2004-08-03', '七里香', '那混乱的年代，朝廷太腐败，人祸惹天灾，东汉王朝在一夕之间崩坏兴衰，九州地图被人们切割成三块分开，读三国历史的兴衰，想去瞧个明白，看看看就马上回来，ㄎ一ㄥ　ㄎ一ㄥ　ㄎ一ㄤ　ㄎ一ㄤ，刀剑棍棒我随口讲，原来真有时光机这么夸张，穿梭时空过又嚣张，万一有去无回怎么办，老实说有点紧张啊啊，江山我站在云端，慢慢往中原方向，前方散落着村庄，长安在兵荒马乱，望着天眼看北斗七星坠入地平线，瞬间英雄豪杰犹如鬼魅般地出现，我呸谁也不服谁我是龟你是鳖，啦啦啦啦啦啦啦啦 Hey，妖兽扰乱人间秩序，血腥如浪潮般来袭，我小命差点没续集，还好有时光机我谢谢你，人魔开始重出地狱，叛军如野火般攻击，五官差点离开身体，还好有时光机我谢谢你，曹魏枭雄在 蜀汉多人才，东吴将士怪 七星连环摆，诸葛亮的天命不来，这些书都有记载，不是我在乱掰，等到东方鱼肚白，我再来跟你说嗨，嘴里有刀 说破歌谣，千年恩怨 一笔勾销，生命潦草 我在弯腰，历史轮回 转身忘掉，黄巾贼你不要吵我，咱姥姥和水擀面条，放下刀若想吃饱，去找皇帝老爷讨，黄巾贼你不要闹我，咱姥姥烧柴煮水饺，放下刀若想吃饱，去找皇帝老爷讨，妖兽扰乱人间秩序，血腥如浪潮般来袭，我小命差点没续集，还好有时光机我谢谢你，人魔开始重出地狱，叛军如野火般攻击，五官差点离开身体，还好有时光机我谢谢你，妖兽扰乱人间秩序，血腥如浪潮般来袭，我小命差点没续集，还好有时光机我谢谢你，人魔开始重出地狱，叛军如野火般攻击，五官差点离开身体，还好有时光机我谢谢你，妖兽扰乱人间秩序，血腥如浪潮般来袭，我小命差点没续集，还好有时光机我谢谢你，（喂！在配唱，鸡排饭，哎，加个蛋呐~），嘴里有刀说破歌谣，嘴里有刀说破歌谣，千年恩怨一笔勾销，千年恩怨一笔勾销，生命潦草我在弯腰，生命潦草我在弯腰，历史轮回转身忘掉，历史轮回转身忘掉', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (49, '49', '08', '困兽之斗', '周杰伦', '方文山', '洪敬尧', '嘻哈/硬核说唱 (Hip-Hop/Hardcore Rap)', '节奏强劲，说唱密集，表达在逆境中挣扎反抗的决心', '五', '2004-08-03', '七里香', '我在阴暗中降落，世界在雨中淹没，画面与现实交错，无法抽离卡在胸口，躯壳如行尸走肉，陷阱旋涡我已受够，挣脱逃离这个空洞，如果我冲出黑幕笼罩的天空，就别再捆绑我的自由，在狂风之中嘶吼，作困兽之斗，我奋力冲破，封闭的思绪震开裂缝，燃烧的花朵升空，消失在空中，记忆在剥落，残留的影响轮廓，溃散在薄雾中，我在阴暗中降落，世界在雨中淹没，画面与现实交错，无法抽离卡在胸口，躯壳如行尸走肉，陷阱旋涡我已受够，挣脱逃离这个空洞，如果我冲出黑幕笼罩的天空，就别想在捆绑我的自由，在狂风之中 嘶吼，作困兽之斗，我奋力冲破，封闭的思绪震开裂缝，燃烧的花朵 升空，消失在空中，记忆在剥落，残留的影响轮廓，溃散在薄雾中，啊~~之中嘶吼，作困兽之斗，我奋力冲破，封闭的思绪震开裂缝，燃烧的花朵升空，消失在空中，记忆在剥落，残留的影响轮廓，溃散在薄雾中', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (50, '50', '09', '园游会', '周杰伦', '方文山', '周杰伦', '流行/电子 (Pop/Electronic)', '旋律梦幻，加入电子音效，描绘初恋的甜蜜与幻想', '五', '2004-08-03', '七里香', '琥珀色黄昏像糖在很美的远方，你的脸没有化妆我却疯狂爱上，思念跟影子在傍晚一起被拉长，我手中那入场券陪我数羊，薄荷色草地芬芳像风没有形状，我却能够牢记你的气质跟脸庞，冷空气跟琉璃在清晨很有透明感，像我的喜欢被你看穿，摊位上一朵艳阳，我悄悄出现你身旁，你慌乱的模样 我微笑安静欣赏，我顶着大太阳，只想为你撑伞，你靠在我肩膀深呼吸怕遗忘，为捞鱼的蠢游戏我们开始交谈，多希望话题不断园游会永不打烊，气球在我手上，我牵着你瞎逛，有话想对你讲 你眼睛却装忙，鸡蛋糕跟你嘴角果酱我都想要尝，园游会影片在播放 这个世界约好一起逛，琥珀色黄昏像糖在很美的远方，你的脸没有化妆我却疯狂爱上，思念跟影子在傍晚一起被拉长，我手中那入场券陪我数羊，薄荷色草地芬芳像风没有形状，我却能够牢记你的气质跟脸庞，冷空气跟琉璃在清晨很有透明感，像我的喜欢被你看穿，摊位上一朵艳阳，我悄悄出现你身旁，你慌乱的模样我微笑安静欣赏，我顶着大太阳，只想为你撑伞，你靠在我肩膀深呼吸怕遗忘，因为捞鱼的蠢游戏我们开始交谈，多希望话题不断园游会永不打烊，气球在我手上，我牵着你瞎逛，有话想对你讲你眼睛却装忙，鸡蛋糕跟你嘴角果酱我都想要尝，园游会影片在播放这个世界约好一起逛', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (51, '51', '10', '止战之殇', '周杰伦', '方文山', '周杰伦', '史诗流行/反战歌曲 (Epic Pop/Anti-War Song)', '以战争中的孩童视角出发，旋律悲壮，编曲宏大，充满人文关怀', '五', '2004-08-03', '七里香', '光轻如纸张光散落地方，光在掌声渐息中它慌忙，她在传唱不堪的伤，脚本在台上演出最后一场，而全村的人们在座位上，静静的看时间是如何遗弃这剧场，战火弄脏她的泪光 谁在风中吵着吃糖，这故事一开始的镜头 灰尘就已经遮蔽了阳光，恐惧刻在孩子们脸上，麦田已倒向战车经过的方向，蒲公英的形状 在飘散 它绝望的飞翔，她只唱只想这首止战之殇，恶夜燃烛光 天破息战乱，殇歌传千里 家乡平饥荒，天真在这条路上跌跌撞撞，她被芒草割伤，孩子们眼中的希望是什么形状，是否醒来有面包当早餐再喝碗热汤，农夫被烧毁土地跟村庄终於拿起枪，她却慢慢习惯放弃了抵抗，woo~孩子们眼中的希望是什么形状，是否院子有秋千可以荡口袋里有糖，刺刀的光被仇恨所擦亮在远方野蛮，而她微微笑著不知道慌张，恐惧刻在孩子们脸上，麦田已倒向战车经过的方向，蒲公英的形状在飘散它绝望的飞翔，她只唱这首止战之殇，恶夜燃烛光天破息战乱，殇歌传千里家乡平饥荒，天真在这条路上跌跌撞撞，她被芒草割伤，孩子们眼中的希望是什么形状，是否醒来有面包当早餐再喝碗热汤，农夫被烧毁土地跟村庄终於拿起枪，她却慢慢习惯放弃了抵抗，woo~孩子们眼中的希望是什么形状，是否院子有秋千可以荡口袋里有糖，刺刀的光被仇恨所擦亮在远方野蛮，而她却微笑著不知道慌张，吧吧啦蹦蹦吧啦吧蹦蹦吧吧啦蹦蹦吧啦吧蹦蹦，天真在这条路上跌跌撞撞，她被芒草割伤，吧吧啦蹦蹦吧啦吧蹦蹦吧吧啦蹦蹦吧啦吧蹦蹦，天真在这条路上跌跌撞撞，她被芒草割伤', '2025-10-29 20:21:10', '2025-10-30 23:03:33');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (52, '52', '1', '夜曲', '周杰伦', '方文山', '林迈可', '古典说唱/哥特摇滚 (Orchestral Rap/Gothic Rock)', '以古典钢琴为主导，融合忧郁的弦乐和说唱，营造出“夜”的寂寥与诗意，是“夜曲三部曲”的代表作', '六', '2005-11-01', '十一月的肖邦', '一群嗜血的蚂蚁 被腐肉所吸引\n我面无表情 看孤独的风景\n失去你 爱恨开始分明\n失去你 还有什么事好关心\n当鸽子不再象征和平\n我终于被提醒\n广场上喂食的是秃鹰\n我用漂亮的押韵\n形容被掠夺一空的爱情\n啊 乌云开始遮蔽 夜色不干净\n公园里 葬礼的回音 在漫天飞行\n送你的白色玫瑰\n在纯黑的环境凋零\n乌鸦在树枝上诡异的很安静\n静静听 我黑色的大衣\n想温暖你日渐冰冷的回忆\n走过的走过的生命\n啊 四周弥漫雾气\n啊 我在空旷的墓地\n老去后还爱你\n为你弹奏肖邦的夜曲\n纪念我死去的爱情\n跟夜风一样的声音\n心碎的很好听\n手在键盘敲很轻\n我给的思念很小心\n你埋葬的地方叫幽冥\n为你弹奏肖邦的夜曲\n纪念我死去的爱情\n而我为你隐姓埋名\n在月光下弹琴\n对你心跳的感应\n还是如此温热亲近\n怀念你那鲜红的唇印\n那些断翅的蜻蜓 散落在这森林\n而我的眼睛 没有丝毫同情\n失去你 泪水混浊不清\n失去你 我连笑容都有阴影\n风在长满青苔的屋顶\n嘲笑我的伤心\n像一口没有水的枯井\n我用凄美的字型\n描绘后悔莫及的那爱情\n为你弹奏肖邦的夜曲\n纪念我死去的爱情\n跟夜风一样的声音\n心碎的很好听\n手在键盘敲很轻\n我给的思念很小心\n你埋葬的地方叫幽冥\n为你弹奏肖邦的夜曲\n纪念我死去的爱情\n而我为你隐姓埋名\n在月光下弹琴\n对你心跳的感应\n还是如此温热亲近\n怀念你那鲜红的唇印\n一群嗜血的蚂蚁 被腐肉所吸引\n我面无表情 看孤独的风景\n失去你 爱恨开始分明\n失去你 还有什么事好关心\n当鸽子不再象征和平\n我终于被提醒\n广场上喂食的是秃鹰\n我用漂亮的押韵\n形容被掠夺一空的爱情', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (53, '53', '2', '蓝色风暴', '周杰伦', '方文山', '洪敬尧', '电子摇滚/舞曲 (Electro Rock/Dance)', '节奏强劲，电子音效密集，为游戏主题曲，充满未来感和破坏力', '六', '2005-11-01', '十一月的肖邦', '亘古长夜 善恶交接\n我终于懂得流眼泪\n洪荒世界\n百分之七十都是水\n湛蓝的 旷野\n在海平面渴望满月\n于是我终于学会告解\n弥赛亚被世人误解\n被分类 爱恨 从此敌对\n远离风暴浩劫\n在第三章第四节\n我正在改写这世界\n用观念进行侵略\n我们占领整条街\n粉刷海洋蓝的季节\n一列 超高速的地铁\n一路 训练我的听觉\n消灭 那些\n太琐碎 太异类\n让问题尖锐 Oh~\n一双 狂奔中的球鞋\n一路 强壮着我的肺\n面对 这些\n太威胁 太强烈\n从来不喊累\n九星联结 排成一列\n在感动中我们忏悔\n生命珍贵\n我用那十四行诗赞美\n年轻的 一切\n我们在地平线感谢\n爱停止向另一边倾斜\n这首部曲的管弦乐\n太凄美 终于 被人了解\n远离风暴浩劫\n耍狠不是靠对嘴\n我就是传说中的谁\n你跟我们很对味\n有同一挂的感觉\n其它人我根本不屑\n一列 超高速的地铁\n一路 训练我的听觉\n消灭 那些\n太琐碎 太异类\n让问题尖锐 Oh~\n一双 狂奔中的球鞋\n一路 强壮着我的肺\n面对 这些\n太威胁 太强烈\n从来不喊累\n一列 超高速的地铁\n一路 训练我的听觉\n消灭 那些\n太琐碎 太异类\n让问题尖锐 Oh~\n一双 狂奔中的球鞋\n一路 强壮着我的肺\n面对 这些\n太威胁 太强烈\n从来不喊累\n一列 超高速的地铁\n一路 训练我的听觉\n消灭 那些\n太琐碎 太异类\n让问题尖锐 Oh~\n一双 狂奔中的球鞋\n一路 强壮着我的肺\n面对 这些\n太威胁 太强烈\n从来不喊累', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (54, '54', '3', '发如雪', '周杰伦', '方文山', '林迈可', '中国风 (Chinese Style)', '歌词充满诗意典故（如“狼牙月”、“伊人”），旋律凄美，是周氏中国风的巅峰之作之一', '六', '2005-11-01', '十一月的肖邦', '狼牙月 伊人憔悴\n我举杯 饮尽了风雪\n是谁打翻前世柜 惹尘埃是非\n缘字诀 几番轮回\n你锁眉 哭红颜唤不回\n纵然青史已经成灰 我爱不灭\n繁华如三千东流水\n我只取一瓢爱了解\n只恋你化身的蝶\n你发如雪 凄美了离别\n我焚香感动了谁\n邀明月 让回忆皎洁\n爱在月光下完美\n你发如雪 纷飞了眼泪\n我等待苍老了谁\n红尘醉 微醺的岁月\n我用无悔 刻永世爱你的碑\n你发如雪 凄美了离别\n我焚香感动了谁\n邀明月 让回忆皎洁\n爱在月光下完美\n你发如雪 纷飞了眼泪\n我等待苍老了谁\n红尘醉 微醺的岁月\n狼牙月 伊人憔悴\n我举杯 饮尽了风雪\n是谁打翻前世柜 惹尘埃是非\n缘字诀 几番轮回\n你锁眉 哭红颜唤不回\n纵然青史已经成灰 我爱不灭\n繁华如三千东流水\n我只取一瓢爱了解\n只恋你化身的蝶\n你发如雪 凄美了离别\n我焚香感动了谁\n邀明月 让回忆皎洁\n爱在月光下完美\n你发如雪 纷飞了眼泪\n我等待苍老了谁\n红尘醉 微醺的岁月\n我用无悔 刻永世爱你的碑\n你发如雪 凄美了离别\n我焚香感动了谁\n邀明月 让回忆皎洁\n爱在月光下完美\n你发如雪 纷飞了眼泪\n我等待苍老了谁\n红尘醉 微醺的岁月\n你发如雪 凄美了离别\n我焚香感动了谁\n邀明月 让回忆皎洁\n爱在月光下完美\n你发如雪 纷飞了眼泪\n我等待苍老了谁\n红尘醉 微醺的岁月\n我用无悔 刻永世爱你的碑\n啦儿啦 啦儿啦 啦儿啦儿啦\n啦儿啦 啦儿啦 啦儿啦儿啊\n铜镜映无邪 扎马尾\n你若撒野 今生我把酒奉陪\n啦儿啦 啦儿啦 啦儿啦儿啦\n啦儿啦 啦儿啦 啦儿啦儿啊\n铜镜映无邪 扎马尾\n你若撒野 今生我把酒奉陪', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (55, '55', '4', '黑色毛衣', '周杰伦', '周杰伦', '林迈可', '抒情流行/民谣 (Pop/Folk)', '旋律简单，以吉他伴奏为主，情感克制而深沉，讲述一段关于离别与纪念的故事', '六', '2005-11-01', '十一月的肖邦', '一件黑色毛衣\n两个人的回忆\n雨过之后 更难忘记\n忘记我还爱你\n你不用在意\n流泪也只是刚好而已\n我早已经待在谷底\n我知道不能再留住你\n也知道不能没有骨气\n感激你 让我拥有秋天的美丽\n看着那白色的蜻蜓\n在空中忘了前进\n还能不能 重新编织\n脑海中起毛球的记忆\n再说我爱你\n可能雨也不会停\n黑色毛衣 藏在哪里\n就让回忆永远停在那里\n一件黑色毛衣\n两个人的回忆\n雨过之后 更难忘记\n忘记我还爱你\n你不用在意\n流泪也只是刚好而已\n我早已经待在谷底\n我知道不能再留住你\n也知道不能没有骨气\n感激你 让我拥有秋天的美丽\n看着那白色的蜻蜓\n在空中忘了前进\n还能不能 重新编织\n脑海中起毛球的记忆\n再说我爱你\n可能雨也不会停\n黑色毛衣 藏在哪里\n就让回忆永远停在那里\n看着那白色的蜻蜓\n在空中忘了前进\n还能不能 重新编织\n脑海中起毛球的记忆\n再说我爱你\n可能雨也不会停\n黑色毛衣 藏在哪里\n就让回忆永远停在那里', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (56, '56', '5', '四面楚歌', '周杰伦', '周杰伦', '洪敬尧', '嘻哈/说唱 (Hip-Hop/Rap)', '歌词犀利，直接回应媒体和狗仔，节奏感强，是周杰伦少有的直接批判社会现象的说唱作品', '六', '2005-11-01', '十一月的肖邦', '我的生活像 拍了一出戏\n有超多导演跟编剧 只说了台词一句\n而他们配了八百个语气 操控着我的情绪\n那根本不是我的口气 想让观众看好戏\n最后的目的 还不是在促进收视率\n我不知道我有没有勇气 拆下他们的面具\n我只知道好像认真的男人最美丽\n会不会一直演下去 到他们满意\n啦啦 啦 啦啦啦啦\n啦 啦 啦啦啦啦啦\nOh Oh\n我不可能再回头\n啦 啦 啦啦啦啦\n啦 啦 啦啦啦啦啦\nOh Oh\n我只能一直往前走\n我在回家路上 看到路标指着演艺圈\n如果选择往前走 我就必须强壮\n走着走着 莫名其妙\n冲出来好几只狗\n我心想我什么时候认养这么多只狗\n它们咬着苹果 手里拿着长镜头\n好像要对着我诉说什么 阴谋\n会说话的狗 它说它是为了狗周刊\n看能不能拍我 多换几根骨头\n如果伤害我是你的天性\n那怜悯是我的座右铭\n(狗狗狗狗)\n需要我照亮你回家的路\n那我会送你们手电筒\n(狗狗狗狗)\n我告诉他们 八卦是会过去的\n新闻是一时的 生活是永久的\n音乐是会留下来的 我帮它们写了歌\n因为我没写过保育动物之类的歌\n我始终还是我 谁都改变不了我\n虽然我知道很多弓箭手 想射下往上爬的我\n当我到了山顶上头 谁都伤不了我\n这些弓箭手 辛苦了你们提笔的手\n我还是会把你们当朋友\n因为我知道 这是你们大家的工作\n加油 咬着苹果的狗\n虽然不是我的对手\n还是可以成为我的狗\n啦啦 啦 啦啦啦啦\n啦 啦 啦啦啦啦啦\nOh Oh\n我不可能再回头\n啦 啦 啦啦啦啦\n啦 啦 啦啦啦啦啦\nOh Oh\n我只能一直往前走\n? (为什么)\n? ?? ???? ??? ?? (我去哪里都会跟着跑)\n??? ?? ?? ?? ?? ???? ?? ? (这些买卖人的人生的秘密)\n???? (这种压力是不需要的)\n? ?? ??? ?? ?? ???? ?? ?? ??(??) (这首歌结束之前 我会决定怎么处理)\n?? ???? ?? privacy??? (从失去我的隐私权)\n???? ?? family ??? ?? (到烦恼我的家人被骚扰)\n???? ????? ? (该结束)\n? ??? ??? ?? ?? ? (因为反正你找不到你想找到的东西)\n啦啦 啦 啦啦啦啦\n啦 啦 啦啦啦啦啦\nOh Oh\n我不可能再回头\n啦 啦 啦啦啦啦\n啦 啦 啦啦啦啦啦\nOh Oh\n我只能一直往前走\n深怕没有了新闻\n才学会开车 来跟踪别人 Oh Oh\n为了什么 Oh Oh 为了骨头\n偷窥别人的生活\n自以为侦探 看太多柯南 Oh Oh\n拍了什么 Oh Oh 什么都没有', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (57, '57', '6', '枫', '周杰伦', '宋健彰', '钟兴民', '抒情摇滚 (Ballad Rock)', '情感浓烈，副歌爆发力极强，配合钢琴与弦乐，是失恋主题的经典抒情摇滚', '六', '2005-11-01', '十一月的肖邦', '乌云在我们心里 搁下一块阴影我聆听沉寂已久的心情清晰透明就像美丽的风景总在回忆里才看得清被伤透的心 能不能够继续爱我我用力牵起没温度的双手过往温柔已经被时间上锁只剩挥散不去的难过缓缓飘落的枫叶像思念我点燃烛火温暖 岁末的秋天极光掠夺天边北风掠过想你的容颜我把爱烧成了落叶却换不回熟悉的那张脸缓缓飘落的枫叶像思念为何挽回要赶在冬天来之前爱你穿越时间两行来自秋末的眼泪让爱渗透了地面我要的只是你 在我身边被伤透的心 能不能够继续爱我我用力牵起没温度的双手过往温柔已经被时间上锁只剩挥散不去的难过在山腰间飘逸的红雨随着北风凋零我轻轻摇曳风铃想 唤醒被遗弃的爱情雪花已铺满了地深怕窗外枫叶已结成冰缓缓飘落的枫叶像思念我点燃烛火温暖 岁末的秋天极光掠夺天边北风掠过想你的容颜我把爱烧成了落叶却换不回熟悉的那张脸缓缓飘落的枫叶像思念为何挽回要赶在冬天来之前爱你穿越时间两行来自秋末的眼泪让爱渗透了地面我要的只是你 在我身边', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (58, '58', '7', '浪漫手机', '周杰伦', '方文山', '洪敬尧', '流行/电子 (Pop/Electronic)', '轻快的流行曲，加入电子音效，主题围绕现代通讯工具，表达爱意', '六', '2005-11-01', '十一月的肖邦', '轻轻放我就是卸不下对你的喜欢原来爱会慢慢增加重量想关上这城市所有的灯光黑暗中专心闻你的发香这夜晚 让暗恋更有画面感回想 与你约会过的地方都舍不得删在脑海里储存欣赏你微笑浏览手机里的浪漫原来真心送出爱是这么简单温习荧幕上你可爱的模样关于缘分的解释我又多传了一行你微笑浏览手机里的浪漫原来爱情可以来得这么突然短讯的桥梁将暧昧期拉长我们的感情蔓延滋长用文字培养在虚拟土壤电视墙吵杂的情歌还在拼命播放我安静在闹区等来电铃响有一些话打好了却不敢传怕收到讯息的你在为难街道上 人潮衬托我的孤单想象 谁幸运地陪在你身旁却误会一场你也在等你手机响你微笑浏览手机里的浪漫原来真心送出爱是这么简单温习荧幕上你可爱的模样关于缘分的解释我又多传了一行你微笑浏览手机里的浪漫原来爱情可以来的这么突然短讯的桥梁将暧昧期拉长我们的感情蔓延滋长用文字培养在虚拟土壤', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (59, '59', '8', '逆鳞', '周杰伦', '黄俊郎', '钟兴民', '中国风/摇滚 (Chinese Style/Rock)', '以“逆鳞”比喻不可触碰的底线，编曲磅礴，融合中国五声音阶与重型摇滚', '六', '2005-11-01', '十一月的肖邦', '而生命 对每个人都不公平 也没道理\n只能扑向泥泞迎向那阵骤雨由不得你\nyeah~\n突来的骤雨 这条街一路泥泞\n就像人生 不过是一场即兴\n整个世界 正在对我们挑衅\n就算如此 还是得无惧前进\n手中的邮报 封面的人在微笑\n下个路口 生命在暗巷尖叫\n活着只是 油墨上面的一角\n明天之后 还有谁翻阅得得到\n我跟你用不同方式\n踩过前方带刺荆棘\n你嚣张不畏惧退缩\n我低头沉默却坚定\n用力的还击 发出声音\n让他们安静 不敢相信 继续前进\n他们畏惧 睁大眼睛\n他们躲避 然后放弃\n专心聆听 我的声音\n而生命 对每个人都不公平 也没道理\n只能扑向泥泞迎向那阵骤雨由不得你\n如果生命 对每个人都不公平 也没道理\n那就让我带着孤寂继续前进 直到光明\n我 我 我只有一种容貌\n我就是永远不会倒\n我就算逆境环绕\n我面对也要带着笑\n我只有一种咆哮\n我要让他们都知道\n我生命再怎么粗糙\n我都要活得很骄傲\n我说自尊阿 看起来或许可笑\n但它至少 撑着我 试着不让我跌倒\n活着 如果只是不甘寂静的喧嚣\n那就咆哮吧 让每个人都能听得到\n用力的还击 发出声音\n让他们安静 不敢相信 继续前进\n他们畏惧 睁大眼睛\n他们躲避 然后放弃\n专心聆听 我的声音\n而生命 对每个人都不公平 也没道理\n只能扑向泥泞迎向那阵骤雨由不得你\n如果生命 对每个人都不公平 也没道理\n那就让我带着孤寂继续前进 直到光明\n而生命 对每个人都不公平 也没道理\n只能扑向泥泞迎向那阵骤雨由不得你\n如果生命 对每个人都不公平 也没道理\n那就让我带着孤寂继续前进 直到光明\n而生命 对每个人都不公平 也没道理\n只能扑向泥泞迎向那阵骤雨由不得你\n如果生命 对每个人都不公平 也没道理\n那就让我带着孤寂继续前进', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (60, '60', '9', '麦芽糖', '周杰伦', '方文山', '洪敬尧', '雷鬼/嘻哈 (Reggae/Hip-Hop)', '节奏慵懒，带有明显的雷鬼（Reggae）风格，描绘爱情的甜蜜与悠闲', '六', '2005-11-01', '十一月的肖邦', '这蜿蜒的微笑拥抱山丘\n溪流跟风唱起歌\n我像田园诗人般\n解读眼前的生活\n麦田弯腰低头在垂钓温柔\n这整座山谷都是风笛手\n我在哑口聆听传说\n跟着童话故事走\n远方的风车\n远距离诉说\n那幸福在深秋\n满满的被收割\n老仓库的角落\n我们数着一麻袋的爱跟快乐\n初恋的颜色\n我牵着你的手经过\n种麦芽糖的山坡\n香浓的诱惑\n你脸颊微热\n吐气在我的耳朵\n摘下麦芽糖熟透\n我醒来还笑着\n开心的 被黏手\n我满嘴 都是糖果\n牵着你的手经过\n种麦芽糖的山坡\n甜蜜的四周\n我低头害羞\n我们愉快的梦游\n我在草地上喝着\n麦芽糖酿的酒\n鲜嫩的 小时候\n我好想 再咬一口\n这蜿蜒的微笑拥抱山丘\n溪流跟风唱起歌\n我像田园诗人般\n解读眼前的生活\n??????（泰文：你好）\n麦田弯腰低头在垂钓温柔\n这整座山谷都是风笛手\n我在哑口聆听传说\n跟着童话故事走\n远方的风车\n远距离诉说\n那幸福在深秋\n满满的被收割\n老仓库的角落\n我们数着一麻袋的爱跟快乐\n初恋的颜色\n我牵着你的手经过\n种麦芽糖的山坡\n香浓的诱惑\n你脸颊微热\n吐气在我的耳朵\n摘下麦芽糖熟透\n我醒来还笑着\n开心的 被黏手\n我满嘴 都是糖果\n牵着你的手经过\n种麦芽糖的山坡\n甜蜜的四周\n我低头害羞\n我们愉快的梦游\n我在草地上喝着\n麦芽糖酿的酒\n鲜嫩的 小时候\n我好想 再咬一口\n牵着你的手经过\n种麦芽糖的山坡\n甜蜜的四周\n我低头害羞\n我们愉快的梦游\n我在草地上喝着\n麦芽糖酿的酒\n鲜嫩的 小时候\n我好想 再咬一口\n????????(泰文：我爱你)\n????????\n????????\n????????\n????????\n????????\n????????\n????????\n我满嘴 都是糖果\n我好想 再咬一口', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (61, '61', '10', '珊瑚海', '周杰伦', '方文山', '钟兴民', '流行/抒情 (Pop/Ballad)（与梁心颐合唱）', '以“海”喻情，旋律优美，是男女对唱的经典情歌', '六', '2005-11-01', '十一月的肖邦', '男：海平面远方开始阴霾\n悲伤要怎么平静纯白\n我的脸上 始终挟带\n一抹浅浅的无奈\n女：你用唇语说你要离开（男：心不在）\n合：那难过无声慢了下来\n汹涌潮水 你听明白\n不是浪而是泪海\n男：转身离开 分手说不出来（女：你有话说不出来）\n合：海鸟跟鱼相爱\n只是一场意外\n男：我们的爱（女：给的爱）\n合：差异一直存在 （女：回不来）\n男：风中尘埃 （女：等待）\n合：竟累积成伤害\n转身离开 分手说不出来\n蔚蓝的珊瑚海\n错过瞬间苍白\n男：当初彼此（女：你我都）\n合：不够成熟坦白 （女：不应该）\n男：热情不再 （女：你的）\n合：笑容勉强不来\n爱深埋珊瑚海\n男：毁坏的沙雕如何重来\n有裂痕的爱怎么重盖\n只是一切 结束太快\n你说你无法释怀\n女：贝壳里隐藏什么期待（男：等花儿开）\n合：我们也已经无心再猜\n女：面向海风（男：面向海风）\n咸咸的爱（咸咸的爱）\n合：尝不出还有未来\n男：转身离开 分手说不出来（女：你有话说不出来）\n合：海鸟跟鱼相爱\n只是一场意外\n男：我们的爱（女：给的爱）\n合：差异一直存在 （女：回不来）\n男：风中尘埃 （女：等待）\n合：竟累积成伤害\n转身离开 分手说不出来\n蔚蓝的珊瑚海\n错过瞬间苍白\n男：当初彼此（女：你我都）\n合：不够成熟坦白 （女：不应该）\n男：热情不再 （女：你的）\n合：笑容勉强不来\n爱深埋珊瑚海', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (62, '62', '11', '飘移', '周杰伦', '方文山', '林迈可', '电子摇滚/舞曲 (Electro Rock/Dance)（与方文山合唱）', '为汽车广告创作，节奏快，模拟赛车的“飘移”感，电子元素突出', '六', '2005-11-01', '十一月的肖邦', '找支笔 写下日记 记录勇气\n我可以对着墙壁 让拳头叛逆\n呼吸 天窗玻璃 打开我的身体\n这里 引擎声就像是一种乐器\n所以 风呼啸而过刺激\n所以 我在转弯飘移\n加足了马力 飘到底看仔细\n零到一百公里 谁敢与我为敌\n我用第一人称 在飘移青春\n输跟赢的分寸 计算的很精准\n我踏上风火轮 在飘移青春\n故事中的我们 在演自己的人生\n胜败的对比 是残酷的可以\n运气 从来就不在我这里\n实力没办法模拟 飘移\n人车一体 飘移\n笑看后视镜的自己 啊\n点火 继续 事关 荣誉\n我除了第一 其他没有兴趣\n得飘 得飘 得咿的飘\n我安静的喝饮料 轻松的笑\n我用第一人称 在飘移青春\n输跟赢的分寸 计算得很精准\n我踏上风火轮 在飘移青春\n故事中的我们 在演自己的人生\n得飘 得飘 得咿的飘\n（得飘 得飘 得咿的飘）\n我绕过山腰 雨声敲敲\n（我绕过山腰 雨声敲敲）\n得飘 得飘 得咿的飘\n（得飘 得飘 得咿的飘）\n再开进隧道 风声潇潇\n（再开进隧道 风声潇潇）\n我用第一人称 在飘移青春\n输跟赢的分寸 计算得很精准\n我踏上风火轮 在飘移青春\n故事中的我们 在演自己的人生', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (63, '63', '12', '一路向北', '周杰伦', '方文山', '蔡科俊', '抒情摇滚 (Ballad Rock)', '电影《头文字D》插曲，旋律悲情，表达离别的伤感与对过去的追忆', '六', '2005-11-01', '十一月的肖邦', '后视镜里的世界\n越来越远的道别\n你转身向背\n侧脸还是很美\n我用眼光去追\n竟听见你的泪\n在车窗外面徘徊\n是我错失的机会\n你站的方位\n跟我中间隔着泪\n街景一直在后退\n你的崩溃在窗外零碎\n我一路向北\n离开有你的季节\n你说你好累\n已无法再爱上谁\n风在山路吹\n过往的画面全都是我不对\n细数惭愧 我伤你几回\n后视镜里的世界\n越来越远的道别\n你转身向背\n侧脸还是很美\n我用眼光去追\n竟听见你的泪\n在车窗外面徘徊\n是我错失的机会\n你站的方位\n跟我中间隔着泪\n街景一直在后退\n你的崩溃在窗外零碎\n我一路向北\n离开有你的季节\n你说你好累\n已无法再爱上谁\n风在山路吹\n过往的画面全都是我不对\n细数惭愧 我伤你几回\n我一路向北\n离开有你的季节\n方向盘周围\n回转着我的后悔\n我加速超越\n却甩不掉紧紧跟随的伤悲\n细数惭愧 我伤你几回\n停止狼狈 就让错纯粹', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (64, '64', '1', '夜的第七章', '周杰伦', '黄俊郎', '钟兴民、林迈可', '古典说唱/侦探风 (Orchestral Rap/Detective Style)', '延续《夜曲》的哥特风格，加入侦探小说叙事，编曲复杂华丽，如同一部音乐剧', '七', '2006-09-05', '依然范特西', '1983年小巷\n12月晴朗\n夜的第七章\n打字机继续推向\n接近事实的那下一行\n石楠烟斗的雾\n飘向枯萎的树\n沉默的对我哭诉\n贝克街旁的圆形广场\n盔甲骑士臂上\n鸢尾花的徽章 微亮\n无人马车声响\n深夜的拜访\n邪恶 在维多利亚的月光下\n血色的开场\n消失的手枪\n焦黑的手杖\n融化的蜡像\n谁不在场\n珠宝箱上\n符号的假象\n矛盾通往 他堆砌的死巷\n证据被完美埋葬\n那嘲弄苏格兰警场 的嘴角上扬\n如果邪恶 是华丽残酷的乐章\n(那么正义 是深沉无奈的惆怅)\n它的终场 我会 亲手写上\n(那我就点亮 在灰烬中的微光)\n晨曦的光 风干最后一行忧伤\n(那么雨滴 会洗净黑暗的高墙)\n黑色的墨 染上安详\n(散场灯关上 红色的布幕下降)\n事实只能穿向\n没有脚印的土壤\n突兀的细微花香\n刻意显眼的服装\n每个人为不同的理由戴着面具说谎\n动机也只有一种名字那叫做欲望\nFar farther farther far\nFarther ther far farther far far\n越过人性的沼泽\n谁真的可以不被弄脏\n我们可以 遗忘 原谅\n但必须知道真相\n被移动过的铁床\n那最后一块图终于拼上\n我听见脚步声\n预料的软皮鞋跟\n他推开门晚风晃了煤油灯 一阵\n打字机停在凶手的名称我转身\n西敏寺的夜空 开始沸腾\n在胸口绽放 艳丽的死亡\n我品尝这最后一口甜美的真相\n微笑回想正义只是安静的伸张\n提琴在泰晤士\n脚步声预料的软皮鞋跟\n他推开门晚风晃了煤油灯 一阵\n打字机停在凶手的名称我转身\n西敏寺的夜空 开始沸腾\n黑色的墨 染上安详\n如果邪恶 是华丽残酷的乐章\n它的终场 我会 亲手写上\n晨曦的光 风干最后一行忧伤\n黑色的墨 染上安详', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (65, '65', '2', '听妈妈的话', '周杰伦', '周杰伦', '林迈可、洪敬尧', '嘻哈/流行说唱 (Hip-Hop/Pop Rap)', '节奏轻快，歌词励志，劝导孩子要听妈妈的话，是充满正能量的说唱作品', '七', '2006-09-05', '依然范特西', '小朋友 你是否有很多问号\n为什么 别人在那看漫画\n我却在学画画 对着钢琴说话\n别人在玩游戏\n我却靠在墙壁背我的 ABC\n我说我要一台大大的飞机\n但却得到一台旧旧录音机\n为什么要听妈妈的话\n长大后你就会开始懂了这段话\n长大后我开始明白\n为什么我跑得比别人快\n飞得比别人高\n将来大家看的都是 我画的漫画\n大家唱的都是 我写的歌\n妈妈的辛苦 不让你看见\n温暖的食谱 在她心里面\n有空就多多握握她的手\n把手牵着一起梦游\n听妈妈的话 别让她受伤\n想快快长大 才能保护她\n美丽的白发 幸福中发芽\n天使的魔法 温暖中慈祥\n在你的未来\n音乐是你的王牌\n拿王牌谈个恋爱\n唉 我不想把你教坏\n还是听妈妈的话吧\n晚点再恋爱吧\n我知道你未来的路\n但妈比我更清楚\n你会开始学其他同学在书包写东写西\n但我建议最好写妈妈我会用功读书\n用功读书 怎么会从我嘴巴说出\n不想你输 所以要叫你用功读书\n妈妈织给你的毛衣\n你要好好的收着\n因为母亲节到时我要告诉她我还留着\n对了 我会遇到周润发\n所以你可以跟同学炫耀\n赌神未来是你爸爸\n我找不到 童年写的情书\n你写完不要送人\n因为过两天你会在操场上捡到\n你会开始喜欢上流行歌\n因为张学友开始准备唱吻别\n听妈妈的话 别让她受伤\n想快快长大 才能保护她\n美丽的白发 幸福中发芽\n天使的魔法 温暖中慈祥\n听妈妈的话 别让她受伤\n想快快长大 才能保护她\n长大后我开始明白\n为什么我跑得比别人快\n飞得比别人高\n将来大家看的都是 我画的漫画\n大家唱的都是 我写的歌\n妈妈的辛苦 不让你看见\n温暖的食谱 在她心里面\n有空就多多握握她的手\n把手牵着一起梦游\n听妈妈的话 别让她受伤\n想快快长大 才能保护她\n美丽的白发 幸福中发芽\n天使的魔法 温暖中慈祥', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (66, '66', '3', '千里之外', '周杰伦', '方文山', '林迈可', '中国风/流行 (Chinese Style/Pop)（与费玉清合唱）', '融合传统戏曲韵味与现代流行，描绘远距离的无奈爱情', '七', '2006-09-05', '依然范特西', '周：屋檐如悬崖 风铃如沧海\n我等燕归来\n时间被安排 演一场意外\n你悄然走开\n故事在城外 浓雾散不开\n看不清对白\n你听不出来 风声不存在\n是我在感慨\n梦醒来 是谁在窗台\n把结局打开\n那薄如蝉翼的未来\n经不起谁来拆\n费：我送你离开 千里之外\n你无声黑白\n沉默年代 或许不该\n太遥远的相爱\n我送你离开 天涯之外\n你是否还在\n琴声何来 生死难猜\n用一生 去等待\n周：闻泪声入林 寻梨花白\n只得一行 青苔\n天在山之外 雨落花台\n我两鬓斑白\n闻泪声入林 寻梨花白\n只得一行 青苔\n天在山之外 雨落花台\n我等你来\n费：一身琉璃白 透明着尘埃\n你无瑕的爱\n你从雨中来 诗化了悲哀\n我淋湿现在\n周：芙蓉水面采 船行影犹在\n你却不回来\n被岁月覆盖 你说的花开\n过去成空白\n费：梦醒来 是谁在窗台\n把结局打开\n周：那薄如蝉翼的未来\n经不起谁来拆\n费：我送你离开 千里之外\n你无声黑白\n沉默年代 或许不该\n太遥远的相爱\n周：我送你离开 天涯之外\n你是否还在\n琴声何来 生死难猜\n用一生\n费：我送你离开 千里之外\n你无声黑白\n沉默年代 或许不该\n太遥远的相爱\n周：我送你离开 天涯之外\n你是否还在\n琴声何来\n费：生死难猜\n合：用一生 去等待', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (67, '67', '4', '本草纲目', '周杰伦', '方文山', '林迈可', '中国风/嘻哈 (Chinese Style/Hip-Hop)', '将传统中医药材入词，节奏强劲，旨在弘扬民族文化，极具颠覆性', '七', '2006-09-05', '依然范特西', '如果华陀再世 崇洋都被医治\n外邦来学汉字 激发我民族意识\n马钱子 决明子 苍耳子 还有莲子\n黄药子 苦豆子 川楝子 我要面子\n用我的方式 改写一部历史\n没什么别的事 跟着我念几个字\n山药 当归 枸杞 Go\n山药 当归 枸杞 Go\n看我抓一把中药 服下一帖骄傲\n我表情悠哉 跳个大概\n动作轻松自在 你学不来\n霓虹的招牌 调整好状态\n在华丽的城市 等待醒来\n我表情悠哉 跳个大概\n用书法书朝代 内力传开\n豪气挥正楷 给一拳对白\n结局平躺下来 看谁厉害\n练成什么丹\n揉成什么丸\n鹿茸切片不能太薄\n老师傅的手法不能这样乱抄\n龟苓膏 云南白药\n还有冬虫夏草\n自己的音乐自己的药 份量刚刚好\n听我说中药苦\n抄袭应该更苦\n快翻开本草纲目 多看一些善本书\n蟾苏 地龙 已翻过江湖\n这些老祖宗的辛苦\n我们一定不能输\n就是这个光 就是这个光\n一起唱\n就是这个光 就是这个光 嘿\n让我来调个偏方\n专治你媚外的内伤\n已扎根千年的汉方\n有别人不知道的力量\n我表情悠哉 跳个大概\n动作轻松自在 你学不来\n霓虹的招牌 调整好状态\n在华丽的城市 等待醒来\n我表情悠哉 跳个大概\n用书法书朝代 内力传开\n豪气挥正楷 给一拳对白\n结局平躺下来 看谁厉害\n蹲 小僵尸蹲 小僵尸蹲\n又蹲 小僵尸蹲 暗巷点灯\n又蹲 小僵尸蹲 钻萝卜坑\n又蹲 小僵尸蹲 念咒语哼\n蹲 小僵尸蹲 小僵尸蹲\n又蹲 小僵尸蹲 暗巷点灯\n又蹲 小僵尸蹲 钻萝卜坑\n又蹲 小僵尸蹲 念咒语哼', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (68, '68', '5', '退后', '周杰伦', '宋健彰', '林迈可', 'R&B/抒情 (R&B/Ballad)', '旋律优美，带有R&B的转音，讲述一段错过的爱情', '七', '2006-09-05', '依然范特西', '天空灰得像哭过\n离开你以后 并没有 更自由\n酸酸的空气 嗅出我们的距离\n一幕锥心的结局\n像呼吸般无法停息\n抽屉泛黄的日记\n榨干了回忆\n那笑容 是夏季\n你我的过去被顺时针的忘记\n缺氧过后的爱情\n粗心的眼泪是多余\n我知道你我都没有错\n只是忘了怎么退后\n信誓旦旦给了承诺\n却被时间扑了空\n我知道我们都没有错\n只是放手会比较好过\n最美的爱情 回忆里待续\n天空灰得像哭过\n离开你以后 并没有 更自由\n酸酸的空气 嗅出我们的距离\n一幕锥心的结局\n像呼吸般无法停息\n抽屉泛黄的日记\n榨干了回忆\n那笑容 是夏季\n你我的过去被顺时针的忘记\n缺氧过后的爱情\n粗心的眼泪是多余\n我知道你我都没有错\n只是忘了怎么退后\n信誓旦旦给了承诺\n却被时间扑了空\n我知道我们都没有错\n只是放手会比较好过\n最美的爱情 回忆里待续\n我知道你我都没有错\n只是忘了怎么退后\n信誓旦旦给了承诺\n却被时间扑了空\n我知道我们都没有错\n只是放手会比较好过\n最美的爱情 回忆里待续', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (69, '69', '6', '红模仿', '周杰伦', '周杰伦', '林迈可', '摇滚/讽刺说唱 (Rock/Satirical Rap)', '讽刺娱乐圈的模仿现象，编曲狂野，说唱犀利，带有车库摇滚味道', '七', '2006-09-05', '依然范特西', '巨炮:诶吆~吉他谁教你的啊\n杰伦:啊~我生下来就会啊 你不知道\n巨炮:诶吆~P咧\n中国风的歌曲 有增无减\n是好是坏 问方文山最清楚\n从娘子唱到双截棍 东风破到发如雪\n一路走来始终如一\n多样的曲风 独爱中国风\n我坚持风格 我活在我的世界\n谁都插不上嘴\n唱反调 是我的本性\n出奇不意是我的个性\n就算我站在山顶\n也只不过是个平民老百姓\n但我的肩膀 会有两块空地\n那就是勇气与毅力\n我要做音乐上的皇帝\n哼哼哈兮 哼哼哈兮\n哼哼哈兮 哼哼哈兮\n下坡的路 不费功夫\n别人已经帮你铺路\n但我选择上坡 因为我取名叫自负\n谦虚和那虚伪 就只差一个字\n有时有点分不清\n因为我喜欢真实的自己\n我不能够后退 因为不是绿叶\n如果只是点缀 愿当皎洁明月\n小草等待风吹 不用靠你的背\n假如天会很黑 我会请嫦娥奔月\n为什么写这首歌\n我现在还找不到动机\n不过用心听下去\n你会觉得更有意义\n如果你对未来产生恐惧\n眼前雾濛濛一片\n那是因为你没把眼镜给擦干净\n勇敢走下去 这首歌会陪你前进\n我常常在想宇宙只有一颗太阳\n为什么我的影子这么多 这么像\n战胜幻象 和我一样\n喜欢模仿的朋友们\n崇拜是件好事 欣赏是种美德\n但走在我后面 我很担心\n别人会看不见你\n到最后只是一个接一个的分身\n这样的鼓励 是否太直接 太讽刺\n老师在讲 到底有没有在听啊\n我告诉你 做自己胜于跟太紧\n最大的敌人就是那内心的自己\n我不能够后退 因为不是绿叶\n如果只是点缀 愿当皎洁明月\n小草等待风吹 不用靠你的背\n假如天会很黑 我会请嫦娥奔月\n哎呦哎呦喔 哎呦哎呦喔喔\n哎呦 不错\n哎呦哎呦喔 哎呦哎呦喔喔\n哎呦 好久不见\n哎呦哎呦喔 哎呦哎呦喔喔\n哎呦 的意思是\n哎呦哎呦喔 哎呦哎呦喔喔\n就是你没话讲的时候可以 哎呦\n哎呦哎呦喔 哎呦哎呦喔喔\n哎呦哎呦喔 哎呦哎呦喔喔\n哎呦哎呦喔 哎呦哎呦喔喔\n哎呦哎呦喔 哎呦哎呦喔嘿\n哎呦哎呦喔 哎呦哎呦喔喔\n哎呦哎呦喔 哎呦哎呦喔喔\n哎呦哎呦喔 哎呦哎呦喔喔\n哎呦哎呦喔 哎呦哎呦喔嘿', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (70, '70', '7', '心雨', '周杰伦', '方文山', '林迈可', '流行/抒情 (Pop/Ballad)', '旋律简单直接，是典型的流行情歌', '七', '2006-09-05', '依然范特西', '橡树的绿叶啊\n白色的竹篱笆\n好想告诉我的她\n这里像幅画\n去年的圣诞卡\n镜子里的胡渣\n画面开始没有她\n我还在装傻 oh~\n说好为我泡花茶\n学习摆刀叉\n学生宿舍空荡荡的家\n守着电话却等不到她\n心里的雨倾盆而下\n也沾不湿她的发\n泪晕开明信片上的牵挂\n那伤心原来没有时差\n心里的雨倾盆而下\n却始终淋不到她\n寒风经过院子里的枝桠\n也冷却了我手中的鲜花\n橡树的绿叶啊\n白色的竹篱笆\n好想告诉我的她\n这里像幅画\n去年的圣诞卡\n镜子里的胡渣\n画面开始没有她\n我还在装傻\n说好为我泡花茶\n学习摆刀叉\n学生宿舍空荡荡的家\n守着电话却等不到她\n心里的雨倾盆而下\n也沾不湿她的发\n泪晕开明信片上的牵挂\n那伤心原来没有时差\n心里的雨倾盆而下\n却始终淋不到她\n寒风经过院子里的枝桠\n也冷却了我手中的鲜花\n心里的雨倾盆而下\n也沾不湿她的发\n泪晕开明信片上的牵挂\n那伤心原来没有时差\n心里的雨倾盆的下\n却始终淋不到她\n寒风经过院子里的枝桠\n也冷却了我手中的鲜花', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (71, '71', '8', '白色风车', '周杰伦', '周杰伦', '蔡科俊', '抒情流行 (Ballad Pop)', '旋律纯净，以钢琴为主，充满童话般的浪漫与淡淡的忧伤', '七', '2006-09-05', '依然范特西', '白色的风车\n安静地转着\n真实的感觉\n梦境般遥远\n甜甜的海水\n复杂的眼泪\n看你傻笑着\n握住我的手\n梦希望没有尽头\n我们走到这就好\n因为我不想太快走完这幸福\n很可惜没有祝福\n但爱你并不孤独\n不会再让你哭\n我背你走到最后\n能不能不要回头\n你紧紧地抱住我\n说你不需要承诺\n你说我若一个人会比较自由\n我不懂你说什么\n反正不会松手\n我背你走到最后\n能不能别想太多\n会不会手牵着手\n晚一点才到尽头\n你说不该再相见只为了瞬间\n谢谢你让我听见\n因为我在等待永远\n白色的风车\n安静地转着\n真实的感觉\n梦境般遥远\n甜甜的海水\n复杂的眼泪\n看你傻笑着\n握住我的手\n很可惜没有祝福\n但爱你并不孤独\n不会再让你哭\n我背你走到最后\n能不能不要回头\n你紧紧地抱住我\n说你不需要承诺\n你说我若一个人会比较自由\n我不懂你说什么\n反正不会松手\n我背你走到最后\n能不能别想太多\n会不会手牵着手\n晚一点才到尽头\n你说不该再相见只为了瞬间\n谢谢你让我听见\n因为我在等待永远\n谢谢你让我听见\n因为我在等待永远', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (72, '72', '9', '迷迭香', '周杰伦', '方文山', '钟兴民', '爵士/嘻哈 (Jazz/Hip-Hop)', '慵懒的爵士鼓点与即兴说唱结合，营造出迷幻、诱惑的氛围', '七', '2006-09-05', '依然范特西', '你的嘴角 微微上翘\n性感的无可救药\n想象不到 如此心跳\n你的一切都想要\n软性的饮料 上升的气泡\n我将对你的喜好\n一瓶装 全喝掉\n这里最不缺就是热闹\n你煽情 给拥抱\n烛火在燃烧 有某种情调\n眼神失焦了几秒\n关于你的舞蹈\n你慵懒的扭动着腰 受不了\n你随风飘扬的笑\n有迷迭香的味道\n语带薄荷味的撒娇\n对我发出恋爱的讯号\n你优雅地像一只猫\n动作轻盈地围绕\n爱的甜味蔓延发酵\n暧昧 来的 刚好\n软性的饮料 上升的气泡\n我将对你的喜好\n一瓶装 全喝掉\n这里最不缺就是热闹\n你煽情 给拥抱\n烛火在燃烧 有某种情调\n眼神失焦了几秒\n关于你的舞蹈\n你慵懒的扭动着腰 受不了\n你随风飘扬的笑\n有迷迭香的味道\n语带薄荷味的撒娇\n对我发出恋爱的讯号\n你优雅地像一只猫\n动作轻盈地围绕\n爱的甜味蔓延发酵\n暧昧 来的 刚好\n你的嘴角 微微上翘\n性感的无可救药\n想像不到 如此心跳\n你的一切都想要\n你的唇膏 鲜艳讨好\n一股自信的骄傲\n什么预兆 气氛微妙\n因为爱你我知道\n预兆 气氛微妙\n因为爱你我知道', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (73, '73', '10', '菊花台', '周杰伦', '方文山', '钟兴民', '中国风 (Chinese Style)', '电影《满城尽带黄金甲》主题曲，旋律哀婉，编曲宏大，充满悲剧色彩和古典美', '七', '2006-09-05', '依然范特西', '你 的泪光 柔弱中带伤\n惨白的月弯弯 勾住过往\n夜 太漫长 凝结成了霜\n是谁在阁楼上 冰冷的绝望\n雨 轻轻弹 朱红色的窗\n我一生在纸上 被风吹乱\n梦 在远方 化成一缕香\n随风飘散 你的模样\n菊花残 满地伤\n你的笑容已泛黄\n花落人断肠 我心事静静躺\n北风乱 夜未央\n你的影子剪不断\n徒留我孤单在湖面 成双\n花 已向晚 飘落了灿烂\n凋谢的世道上 命运不堪\n愁 莫渡江 秋心拆两半\n怕你上不了岸 一辈子摇晃\n谁 的江山 马蹄声狂乱\n我一身的戎装 呼啸沧桑\n天 微微亮 你轻声的叹\n一夜惆怅 如此委婉\n菊花残 满地伤\n你的笑容已泛黄\n花落人断肠 我心事静静躺\n北风乱 夜未央\n你的影子剪不断\n徒留我孤单在湖面 成双\n菊花残 满地伤\n你的笑容已泛黄\n花落人断肠 我心事静静躺\n北风乱 夜未央\n你的影子剪不断\n徒留我孤单在湖面 成双', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (74, '74', '01', '牛仔很忙', '周杰伦', '黄俊郎', '钟兴民', '乡村摇滚/流行 (Country Rock/Pop)', '周杰伦少见的美式乡村风格，节奏轻快，带有口哨声，充满玩乐气息', '八', '2007-11-01', '我很忙', '呜啦啦啦火车笛 随着奔腾的马蹄，小妹妹吹着口琴夕阳下美了剪影，我用子弹写日记介绍完了风景，接下来换介绍我自己，我虽然是个牛仔在酒吧只点牛奶，为什么不喝啤酒因为啤酒伤身体，很多人不长眼睛嚣张都靠武器，赤手空拳就缩成蚂蚁，不用麻烦了 不用麻烦了，不用麻烦 不用麻烦了 不用麻烦了，你们一起上 我在赶时间，每天决斗观众都累了 英雄也累了，不用麻烦了 不用麻烦了，副歌不长你们有几个 一起上好了，正义呼唤我 美女需要我 牛仔很忙的，（心爱ㄟ你走去叨位），（我那ㄟ拢没看到你），我啦啦啦骑毛驴因为马跨不上去，洗澡都洗泡泡浴因为可以玩玩具，我有颗善良的心 都只穿假牛皮，喔 跌倒时尽量不压草皮，枪口它没长眼睛 我曾经答应上帝，除非是万不得已 我尽量射橡皮筋，老板先来杯奶昔要逃命前请你，顺便喂喂我那只小毛驴，不用麻烦了 不用麻烦了，不用麻烦不用麻烦了 不用麻烦了，你们一起上 我在赶时间，每天决斗观众都累了 英雄也累了，不用麻烦了 不用麻烦了，副歌不长你们有几个 一起上好了，正义呼唤我 美女需要我 牛仔很忙的，不用麻烦了 不用麻烦了，不用麻烦不用麻烦了 不用麻烦了，你们一起上 我在赶时间，每天决斗观众都累了 英雄也累了，不用麻烦了 不用麻烦了，副歌不长你们有几个 一起上好了，正义呼唤我 美女需要我 牛仔很忙的', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (75, '75', '02', '彩虹', '周杰伦', '周杰伦', '林迈可', '抒情流行 (Ballad Pop)', '旋律简单却极其动人，以吉他分解和弦为主，表达对爱情的期待与脆弱', '八', '2007-11-01', '我很忙', '哪里里有彩虹告诉我，能不能把我的愿望还给我，为什么天这么安静，所有的云都跑到我这里，有没有口罩一个给我，释怀说了太多就成真不了，也许时间是一种解药，也是我现在正服下的毒药，看不见你的笑 我怎么睡得着，你的身影这么近我却抱不到，没有地球太阳还是会绕，没有理由我也能自己走，你要离开 我知道很简单，你说依赖 是我们的阻碍，就算放开 但能不能别没收我的爱，当作我最后才明白，有没有口罩一个给我，释怀说了太多就成真不了，也许时间是一种解药，也是我现在正服下的毒药，看不见你的笑 我怎么睡得着，你的声音这么近我却抱不到，没有地球太阳还是会绕，没有理由我也能自己走，你要离开 我知道很简单，你说依赖 是我们的阻碍，就算放开 但能不能别没收我的爱，当作我最后才明白，看不见你的笑，要我怎么睡得着，你的身影这么近我却抱不到，没有地球太阳开始会绕会绕，没有理由我也能自己走掉，释怀说了太多就成真不了，也许时间是一种解药解药，也是我现在正服下的毒药，你要离开 我知道很简单，你说依赖 是我们的阻碍，就算放开 但能不能别没收我的爱，当作我最后才明白', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (76, '76', '03', '青花瓷', '周杰伦', '方文山', '钟兴民', '中国风 (Chinese Style)', '将瓷器之美写入歌词，意境唯美，是周氏中国风最广为人知的代表作之一', '八', '2007-11-01', '我很忙', '素胚勾勒出青花 笔锋浓转淡，瓶身描绘的牡丹一如你初妆，冉冉檀香透过窗 心事我了然，宣纸上走笔至此搁一半，釉色渲染仕女图 韵味被私藏，而你嫣然的一笑 如含苞待放，你的美一缕飘散 去到我去不了的地方，天青色等烟雨 而我在等你，炊烟袅袅升起 隔江千万里，在瓶底书汉隶 仿前朝的飘逸，就当我为遇见你伏笔，天青色等烟雨 而我在等你，月色被打捞起 晕开了结局，如传世的青花瓷自顾自美丽 你眼带笑意，色白花青的锦鲤跃然于碗底，临摹宋体落款时 却惦记着你，你隐藏在窑烧里 千年的秘密，极细腻犹如绣花针落地，帘外芭蕉惹骤雨 门环惹铜绿，而我路过那江南小镇 惹了你，在泼墨山水画里 你从墨色深处被隐去，天青色等烟雨 而我在等你，炊烟袅袅升起 隔江千万里，在瓶底书汉隶 仿前朝的飘逸，就当我为遇见你伏笔，天青色等烟雨 而我在等你，月色被打捞起 晕开了结局，如传世的青花瓷 自顾自美丽 你眼带笑意，天青色等烟雨 而我在等你，炊烟袅袅升起 隔江千万里，在瓶底书汉隶 仿前朝的飘逸，就当我为遇见你伏笔，天青色等烟雨 而我在等你，月色被打捞起 晕开了结局，如传世的青花瓷 自顾自美丽 你眼带笑意', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (77, '77', '04', '阳光宅男', '周杰伦', '方文山', '周杰伦', '流行摇滚/电子 (Pop Rock/Electronic)', '鼓励宅男走出家门，节奏轻快，电子元素突出', '八', '2007-11-01', '我很忙', '钥匙挂腰带　皮夹插后面口袋　，黑框的眼镜有几千度来海边穿西装裤，他不在乎　我却想哭　有点无助　，他的样子像刚出土的文物，他烤肉竟然会　自带水壶　，写信时用浆糊　走起路一不注意就撞树，我不想输　就算辛苦　，我也要等　我也不能让你再走寻常路，我决定插手你的人生　，当你的时尚顾问　别说你不能，让我们乘着阳光　海上冲浪　吸引她目光，不要怕露出胸膛　流一点汗　你成了型男，让我们乘着阳光　看着远方　别当路人甲，让美女缺氧　靠在你肩膀　我微笑在你旁边撑伞，喔对了对女生　用心疼　约会要等　，讲笑话不能闷　别太冷　像我一样就刚好，对爱的人　接吻要深　，拥抱要真　来电显示给个甜蜜的昵称，穿着要个性　这只是刚刚入门　，接下来你还要会弹琴会写歌会双截棍，头脑清楚　不能迷糊　，我要将你彻底改造基因重组大变身', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (78, '78', '05', '蒲公英的约定', '周杰伦', '方文山', '林迈可', '校园民谣/抒情 (School Folk/Ballad)', '旋律清新，讲述童年约定的纯真爱情，是校园民谣的经典', '八', '2007-11-01', '我很忙', '小学篱芭旁的蒲公英，是记忆里有味道的风景，午睡操场传来蝉的声音，多少年后也还是很好听，将愿望折纸飞机寄成信，因为我们等不到那流星，认真投决定命运的硬币，却不知道到底能去哪里，一起长大的约定，那样清晰 打过勾的我相信，说好要一起旅行 是你如今 唯一坚持的任性，在走廊上罚站打手心，我们却注意窗边的蜻蜓，我去到哪里你都跟很紧，很多的梦在等待着进行，一起长大的约定 那样清晰 打过勾的我相信，说好要一起旅行 是你如今 唯一坚持的任性，一起长大的约定 那样真心 与你聊不完的曾经，而我已经分不清 你是友情还是错过的爱情', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (79, '79', '06', '无双', '周杰伦', '方文山', '钟兴民', '中国风/摇滚 (Chinese Style/Rock)', '以“无双”比喻独一无二的爱，编曲融合中国风与摇滚', '八', '2007-11-01', '我很忙', '苔藓绿了木屋，路深处 翠落的孟宗竹，乱石堆上有雾，这种隐居叫做江湖，箭矢漫天飞舞，竟然在城墙上遮蔽了日出，是谁 在哭，（冲 你懂 你懂 你匆匆，有多少的 蛮力就拉 多少的弓，听我说武功无法高过寺院的钟，禅定的风 静如水的松），我命格无双 一统江山，狂胜之中 我却黯然语带悲伤，（我一路安营扎下蓬 青铜刀锋，不轻易用 苍生为重），我命格无双 一统江山，破城之后 我却微笑决不恋战，我等待异族望天空 歃血为盟，我等效忠 浴火为龙，残缺的老茶壶，几里外 马蹄上的尘土，升狼烟的城池，这种世道叫作乱世，那历史已模糊，刀上的锈却出土的很清楚，是我 在哭，（序你去 你去 你继续，我敲木鱼开始冥想这场战役，我攻城略地 想冷血 你需要勇气，挥剑离去 我削铁如泥，你去 你再去 你继续不敌我，致命的一击，远方的横笛 吹奏你战败的消息，保持着杀气 想赢的情绪，看我君临天下的驾驭），我命格无双 一统江山，狂胜之中 我却黯然语带悲伤，（我一路安营扎下篷 青铜刀锋，不轻易用 苍生为重），我命格无双 一统江山，破城之后 我却微笑决不恋战，（我等待异族望天空 歃血为盟，我等效忠 浴火为龙），命格无双 一统江山，狂胜之中 我却黯然语带悲伤，我命格无双 一统江山，破城之后 我却微笑决不恋战，（我等待异族望天空 歃血为盟，我等效忠 浴火为龙）', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (80, '80', '07', '我不配（距离）', '周杰伦', '方文山', '林迈可', '抒情流行 (Ballad Pop)', '情感真挚，旋律流畅，讲述因身份差距而无法相守的爱情', '八', '2007-11-01', '我很忙', '这街上太拥挤　太多人有秘密　，玻璃上有雾气在被隐藏起过去，你脸上的情绪　在还原那场雨　，这巷弄太过弯曲走不回故事里，这日子不再绿　又斑驳了几句　，剩下搬空回忆的我在大房子里，电影院的座椅　隔遥远的距离　，感情没有对手戏你跟自己下棋，还来不及仔仔细细写下你的关于，描述我如何爱你　你却微笑的离我而去，这感觉　已经不对　我努力在挽回，一些些　应该体贴的感觉　我没给，你嘟嘴　许的愿望很卑微　在妥协，是我忽略　你不过要人陪，这感觉　已经不对　我最后才了解，一页页　不忍翻阅的情节　你好累，你默背　为我掉过几次泪　多憔悴，而我心碎你受罪　你的美　我不配，这街上太拥挤　太多人有秘密　，玻璃上有雾气在被隐藏起过去，你脸上的情绪　在还原那场雨　，这巷弄太过弯曲走不回故事里，这日子不再绿　又斑驳了几句　，剩下搬空回忆的我在大房子里，电影院的座椅　隔遥远的距离　，感情没有对手戏你跟自己下棋，还来不及仔仔细细写下你的关于，描述我如何爱你　你却微笑的离我而去，这感觉　已经不对　我努力在挽回，一些些　应该体贴的感觉　我没给，你嘟嘴　许的愿望很卑微　在妥协，是我忽略　你不过要人陪，这感觉　已经不对　我最后才了解，一页页　不忍翻阅的情节　你好累，你默背　为我掉过几次泪　多憔悴，而我心碎你受罪　你的美　我不配', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (81, '81', '08', '扯', '周杰伦', '方文山', '林迈可', '流行摇滚 (Pop Rock)（与杨瑞代合唱）', '探讨现代人际关系的疏离，编曲直接，情绪外放', '八', '2007-11-01', '我很忙', '喔 在小朋友你这是 你这是玩些什么东西啊？，扯铃啊，扯铃！？ 怎么声音好像不大对啊？，什么声音？，我说你讲话的声音啊！，哈哈哈哈！，天气　冷的让人生闷气，火气　我沮丧的很生气，空气　太糟需要有氧气，太多假义气一想就气，敲门　敲敲门　基本礼貌叩要先问，离开也不随手关灯　生活习惯真有够混，敲门　敲敲门　简单动作叩也不等，你看来虽不像坏蛋　但做事做人却很蠢，你像一团沼气　影响我的士气　，损我的英气又那么神气，说话的语气　败坏了风气　，我不想为你为你白花了力气，那么会扯去扯铃　扯多你就会上瘾，扯你最善变的表情　我的解释请你务必要听，那么会扯去扯铃　却扯不出个命运，扯你最善变的表情　嘿你这样说我有一点伤心，不停犯错　不停推拖，养了一堆借口　等它成熟，前一秒说是朋友　后一秒诬赖我，别再跟我哈啦　我不是个傻瓜，说谎就要付出代价　是应有的惩罚，别再跟我哈啦　你被当成笑话，自己造成的那尴尬　我也没有办法', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (82, '82', '09', '甜甜的', '周杰伦', '方文山', '林迈可', '流行/小品 (Pop/Ditty)', '旋律轻快甜蜜，充满幸福感，是爱情小品的代表作', '八', '2007-11-01', '我很忙', '我轻轻地尝一口 你说的爱我，还在回味你给过的温柔，我轻轻地尝一口 这香浓的诱惑，我喜欢的样子你都有，你爱过头 竟然答应我，要给我蜂蜜口味的生活，加一颗奶球 我搅拌害羞，将甜度调高后再牵手，你的爱太多 想随身带走，想你的时候 就吃上一口，我温热着 被呵护的感受，却又担心降温了要求，我尝着你话里面的奶油溜啊溜，听过的每句话都很可口呦啊呦，那些多余的画面全被跳过，你的眼中只有我，我轻轻地尝一口 你说的爱我，还在回味你给过的温柔，我轻轻地尝一口 这香浓的诱惑，我喜欢的样子你都有，我轻轻地尝一口 你说的爱我，舍不得吃会微笑的糖果，我轻轻地尝一口 份量虽然不多，却将你的爱完全吸收，我微笑着 让香味停留，缘分走到这也赖着不走，像夹心饼干 中间有甜头，继续下去不需要理由，我尝着你话里面的奶油溜啊溜，听过的每句话都很可口呦啊呦，那些多余的画面全被跳过，你的眼中只有我，我轻轻地尝一口 你说的爱我，还在回味你给过的温柔，我轻轻地尝一口 这香浓的诱惑，我喜欢的样子你都有，我轻轻地尝一口 你说的爱我，舍不得吃会微笑的糖果，我轻轻地尝一口 份量虽然不多，却将你的爱完全吸收，我轻轻地尝一口 你说的爱我，还在回味你给过的温柔，我轻轻地尝一口 味道香浓的说，我喜欢的样子你都有，我轻轻地尝一口 你说的爱我，舍不得吃会微笑的糖果，我轻轻地尝一口 份量虽然不多，却将你的爱完全吸收', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (83, '83', '10', '最长的电影', '周杰伦', '周杰伦', '钟兴民', '抒情流行 (Ballad Pop)', '以电影比喻爱情，旋律层层递进，情感饱满，是经典的告别情歌', '八', '2007-11-01', '我很忙', '我们的开始　是很长的电影，放映了三年　我票都还留着，冰上的芭蕾　脑海中还在旋转，望着你　慢慢忘记你，朦胧的时间　我们溜了多远，冰刀划的圈　圈起了谁改变，如果再重来　会不会稍嫌狼狈，爱是不是不开口才珍贵，再给我两分钟　让我把记忆结成冰，别融化了眼泪　你妆都花了 要我怎么记得，记得你要我忘了吧　记得你叫我忘了吧，你说你会哭　不是因为在乎，朦胧的时间　我们溜了多远，冰刀划的圈　圈起了谁改变，如果再重来　会不会稍嫌狼狈，爱是不是不开口才珍贵，再给我两分钟　让我把记忆结成冰，别融化了眼泪　你妆都花了 要我怎么记得，记得你叫我忘了吧　记得你叫我忘了吧，你说你会哭　不是因为在乎，再给我两分钟　让我把记忆结成冰，别融化了眼泪　你妆都花了 要我怎么记得，记得你叫我忘了吧　记得你叫我忘了吧，你说你会哭　不是因为在乎', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (84, '84', '1', '龙战骑士', '周杰伦', '方文山', '钟兴民', '史诗摇滚/电子 (Epic Rock/Electronic)', '为游戏创作，编曲宏大，融合电子与摇滚，充满英雄气概', '九', '2008-10-14', '魔杰座', '放手一搏令谁都惭愧 迎着风极速在超越，那守门之兽展翼将飞 它们却没看过蝴蝶，不懂什么 叫有花香的季节 什么叫绿草如茵的旷野，所有关于我的传说 全都不对，全部是纸屑 全部要改写，对敌人谦卑 抱歉 我不会 而远方龙战于野，咆哮声不自觉 横越过了几条街，我坚决 冲破这一场浩劫，这世界谁被狩猎，谁淌血我却只为，拯救你的无邪，城墙上我在等魔坠，火焰吞噬无名碑，摧毁却无法击溃 我要爱上谁，废墟怎么被飞雪了解 只能滋长出羊齿蕨，那些仇恨已形成堡垒 我又该怎么去化解，低吼威胁 那些龙形的傀儡 它们发不出的音叫心碎，惊觉你啜泣声迂回 如此纯洁，以温柔削铁 以爱在谅解，在末日边陲 纯爱 被隔绝 我在危城的交界，目睹你的一切 锈迹斑斑的眼泪，我坚决 冲破这一场浩劫，这世界谁被狩猎，谁淌血我却只为，拯救你的无邪，城墙上我在等魔坠，火焰吞噬无名碑，摧毁却无法击溃 我要爱上谁，我坚决 冲破这一场浩劫，这世界谁被狩猎，摧毁却无法击溃 我要爱上谁', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (85, '85', '2', '给我一首歌的时间', '周杰伦', '周杰伦', '林迈可', '流行摇滚 (Pop Rock)', '旋律流畅，节奏轻快，表达想与爱人共度短暂时光的愿望', '九', '2008-10-14', '魔杰座', '雨淋湿了天空 毁的很讲究，你说你不懂 为何在这时牵手，我晒干了沉默 悔的很冲动，就算这是做错 也只是怕错过，在一起叫梦 分开了叫痛，是不是说 没有做完的梦最痛，迷路的后果 我能承受，这最后的出口在爱过了才有，能不能给我一首歌的时间，紧紧的把那拥抱变成永远，在我的怀里你不用害怕失眠，哦 如果你想忘记我也能失忆，能不能给我一首歌的时间，把故事听到最后才说再见，你送我的眼泪 让它留在雨天，哦 越过你划的线我定了勇气 的终点，雨淋湿了天空 毁的很讲究，你说你不懂我为何在这时牵手，我晒干了沉默 悔的很冲动，就算这是做错 也只是怕错过，在一起叫梦 分开了叫痛，是不是说 没有做完的梦最痛，迷路的后果 我能承受，这最后的出口在爱过了才有，能不能给我一首歌的时间，紧紧的把那拥抱变成永远，在我的怀里你不用害怕失眠，哦 如果你想忘记我也能失忆，能不能给我一首歌的时间，把故事听到最后才说再见，你送我的眼泪 让它留在雨天，哦 越过你划的线我定了勇气 的终点，哦 你说我不该不该 不该在这时候说了我爱你，要怎么证明我没有说谎的力气，哦 请告诉我 暂停算不算放弃，我只有一天的回忆，能不能给我一首歌的时间，紧紧的把那拥抱变成永远，在我的怀里你不用害怕失眠，哦 如果你想忘记我也能失忆，能不能给我一首歌的时间，把故事听到最后才说再见，你送我的眼泪 让它留在雨天，哦 越过你划的线我定了勇气 的终点，(你说我不该不该 不该在这时候说了爱你，要怎么证明我没力气 告诉我暂停算不算放弃，我说我不该不该 不该在这时才说爱你，要怎么证明我没力气 我只有一天的回忆)', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (86, '86', '3', '蛇舞', '周杰伦', '黄俊郎', '黄雨勋', '世界音乐/电子 (World Music/Electronic)', '灵感来自印度蛇舞，运用异域音阶和电子节拍，风格独特', '九', '2008-10-14', '魔杰座', '尼罗河悄悄漫过纸莎草，蜿蜒像一袭不带感情的纱袍，而你穿上后转身为我舞蹈，为寂寥的大地舞一场惊叹号，黄昏燃烧 金字塔上的 云角，人面狮身下的影子 在预兆，石阶上焚着油膏 在我国度里，堆积了 几个世纪的尘嚣，在羊皮卷角 古老的明了，谁都逃不掉 天平上的烦恼，你微微的笑 赤足又扭腰，朝着命运凿出一道 美艳的符号，来找我 找不到我 你那迷路的眼眸 (那迷路的眼眸 找不到我)，跟着我 被我诱惑 众神都已着了魔 (众神都着了魔 被我诱惑)，说爱我 爱不爱我 你那王者的沉默 (那王者的沉默 爱不爱我)，看着我 被我诱惑 你的灵魂属于我 (你的灵魂属于我 被我诱惑)', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (87, '87', '4', '花海', '周杰伦', '古小力、黄凌嘉', '黄雨勋', 'J-Pop/抒情摇滚 (J-Pop/Ballad Rock)', '旋律带有明显的日本流行音乐（J-Pop）风格，情感澎湃', '九', '2008-10-14', '魔杰座', '静止了 所有的花开，遥远了 清晰了爱，天郁闷 爱却很喜欢，那时候 我不懂 这叫爱，你喜欢 站在那窗台，你好久 都没再来，彩色的 时间染上空白，是你流的泪晕开，不要你离开 距离隔不开，思念变成海 在窗外进不来，原谅说太快 爱成了阻碍，手中的风筝放太快 回不来，不要你离开 回忆划不开，欠你的宠爱 我在等待重来，天空仍灿烂 它爱着大海，情歌被打败 爱已不存在', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (88, '88', '5', '魔术先生', '周杰伦', '方文山', '钟兴民', '放克/嘻哈 (Funk/Hip-Hop)', '节奏感强，带有放克的律动，歌词充满魔术般的奇幻想象', '九', '2008-10-14', '魔杰座', '（巨炮独白）杰伦 你这音乐让我想要变魔术的感觉，我刚好 我跟你讲我学了一个超厉害的魔术，要不要学学看，真的 有没有在听那你，有 有啊 我跟你讲 很简单，左手轻轻握住你的鼻子，然后右手 很简单 穿过你的左手，我刚才说的是可能要音乐来会比较舒服一点，慢一点慢一点 这时候找到一面镜子抬头一看，你就变成了一只大象，你举手 你抬头 你说选我选我，手上锁 又挣脱 你仍一脸迷惑，吹个风 手一松 那硬币竟失踪，一鞠躬 那掌声 拍的凶，手交错 轻轻碰 戒指换手移动，给观众 一个梦 讶异中有笑容，手穿海报却不拿汉堡 反而拿出牛仔帽，你永远都猜不着，每当我在台上演出人体漂浮，你就在台下偷偷吃我的泡芙，等待白鸽飞出 再将爱说清楚，啊~~ 读你读你读 心想啥事 用古典迫牌方式，我手法精致艾尔姆支雷一百分的姿势，谁说恋爱别找魔术师 我不需要解释，所以他小丑我是大师，你举手 你抬头 你说选我选我，我将牌 换颜色 变出你的选择，将自由 的女神 变不见 不稀奇，一〇一 变不见 才惊喜，手摊开 帽子里 总能空手出牌，不管切 多少牌 总能切的回来，手穿海报却不拿汉堡 反而拿出牛仔帽，你永远都猜不着，不要问我到底什么才是真的，我变给你看的感情才是真的，因为无时无刻 我只想你快乐，啊~~~ 读你读你读 心想啥事 用古典迫牌方式，我手法精致艾尔姆支雷一百分的姿势，谁说恋爱别找魔术师 我不需要解释，所以他小丑我是大师，读你读你读 心想啥事 用古典迫牌方式，我手法精致艾尔姆支雷一百分的姿势，谁说恋爱别找魔术师 我不需要解释，所以不用麻烦了 不用麻烦了 不用麻烦了，读你读你读 心想啥事 用古典迫牌方式，我手法精致艾尔姆支雷一百分的姿势，谁说恋爱别找魔术师 我不需要解释，所以他小丑我是大师', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (89, '89', '6', '说好的幸福呢', '周杰伦', '方文山', '钟兴民', '抒情流行 (Ballad Pop)', '旋律悲伤，情感内敛，质问逝去的爱情，是经典的失恋情歌', '九', '2008-10-14', '魔杰座', '你的回话凌乱着 在这个时刻，我想起喷泉旁的白鸽 甜蜜散落了，情绪莫名的拉扯 我还爱你呢，而你断断续续唱着歌 假装没事了，时间过了 走了 爱情面临选择，你冷了 倦了 我哭了，离开时的不快乐 你用卡片纸写着，有些爱只给到这 真的懂了，怎么了 你累了 说好的 幸福呢，我懂了 不说了 爱淡了 梦远了，开心与不开心 一一细数着 你在不舍，那些爱过的感觉都太深刻 我都还记得，你不等了 说好的 幸福呢，我错了 泪干了 放手了 后悔了，只是回忆的音乐盒还旋转着 要怎么停呢，怎么了 你累了 说好的 幸福呢，我懂了 不说了 爱淡了 梦远了 我都还记得，你不等了 说好的 幸福呢，我错了 泪干了 放手了 后悔了，只是回忆的音乐盒还旋转着 要怎么停呢', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (90, '90', '7', '兰亭序', '周杰伦', '方文山', '钟兴民', '中国风 (Chinese Style)', '以书法名作《兰亭序》为灵感，歌词文雅，旋律优美，展现书法与爱情的结合', '九', '2008-10-14', '魔杰座', '兰亭临帖 行书如行云流水，月下门推 心细如你脚步碎，忙不迭 千年碑易拓却难拓你的美，真迹绝 真心能给谁，牧笛横吹 黄酒小菜又几碟，夕阳余晖 如你的羞怯似醉，摹本易写 而墨香不退与你共留余味，一行朱砂 到底圈了谁，无关风月 我题序等你回，悬笔一绝 那岸边浪千叠，情字何解 怎落笔都不对，而我独缺 你一生的了解，(无关风月 我题序等你回，悬笔一绝 那岸边浪千迭，情字何解 怎落笔都不对，而我独缺 你一生的了解，无关风月 我题序等你回，悬笔一绝 那岸边浪千迭，情字何解 怎落笔都不对，独缺 你一生了解)，弹指岁月 倾城顷刻间烟灭，青石板街 回眸一笑你婉约，恨了没 你摇头轻叹谁让你蹙着眉，而深闺 徒留胭脂味，人雁南飞 转身一瞥你噙泪，掬一把月 手揽回忆怎么睡，又怎么会 心事密缝绣花鞋针针怨怼，若花怨蝶 你会怨着谁，无关风月 我题序等你回，悬笔一绝 那岸边浪千迭，情字何解 怎落笔都不对，而我独缺 你一生的了解，无关风月 我题序等你回，手书无愧 无惧人间是非，雨打蕉叶 又潇潇了几夜，我等春雷 来提醒你爱谁', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (91, '91', '8', '流浪诗人', '周杰伦', '方文山', '蔡科俊', '流行/民谣 (Pop/Folk)（与杨瑞代合唱）', '旋律简单，带有流浪的漂泊感，是轻松的小品', '九', '2008-10-14', '魔杰座', '海边篱笆 咿呀咿呀，风一直刮 我像枝桠，帮你过滤了风沙，墙上的时差 滴答滴答，还在牵挂，我们都偏爱她的长发，Gary)，你坐火车 忾恰忾恰，回来我这 就像燕子，下雨躲屋檐怕冷，写一封书信汐沙汐沙，写谁的名，你讲她的故事给我听，合)，又想你一次 一次，要怎样才能跟你认识，我真的不该不该，简单一句爱说不出来，Jay)，经过山丘 嗨呦嗨呦，汗一直流 行李不多，但思念一定带走，Gary)，我们走同一条路，哒啰哒啰 要走到哪，随风流浪去玩耍，合)，等发芽 树有树枝，等写字 我有地址，等它满 茶有茶叶，等消息 我们都在想她，春天 花有花蕊，等展翅 田有蜻蜓，等结局 流浪诗人的回忆，合)，又想你一次 一次，要怎样才能跟你认识，我真的不该不该，简单一句爱说不出来，Rap)，海边篱笆 咿呀咿呀，风一直刮 我像枝桠，帮你过滤风沙，墙上的时差 滴答滴答，还在牵挂 我爱她的长发，你坐火车 忾恰忾恰，回来我这 就像燕子怕冷，写一封书信 沙汐沙汐，写谁的名 你讲给我听，合)，远方回音，我们迎风边走边弹琴，我们的人生，因为她开始认真，她的眼睛，像是一幅翠绿的风景，我们的感情 越唱放越深', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (92, '92', '9', '时光机', '周杰伦', '方文山', '黄雨勋', '流行摇滚 (Pop Rock)', '节奏轻快，主题关于穿越时空，充满想象力', '九', '2008-10-14', '魔杰座', '墙角迎风的雏菊 茉莉花开的香气 闭上眼回到过去，划分界限的桌椅 下课却靠在一起 我就是离不开你，一路乘着溜滑梯 我们说好走到底 以为从此就分离，用黑板上的日期 倒数找你，慢慢清晰 原来思念你 是加了糖的消息，我用铅笔 画的很仔细 素描那年 天气，蝉鸣的夏季 我想遇见你，那童年的希望是一台 时光机，我可以一路开心到底 都不换气，戴竹蜻蜓 穿过那森林，打开了任意门找到你 一起旅行，那童年的希望是一台 时光机，你我翻滚过的榻榻米 味道熟悉，所有回忆 在小叮当口袋里，一起荡秋千的默契 在风中持续着甜蜜，有些话总来不及 一直都放在心底 想要将你看仔细，但错身而过的你 已经离去，慢慢清晰 原来思念你 是加了糖的消息，我用铅笔 画的很仔细 素描那年 天气，蝉鸣的夏季 我想遇见你，那童年的希望是一台 时光机，我可以一路开心到底 都不换气，戴竹蜻蜓 穿过那森林，打开了任意门找到你 一起旅行，那童年的希望是一台 时光机，你我翻滚过的榻榻米 味道熟悉，所有回忆 在小叮当口袋里，一起荡秋千的默契 在风中持续着甜蜜，那童年的希望是一台 时光机，我可以一路开心到底 都不换气，戴竹蜻蜓 穿过那森林，打开了任意门找到你 一起旅行，那童年的希望是一台 时光机，你我翻滚过的榻榻米 味道熟悉，所有回忆 在小叮当口袋里，一起荡秋千的默契 在风中持续着甜蜜，持续着甜蜜……', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (93, '93', '10', '乔克叔叔', '周杰伦', '黄俊郎', '黄雨勋', '小丑叙事曲/另类摇滚 (Clown Ballad/Alternative Rock)', '以小丑（Joker）视角讲述内心孤独，编曲怪诞而悲伤', '九', '2008-10-14', '魔杰座', '亲爱的 别吓到闭上了眼睛，小丑把戏 不是大家都可以，夸张眼影 蓝色忧伤的泪滴，丢丢刀 喷喷火 踩高跷吹笛，跌倒失手烧到眉毛我故意，哈哈你笑的开心我可是在玩命，扑克牌里 我的肖像才一两张，你看你看我的重要性，彩色的 大卷发 红鼻子 最滑稽 的步法，这样的快乐你学会了吗 (会了吗)，用笨拙 又惊险 的杂耍 继续对 你装傻，所有的悲伤通通忘了吧 (忘了吧)，听我说 拿出你的钞票 笑平常买不到，先生小姐们赶快来 赶快来，再慢就看不到 座位没剩多少，还能跟乔克叔叔拍 一张照，我只是 卑微的小丑 翻几个跟斗，就等你拍一拍手，人群散了后 夜色多朦胧，月光也会跟着我，我不是 孤独的小丑 你笑了之后，不需要记得我，灯熄的时候 满天的星空，最明亮的是寂寞，下着雨 我躲在 面具里 偷偷地 在哭泣，因为看了不能说的秘密，魔术师 我恨你 抢走我 的生意 别忘记，蝙蝠侠靠我才票房冠军，听我说 拿出你的钞票 笑平常买不到，先生小姐们赶快来 赶快来，再慢就看不到 座位没剩多少，还能跟乔克叔叔拍 一张照，我只是 卑微的小丑 翻几个跟斗，就等你拍一拍手，人群散了后 夜色多朦胧，月光也会跟着我，我不是 孤独的小丑 你笑了之后，不需要记得我，灯熄的时候 满天的星空，最明亮的是寂寞，我只是 卑微的小丑 翻几个跟斗，就等你拍一拍手，人群散了后 夜色多朦胧，月光也会跟着我，我不是 孤独的小丑 你笑了之后，不需要记得我，灯熄的时候 满天的星空，最明亮的是寂寞', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (94, '94', '11', '稻香', '周杰伦', '周杰伦', '黄雨勋', '励志流行/乡村 (Inspirational Pop/Country)', '鼓励人们回归简单，珍惜幸福，加入蟋蟀、青蛙等自然音效，风格清新', '九', '2008-10-14', '魔杰座', '对这个世界 如果你有太多的抱怨，跌倒了 就不敢继续往前走，为什么 人要这么的脆弱堕落，请你打开电视看看，多少人 为生命在勇敢的走下去，我们是不是该知足，珍惜一切 就算没有拥有，还记得 你说家是唯一的城堡，随着稻香河流继续奔跑，微微笑 小时候的梦我知道，不要哭 让萤火虫带着你逃跑，乡间的歌谣永远的依靠，回家吧 回到最初的美好，不要这么容易 就想放弃，就像我说的，追不到的梦想 换个梦不就得了，为自己的人生鲜艳上色，先把爱涂上喜欢的颜色，笑一个吧 功成名就不是目的，让自己快乐快乐 这才叫做意义，童年的纸飞机现在终于飞回我手里，所谓的那快乐，赤脚在田里追蜻蜓 追到累了，偷摘水果被蜜蜂给 叮到怕了，谁在偷笑呢，我靠着稻草人 吹着风 唱着歌 睡着了，哦哦 午后吉他在虫鸣中更清脆，哦哦 阳光洒在路上就不怕心碎，珍惜一切 就算没有拥有，还记得 你说家是唯一的城堡，随着稻香河流继续奔跑，微微笑 小时候的梦我知道，不要哭 让萤火虫带着你逃跑，乡间的歌谣永远的依靠，回家吧 回到最初的美好，还记得 你说家是唯一的城堡，随着稻香河流继续奔跑，微微笑 小时候的梦我知道，不要哭 让萤火虫带着你逃跑，乡间的歌谣永远的依靠，回家吧 回到最初的美好', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (95, '95', '01', '跨时代', '周杰伦', '黄俊郎', '黄雨勋', '电子/古典说唱 (Electronic/Orchestral Rap)', '探讨艺术的永恒与时代的更迭，编曲复杂，融合古典与现代电子', '十', '2010-05-18', '跨时代', '钟逆时针而绕 恶物狰狞地倾巢，我谦卑安静地于城堡下的晚祷，压抑远古流窜的蛮荒暗号，而管风琴键高傲地说那只是在徒劳，嗷嗷嗷嗷嗷 我的乐器在环绕，时代无法淘汰我霸气的皇朝，你无法预言因为我越险翅越艳，没有句点跨时代蔓延翼朝天，月下浮雕 魔鬼的浅笑，狼迎风嚎 蝠翔似黑潮，用孤独去调尊严的色调，我跨越过时代 如兽般的姿态，琴声唤起沉睡的血脉，不需要被崇拜 如兽般的悲哀，只为永恒的乐曲存在 醒过来，钟逆时针而绕 恶物狰狞地倾巢，我谦卑安静地于城堡下的晚祷，压抑远古流窜的蛮荒暗号，而管风琴键高傲地说那只是在徒劳，嗷嗷嗷嗷嗷 我的乐器在环绕，时代无法淘汰我霸气，你无法预言因为我越险翅越艳，没有句点跨时代蔓延翼朝天，月下浮雕 魔鬼的浅笑，狼迎风嚎 蝠翔似黑潮，用孤独去调尊严的色调，我跨越过时代 如兽般的姿态，琴声唤起沉睡的血脉，不需要被崇拜 如兽般的悲哀，只为永恒的乐曲存在 醒过来，我不需要被崇拜 我不需要被崇拜，我跨越过时代 如兽般的姿态，琴声唤起沉睡的血脉，不需要被崇拜 如兽般的悲哀，只为永恒的乐曲存在 醒过来', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (96, '96', '02', '说了再见', '周杰伦', '古小力、黄淩嘉', '钟兴民', '抒情流行 (Ballad Pop)', '表达对逝去爱情的无奈与告别，旋律悲伤', '十', '2010-05-18', '跨时代', '天亮了 雨下了 你走了，清楚了 我爱的 遗失了，落叶飘在湖面上睡著了，想要放 放不掉 泪在飘，你看看 你看看不到，我假装过去不重要 却发现自己办不到，说了再见 才发现再也见不到，我不能 就这样 失去你 的微笑，口红待在桌脚 而你我找不到，若角色对调 你说好不好，说了再见 才发现再也见不到，能不能 就这样 忍著痛 泪不掉，说好陪我到老 永恒往哪里找，再次拥抱 一分一秒 都好，Repeat *，你的笑　你的好　脑海里　一直在绕，我的手　忘不了　你手的温度，心 碎了一地　捡不回从前的心跳　，身陷过去我无力逃跑，说再见　才发现再也见不到，能不能 就这样 忍着痛 泪不掉，说好陪我到老　永恒往哪里找，再次拥抱 一分一秒 都好', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (97, '97', '03', '烟花易冷', '周杰伦', '方文山', '黄雨勋', '中国风 (Chinese Style)', '以洛阳古城为背景，旋律凄美，充满历史沧桑感和佛学意境', '十', '2010-05-18', '跨时代', '繁华声 遁入空门 折煞了世人，梦偏冷 辗转一生 情债又几本，如你默认 生死枯等，枯等一圈 又一圈的年轮，浮屠塔 断了几层 断了谁的魂，痛直奔 一盏残灯 倾塌的山门，容我再等 历史转身，等酒香醇 等你弹 一曲古筝，雨纷纷 旧故里草木深，我听闻 你始终一个人，斑驳的城门 盘踞着老树根，石板上 回荡的是 再等，雨纷纷 旧故里草木深，我听闻 你仍守着孤城，城郊牧笛声 落在那座野村，缘份落地生根是 我们，听青春 迎来笑声 羡煞许多人，那史册 温柔不肯 下笔都太狠，烟花易冷 人事易分，而你在问我是否还 认真，千年后 累世情深 还有谁在等，而青史 岂能不真 魏书洛阳城，如你在跟 前世过门，跟着红尘 跟随我 浪迹一生，Repeat *，RAP:，雨纷纷 旧故里草木深，我听闻 你始终一个人，斑驳的城门 盘踞着老树根，石板上回荡的是再等，雨纷纷 雨纷纷 旧故里草木深，我听闻 我听闻 你仍守著孤城，城郊牧笛声 落在那座野村，缘份落地生根是 我们，缘份落地生根是 我们，伽蓝寺听雨声盼 永恒', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (98, '98', '04', '免费教学录影带', '周杰伦', '黄俊郎', '蔡科俊', '嘻哈/实验 (Hip-Hop/Experimental)', '风格前卫，采样独特，带有实验性质', '十', '2010-05-18', '跨时代', '如果你 想要变成一个Rocker，你就必须要先有一把Guitar，刷和弦的时候尽量不用Pick，啊看起来样子会比较随性，就算你弹错了大家会以为，你是故意（哒哒啦哒），你是不是 啊哈 感觉到了，我的和弦 啊哈 在重复著，哎呦不错代表你耳朵没有聋，Blues就是在重复这几个和弦，摇滚的节奏在右手 灵魂在左手，心就是宇宙 我弹的叫自由（哒哒啦哒），*听我的Blues（Blues）要学会尖叫（尖叫），比一个Peace（Peace）是为了拍照（拍照），丢一块Ice（Ice） 叫他不要吵（不要吵），摇滚不是为了把妹是为了梦想，当然魅力太强被别人爱上我没办法，啊 断了，没关系再买一把吉他（吉他），没有钱就借别人的吧（的吧），怎么会有人喜欢摔吉他（吉他），有种你就摔最贵的吉他（吉他），你要好好珍惜它 它才会对你说话，手在弹如果脚有点闲，再加点舞蹈就太完美了，举起你的单手给他个啵！，千万别在这时放个屁啵！〖这时候你可以放开Pick 啵!〗，OhOh美女在哪你就要看到哪里，你一定以为我接下来要唱副歌，OhOh还没 不急我先教你弹，再升一格 再升一格 最后退一格 啊，Repeat *，再来一次 如果你加几个音就变乡村风味，大家听久了都（咩）会很想喝牛奶，牛仔很忙没有空帮你挤牛奶（这是羊不是牛后）（是喔），不过不要笨到自己跑去挤牛奶（没有啦），因为临时要在路边找到一头牛真的很难（啦啦啦啦啦啦啦啦），副歌，听我的Blues（Blues）要学会尖叫（尖叫），比一个Peace（Peace）是为了拍照（拍照），丢一块Ice（Ice） 叫他不要吵（嘘），摇滚不是为了把妹是为了梦想，当然魅力太强被别人爱上我没办法，当然魅力太强被别人爱上我没办法，再来一次 最后一次 再补一次', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (99, '99', '05', '好久不见', '周杰伦', '周杰伦', '蔡庭贵', '流行/小品 (Pop/Ditty)', '旋律简单可爱，以台湾话（闽南语）演唱，表达亲切的问候', '十', '2010-05-18', '跨时代', '好久不见 你还好吗，你的小狗 长大了吗，我的围巾 还围着吗，我的相片 都丢了吧，我剪不到后面头发，这个借口还不错吧（哎呦不错），一把剪刀一堆废话，还不是想求求你回来吧，*别再一个人在生气，给他烦恼 给他操心，虽然不关我的事情，谁叫他是我的兄弟 耶，都这么久就算了吧，想想秋天就要过去 耶，冬天来临他会怕冷，你不回来难道要我抱他，这样好吗（台语），(麦搁一个人咧生气，乎伊烦恼 乎伊操心，虽然不关我的代志，谁叫他是我的兄弟 耶，拢这么久就唰唰去，想想秋天就马过去 耶，冬天来临他会怕冷，你不回来甘讲要我抱伊，按呢甘好 ），是我不好 我没有紧紧抱住你，你说泪留着很危险，如果等雨一起（等雨一起），流下不让同情发现，我对天空这个那个流星，大喊后会不会有奇迹，就算做朋友也没关系，为你改变了自己都不认识自己，不是我跑去了整形，只是我拿出真心，开一瓶这个那个香槟，去我的Mr.J餐厅，点蜡烛顺便吃个甜品，庆祝你打死不连络的毅力，冷战早已不流行，赶快回来到 我身边，Repeat *', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (100, '100', '06', '雨下一整晚', '周杰伦', '方文山', '钟兴民', '中国风 (Chinese Style)', '前半段现代抒情，后半段突然转入古代场景，实现“时空穿越”，编曲精妙', '十', '2010-05-18', '跨时代', '街灯下的橱窗 有一种落寞的温暖，吐气在玻璃上 画着你的模样，开著车漫无目的地转弯 不知要去哪个地方，闹区的电视墙 到底有谁在看，白杨木影子被拉长 像我对你的思念走不完，原来我从未习惯 你已不在我身旁，街道的铁门被拉上 只剩转角霓虹灯还在闪，这城市 的小巷 雨下一整晚，RAP，你撑把小纸伞 叹姻缘太婉转 唉~，雨落下雾茫茫 问天涯在何方 喔喔~，啊~午夜里 笛声残 偷偷透 透过窗，烛台前 我嘛还在想，啊~小舢板 划呀划　小纸伞 遮雨也遮月光，白杨木影子被拉长 像我对你的思念走不完，原来我从未习惯 你已不在我身旁，街道的铁门被拉上 只剩转角霓虹灯还在闪，这城市 的小巷 雨下一整晚　Repeat *', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (101, '101', '07', '嘻哈空姐', '周杰伦', '方文山', '林迈可', '嘻哈/电子 (Hip-Hop/Electronic)', '节奏轻快，主题轻松，展现空姐的酷炫一面', '十', '2010-05-18', '跨时代', '起落架离开地上 空姐亲切的讲，请我打开遮阳板，将安全带系上，接著问是否用餐 需不需要毛毯，而我沉睡在客舱 梦在我正上方，她没有狐狸脸蛋 竟然可以这么耐看，发香 爱爱爱爱上 醒来在飞机上 座位还在晃，一半 她放慢脚步想我拼命跑想我去追上，我知道 因为 我想，*她问我 Coffee tea or me（她问我她问我 Coffee tea or me），我深深倒抽一口气（我深深我深深倒抽一口气），她身体摆动的频率（她身体她身体摆动的频率），让我几乎喘不过气（让我几让我几乎喘不过气），我点咖啡不加糖 正对着她品尝，那免税品的包装 诱人像她一样，我决定边走边唱 她的眼神渴望，充满暗示与想像 给予人一种挑战，梦游的初步阶段 我脑海播放一段，形状 幻幻幻幻想 醒来在走道上 随节奏在晃，闪亮 她一路翘臀推著那餐车性感的模样，短裙的 弧度 漂亮，Repeat *，她问我 Coffee tea or me（她问我她问我 Coffee tea or me），我张大眼睛在怀疑（我深深我深深倒抽一口气），厚嘴唇很有吸引力（她身体她身体摆动的频率），我会不会瞬间麻痹（让我几让我几乎喘不过气）', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (102, '102', '08', '我落泪?情绪零碎', '周杰伦', '方文山', '钟兴民', '抒情流行 (Ballad Pop)', '情感细腻，旋律悲伤，描绘失恋后的混乱心绪', '十', '2010-05-18', '跨时代', '地上 断了翅的蝶，雾散之后的 满月，原来爱 跟心碎，都可以很 细节，听夜风绕过 几条街，秋天瘦了满地 的落叶，于是又一整夜，感性的句子 都枯萎 凋谢，我不想再写 随手撕下这一页 哼 （这一页），原来诗跟离别 可以没有结尾（没有结尾），憔悴后悔等等 这些，于是我 把诗折叠，邮寄出感觉 夹一束白玫瑰，你将爱退回，我不落泪 忍住感觉，分手在起风 这个季节，哭久了会累 也只是别人的以为，冷的咖啡 我清醒着 一再续杯，我落泪 情绪零碎，你的世界 一幕幕纷飞，门外的蔷薇 带刺伤人的很直接，过去被翻阅 结局满天的 风雪，Repeat *', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (103, '103', '09', '爱的飞行日记', '周杰伦', '方文山', '蔡科俊', '流行/电子 (Pop/Electronic)（与杨瑞代合唱）', '以飞行比喻爱情旅程，电子元素突出', '十', '2010-05-18', '跨时代', '赤道的边境万里无云天很晴，爱你的事情说了千遍有回音，岸边的丘陵崎岖不平浪入侵，我却很专心分辨得出你的声音，用南极的冰将爱结晶我用心，永不融化的是爱你的这个决定，透明 坚硬，升空对抗重力反应，逐渐渺小的风景，景景景景景色分明，我加速引擎，抛开远方的黎明，剩速度回应 向银河逼近，我对着流星，祈祷时专心，为爱飞行，脱离地心引力的热情，找一颗星 只为了你命名，我用光年传递爱情，为爱飞行，脱离地心引力的热情，我在宇宙无重力的环境，为你降临，赤道的边境万里无云天很晴，爱你的事情说了千遍有回音，岸边的丘陵崎岖不平浪入侵，我却很专心分辨得出你的声音，用南极的冰将爱结晶我用心，永不融化的是爱你的这个决定，透明（透明） 坚硬（坚硬），升空对抗重力反应，逐渐渺小的风景，景景景景景色分明，我加速引擎 抛开远方的黎明，剩速度回应 向银河逼近，我对着流星 祈祷时专心，为爱飞行，脱离地心引力的热情，找一颗星 只为了你命名，我用光年传递爱情，为爱飞行，脱离地心引力的热情，我在宇宙无重力的环境，为你降临', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (104, '104', '10', '自导自演', '周杰伦', '周杰伦', '黄雨勋', '抒情流行 (Ballad Pop)', '旋律优美，表达在爱情中独自承受的无奈', '十', '2010-05-18', '跨时代', '巷口甩尾甩开了过去的熟悉，照后镜的你比脑海清晰，你我距离就像打滑和那漂移，差很远但看似很接近，车灯闪了一下代表我还在意，被我看见你上他的车这么不小心（不小心），喇叭按了二声代表我会离去，你放心我理解这游戏，呼啸而过的引擎声 是你最讨厌的旋律，穿梭在城市中 变成一首幻想曲，一边疯狂纪录 一边璀璨地忘记，（忘记忘记忘记忘记），你发脾气甩上车门香味留在这里，对不起要走可以关门别太大力，用点心 你说不是用来吃的点心，冰淇淋溶化了谎言在你身边的美丽，*没有了雨雨刷还是不停左右，就像回忆开始对我挥了挥手，仪表板转动在猜我会不会懂，速度再快也追不回承诺，车窗摇下听你听你完美借口　，音乐开大让我让我假装感动，贴心的你不用自导自演心痛，我看不懂我会更难过，Repeat ALL，Repeat *', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (105, '105', '11', '超人不会飞', '周杰伦', '周杰伦', '林迈可', '嘻哈/叙事说唱 (Hip-Hop/Narrative Rap)', '讲述成名背后的辛酸与压力，说唱真挚，充满自省', '十', '2010-05-18', '跨时代', '妈妈说很多事别太计较，只是使命感找到了我我睡不着，如果说骂人要有点技巧，我会加点旋律你会觉得 超屌，〖如果说骂人要有点技巧，我会加点旋律你会觉得 超好〗，我的枪不会装弹药（弹药），所以放心不会有人倒（人倒），我拍青蜂侠不需要替身，因为自信是我绘画的颜料，我做很多事背后的意义远比你们想像，拍个电视剧为了友情与十年前的梦想，收视率再高也难抗衡我的伟大理想，因为我的人生无需再多一笔那奖项，我不知道何时变成了社会的那榜样，被狗仔拍不能比中指要大器的模样（怎样），〖被狗仔拍要对着镜头要大器的模样（怎样）〗，我唱的歌词要有点文化 因为随时会被当教材，CNN能不能等英文好一点再访，时代杂志封面能不能重拍 随时随地注意形象，要控制饮食不然就跟杜莎夫人蜡像的我不像（本来就不像），好莱坞的中国戏院地上有很多手印脚印何时才能看见我的掌，喔如果超人会飞 那就让我在空中停一停歇，再次俯瞰这个世界 会让我觉得好一些，拯救地球好累 虽然有些疲惫但我还是会，不要问我哭过了没 因为超人不能流眼泪，唱歌要拿最佳男歌手 拍电影也不能只拿个最佳新人，你不参加颁奖典礼就是没礼貌 你去参加就是代表你很在乎，得奖时你感动落泪（落泪） 人家就会觉得你夸张做作（做作），你没表情别人就会说太嚣张 如果你天生这个表情 那些人甚至会怪你妈妈（妈妈），结果最后是别人在得奖 你也要给予充分的掌声与微笑，开的车不能太好 住的楼不能太高，我到底是一个创作歌手还是好人好事代表，专辑一出就必须是冠军 拍了电影就必须要大卖，只能说当超人真的好难，如果超人会飞（超人会飞） 那就让我在空中停一停歇（停一停歇），再次俯瞰这个世界 会让我觉得好一些，拯救地球好累（地球好累） 虽然有些疲惫但我还是会（我还是会），不要问我哭过了没 因为超人不能流眼泪', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (106, '106', '1', '惊叹号', '周杰伦', '方文山', '林迈可', '流行摇滚/舞曲 (Pop Rock/Dance)', '节奏强劲，充满能量，如同音乐的“惊叹号”', '十一', '2011-11-11', '惊叹号', '越山丘 过哑口 云端的空气稀薄，这街头 敌意多 烟硝弥漫不了我，空袭对我是种罗嗦，警报呢 是让你们有 时间走，哇 靠毅力极限燃烧，哇 靠斗志仰天咆啸，哇 靠自己创作跑道 靠！！！！！！！，靠 毅力极限燃烧，哇 靠斗志仰天咆啸，哇 靠高速奔向目标 靠！！！！！！！，顺向坡 从不走 逆着风清醒了我，我沉默 话不多 赢的时候才开口，势均力敌才叫战斗，希望呢 你们是像样 的对手，哇 靠毅力极限燃烧，哇 靠斗志仰天咆啸，哇 靠自己创作跑道 靠！！！！！！！，靠 毅力极限燃烧，哇 靠斗志仰天咆啸，哇 靠高速奔向目标 靠！！！！！！！，哇 靠毅力极限燃烧，哇 靠斗志仰天咆啸，哇 靠自己创作跑道 哇 靠，高楼的视野 不知名的街，霓虹侵略 庸俗了这一切，是与非 隔着路口对决，我主宰 我自己的世界，横着写 意气风发的谁，永不放弃 去超越 去粉碎 是非，哇 靠毅力极限燃烧，哇 靠斗志仰天咆啸，哇　靠自己创作跑道 靠！！！！！！！，靠 毅力极限燃烧，哇 靠斗志仰天咆啸，哇 靠高速奔向目标 靠！！！！！！！ 靠', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (107, '107', '2', '迷魂曲', '周杰伦', '方文山', '林迈可', '探戈/电子 (Tango/Electronic)', '融入阿根廷探戈节奏，营造神秘、诱惑的氛围', '十一', '2011-11-11', '惊叹号', '我用琴键移动 决定你一生的内容，黑帽戴上 穿着横条毛衣再配上手套，接着走在一遍雾里 我不是那佛莱迪，所以别怕 我偷偷摸摸走进你梦里，我用音乐这武器 进入你梦里 指导你演戏，　传来一声哎呦 睡了太久 睡了太熟，小心秘密 被我偷走 心事泄漏 全被我看透，不过请别 担心 我不是李奥纳多，不会一层又一层的把梦 偷偷盗走，我弹琴 设陷阱 向你 缓缓的逼近，你 的伤心 由 我决定，我弹琴 谈感情 让你 慢慢的上瘾，你 的爱情 已 经注定，我弹琴 设陷阱 向你 缓缓的逼近，你 的伤心 由 我决定，我弹琴 谈感情 让你 慢慢的上瘾，你 的爱情 已 经注定，这场赌局 请相信我你很难赢，场景 就像一场豪华的梦境，歌声魅影 你深深的被吸引，闭上眼睛 脑海风景 已经开始飞行，意志再再坚定 再多冷静 再多任性，你也无法 去抵抗 我所弹的 热情，跟着节奏 温柔 跟着我 让旋律自由，一遍又一遍的诱惑 爱上我 是种 生活，我用琴键移动 决定你一生的内容，我弹琴 设陷阱 向你 缓缓的逼近，你 的伤心 由 我决定，我弹琴 谈感情 让你 慢慢的上瘾，你 的爱情 已 经注定，我弹琴 设陷阱 向你 缓缓的逼近，你 的伤心 由 我决定，我弹琴 谈感情 让你 慢慢的上瘾，你 的爱情 已 经注定，我用琴键移动（你 的伤心 由 我决定），决定你一生的内容（你 的爱情 已 经注定），我用琴键移动（你 的伤心 由 我决定），决定你一生的内容（你 的爱情 已 经注定）', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (108, '108', '3', 'Mine Mine', '周杰伦', '周杰伦', '林迈可', '嘻哈/电子 (Hip-Hop/Electronic)', '节奏感强，带有挑衅意味', '十一', '2011-11-11', '惊叹号', '没有你的生活 我开始写小说，好多画面好多灵感 我要把稿费都给你，巷口不小心经过 你的车子依旧停在红线 帮你缴罚单，你叫我别管 我才想到我们已经分开，想起那一个夏天 那不是那不是那是冬天，想起你生气的脸 每天就像冬天 唉唉唉，你说那是爱爱爱，谁该坚强起来 月亮还是太阳 是谁遮了谁 是谁都会依赖，你说已分开 为什么还要帮你撑伞，Cuz baby you are mine mine(Mine)，Mine mine(Mine)，太快 就承认 我真的很想你，会不会没有男子气概 You say，Bye-bye(Bye )，Oh bye-bye(Bye )，拆开 我的心随你看 满满的都是爱，我的眼皮跳一下 代表你在想我，我的耳朵痒一下 代表你在讲我坏话，我没这么不好吧 不用跟朋友说吧，如果以后和好了 看到你朋友不是很尴尬，想起那一个夏天 那不是那不是那是冬天，想起你生气的脸 每天就像冬天 唉唉唉，你说那是爱爱爱，骗谁 我说的气话都收回，我写的小说根本是空白黑夜，你说既然已分开 为何还要帮你撑伞，唛唛 你唛搁唛搁偷偷离开，唛唛 你唛搁唛搁偷偷离开，唛惊 我不会放你一人治那 你想祙有人靠有人会疼，唛呐 你雨伞雨伞赶紧打开，唛呐 你雨伞雨伞赶紧打开，唛闹 落大雨你淋雨我艰苦 落大雨我没你会艰苦，Cuz baby you are mine mine(Mine )，Mine mine(Mine )，太快 就承认 我真的很想你，会不会没有男子气概 You say，唛呐 你雨伞雨伞赶紧打开，唛呐 你雨伞雨伞赶紧打开，唛闹 落大雨你淋雨我艰苦 落大雨我没你会艰苦', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (109, '109', '4', '公主病', '周杰伦', '周杰伦', '黄雨勋', '流行/电子 (Pop/Electronic)（与杨瑞代合唱）', '轻快的电子流行曲，调侃“公主病”', '十一', '2011-11-11', '惊叹号', '哎呦哥哥 嗨 你好！，我不是哎呦哥哥 我是巨炮叔叔 你怎么啦？，我生病了！，那听一下哎呦哥哥的阳光宅男就会好了啦！，No no～ 好不了喔…，为什么呢？，因为是公主病啦！(一开始的台词)，为什么我要去晒太阳 我要去学游泳，冲浪板要单手来扛，还不是因为你喜欢阳光男孩 要我奔跑在海滩上，你丢飞盘我学狗来接 汪，要我学后羿射太阳 因为你说太热，哥儿们都笑你活在 自己童话世界，你说不是的话怎么叫公主，看来这位公主 病的好像不轻，哭着说我背叛你，我说在哪里，你说在梦里，说一千遍爱你 这都不是问题，我用音乐来治你的公主病，要我打包自己 扮成Hello Kitty，那看起来就会有点问题，没关系我爱你 就算你爱自己，痘痘帮你挤赶走坏坏脾气，如果突然心急 想要美好婚姻，我的城堡说欢迎光临，为什么我要去晒太阳 我要去学游泳，冲浪板要单手来扛，还不是因为你喜欢阳光男孩 要我奔跑在海滩上，你丢飞盘我学狗来接 汪，要我学后羿射太阳 因为你说太热，哥儿们都笑你活在 自己童话世界，你说不是的话怎么叫公主，看来这位公主 病的好像不轻，哭着说我背叛你，我说在哪里，你说在梦里，说一千遍爱你 这都不是问题，我用音乐来治你的公主病，要我打包自己 扮成Hello Kitty，那看起来就会有点问题，没关系我爱你 就算你爱自己，痘痘帮你挤赶走坏坏脾气，如果突然心急 想要美好婚姻，我的城堡说欢迎光临，说一千遍爱你 这都不是问题，我用音乐来治你的公主病，要我打包自己 扮成Hello Kitty，那看起来就会有点问题，没关系我爱你 就算你爱自己，痘痘帮你挤赶走坏坏脾气，如果突然心急 想要美好婚姻，我的城堡说欢迎光临', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (110, '110', '5', '你好吗', '周杰伦', '罗宇轩、李汪哲', '黄雨勋', NULL, NULL, '十一', '2011-11-11', '惊叹号', '墙上静止的钟是为谁停留，是不是和我一样赖着不走，你说故事已经结束 很久，我忘了　向前走，我努力假装现在过得很好，现在的你看来已不需要我，也许在不同的时空，还牵着　你的手，想知道你真的过得好吗，没有我也许是种解脱，将思念穿梭在宇宙数千光年，悄悄到　你身边，现在我试着习惯一个人过，也许你已经开始新的生活，陪着我的叫做寂寞，陪你的　是谁呢？，想知道你真的过得好吗，没有我也许是种解脱，将思念穿梭在宇宙数千光年，悄悄到　你身边，现在我试着习惯一个人过，也许你已经开始新的生活，陪着我的叫做寂寞，陪你的　是谁呢？，也许在不同的时空，还牵着　你的手', '2025-10-29 20:21:10', '2025-10-29 20:21:10');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (111, '111', '6', '疗伤烧肉粽', '周杰伦', '周杰伦', '林迈可', '嘻哈/幽默说唱 (Hip-Hop/Humorous Rap)', '幽默地将食物与疗伤结合，风格轻松搞笑', '十一', '2011-11-11', '惊叹号', '唉呦 我早已说过你跟他应该会分开，吵架的理由我也已经知道大概，你需要人宠爱 天天叫你Baby，这英文 好险我会念，不听我的劝 纠缠好几年，委屈时借你靠肩 我不收你钱，等你想开了 不会再红着眼，什么叫正港的情人我来示范一遍，烧肉粽 如果你想吃不需要等到端午节，烧肉粽 你要酸的甜的苦的辣的随时给你，烧肉粽 酸甜苦辣的爱情请把它忘记，烧肉粽 我可以陪你也让你出气，把你的手借我 请你不用想太多，爱你不会说出口 只给你打气加油，只喜欢你笑容 所以不用想太多，当了一天情人以后 我怕你会嫌不够，反正现在分了 就跟你老实说吧，之前跟他套招 我真的没有办法，我实在不忍心 如果不骗你你会更伤心，只是我没想到 你居然会相信，不知道你是傻还是真的单纯，我想你是傻吧傻才会跟他一起，如果莫名奇妙你们又复合了，我说的这些就请把它忘了，烧肉粽 如果你想吃不需要等到端午节，烧肉粽 你要酸的甜的苦的辣的随时给你，烧肉粽 酸甜苦辣的爱情请把它忘记，烧肉粽 我可以陪你也让你出气，把你的手借我 请你不用想太多，爱你不会说出口 只给你打气加油，只喜欢你笑容 所以不用想太多，当了一天情人以后 我怕你会嫌不够，把你的手借我 Oh oh oh，爱你不会说出口 Oh oh oh yeah～，只喜欢你笑容 所以不用想太多，当了一天情人以后 我怕你会嫌不够', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (112, '112', '7', '琴伤', '周杰伦', '方文山', '黄雨勋', '中国风/古典 (Chinese Style/Classical)', '将《梁祝》小提琴协奏曲融入，中西合璧，讲述凄美爱情', '十一', '2011-11-11', '惊叹号', '海天 连线的 地方是那夕阳，木造 的甲板一整遍 是那金黄，你背光 的轮廓就像剪影一样，充满着想象 任谁都 会爱上，琴键声 在船舱 随海风 回荡，竟有一种 属于中世纪才有的浪漫，微笑眺望远方 是你的习惯，古典钢琴 在敲打 小小的那哀伤，你的眼神 隐约中有着不安不安，你不敢不敢 继续的暧昧喜欢，你泪化了妆 不舍全写在脸上，摇摇晃晃 船已入港，我不忍为难 问谁在等你靠岸，一圈戒痕 在你指上，目送你 越走越远的 悲伤，我害怕 故事走不到一半 你心里早就已经有了答案，走偏了 方向 你绝口 不谈 不谈，我不过问 只是彼此 的心被捆绑，明明 海阔天空 蔚蓝的海洋，你心里面 却有一个不透明的地方，浪倒映月光 足迹遗留在沙滩，留遗憾在码头上 空气弥漫着怀旧时光，我看见 呵护着你的那个 对象，我的和弦开始慢板的沧桑，你泪化了妆 不舍全写在脸上，摇摇晃晃 船已入港，我不忍为难 问谁在等你靠岸，一圈戒痕 在你指上，目送你 越走越远的 悲伤，你泪化了妆 不舍全写在脸上，摇摇晃晃 船已入港，我不忍为难 问谁在等你靠岸，一圈戒痕 在你指上，目送你 越走越远的 悲伤', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (113, '113', '8', '水手怕水', '周杰伦', '黄俊郎', '周杰伦', '嘻哈/概念说唱 (Hip-Hop/Conceptual Rap)', '探讨职业与恐惧的矛盾，概念性强', '十一', '2011-11-11', '惊叹号', '大海真可怕 叫我 水手 Oh oh come on come on baby，美人鱼勾引我这招 卑鄙，Oh喊我 水手 Oh oh come on come on honey，我喜欢你胜过Money，船舱它是我的家 大海是我嘘嘘的地方，我对海鲜会过敏 吃素已很久，想当那歌手 结果变成水手，Oh oh～ 怎么有点东北腔 No no～ 去到太远的地方，人家Popeye最爱吃菠菜 我却爱清粥小菜 再来点海带，铃不铃不铃 铃不铃不铃 铃不铃不铃，铃不铃不铃 我的闹钟怎么叫不醒我，喝不喝不喝 喝不喝不喝 喝不喝不喝 喝不喝不喝 林老师在喝牛奶，叫我 水手 Oh oh come on come on baby，美人鱼勾引我这招 卑鄙，Oh喊我 水手 Oh oh come on come on honey，我喜欢你胜过Money 这些海鲜 捕吃可吃，知不可吃 捕吃可吃 知不可吃可，不吃不吃不吃 克制不吃土司 跟我学一遍 来，（B Box），我去海产店买鱼虾来放生 去水族馆把鱼通通捞走，只有一种鱼捞不走 姓大名叫白鲨 大白鲨，船长说 为了节能减碳尽量用手划 有空就去甲板吸收太阳能，抹抹防晒 等着美人鱼上钩 Go，铃不铃不铃 铃不铃不铃 铃不铃不铃 铃不铃不铃，我的闹钟怎么叫不醒我，喝不喝不喝 喝不喝不喝 喝不喝不喝 喝不喝不喝，林老师在喝牛奶，叫我 水手 Oh oh come on come on baby，美人鱼勾引我这招 卑鄙，Oh喊我 水手 Oh oh come on come on honey，我喜欢你胜过Money，嘘 叫我 水手 Oh oh come on come on baby，美人鱼勾引我这招 卑鄙，Oh喊我 水手 Oh oh come on come on honey，我喜欢你胜过Money，叫我 水手 Oh oh come on come on baby，美人鱼勾引我这招 卑鄙 大白鲨 Oh喊我 水手，Oh oh come on come on honey，我喜欢你胜过Money', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (114, '114', '9', '世界未末日', '周杰伦', '方文山', '林迈可', '励志流行 (Inspirational Pop)', '鼓励人们在灾难面前保持希望，风格温暖', '十一', '2011-11-11', '惊叹号', '这街道在下陷，我们就快失去了家园，你我却都没有埋怨，将眼泪停格瞬间，街景摧毁 我内心却不轻易撤退，满天风雪 我们会微笑去面对，我牵着你的手，一路穿梭在城市路口，就算故事到了尽头，我们也绝不退缩，快转风景，被一再提醒失去森林，落叶声音，停不住我们的关心，就算是世界要崩溃，亲爱的我也绝不会落泪，不放弃爱过的那种感觉，珍惜着有你记忆的一切，就算是世界要倾斜，亲爱的我也绝不说离别，尽管末日威胁再强烈，有爱就不累，我牵着你的手，一路穿梭在城市路口，就算故事到了尽头，我们也绝不退缩，快转风景，被一再提醒失去森林，落叶声音，停不住我们的关心，就算是世界要崩溃，亲爱的我也绝不会落泪，不放弃爱过的那种感觉，珍惜着有你记忆的一切，就算是世界要倾斜，亲爱的我也绝不说离别，尽管末日威胁再强烈，有爱就不累', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (115, '115', '10', '皮影戏', '周杰伦', '唐从圣', '林迈可', '中国风/电子 (Chinese Style/Electronic)', '以传统皮影戏为题材，融合电子节拍', '十一', '2011-11-11', '惊叹号', '微薄的身躯 刻划出厚实尊严，　　小小屏幕 撑起大大一片天，　　观众静候在我的眼前 灯光闪耀在后面 我碎碎念，　　唱念做打喜怒哀乐 让你妈妈扭一下，　　记得跟着锣鼓点 哇勒点点点点点点点，　　我们的表演向左边 向右边，　　左右都逢源不恐后或争先，　　筋斗云就算在十万八千里，　　看我只需要翻三圈，　　近在咫尺 远在天边，　　笑我疯癫 凭你的脸？，　　还是快去排队买票看我的表演，　　大声点我听不见，　　皮影似神仙 我身轻如燕，　　你面前忽隐又忽现，　　飘逸在云和雾里面，　　傲气贯山巅，　　随性唱一遍变世代传承的经典，　　皮影似神仙 我身轻如燕，　　你面前忽隐又忽现 飘逸在云和雾里面 傲气贯山巅，　　随性唱一遍变世代传承的经典，　　剧力万千惊叹声连连，　　动静掌控全在绕指间，　　透明的眼 纯净的笑脸 只看颜色就能辩忠奸，　　唱念做打喜怒哀乐 让你妈妈扭一下，　　记得跟着锣鼓点 哇勒点点点点点点点，　　这说的故事 百善孝为先，　　这说的不是吃的虾味鲜，　　筋斗云就算在十万八千里，　　看我只需要翻三圈，　　近在咫尺 远在天边，　　笑我疯癫 凭你的脸？，　　还是快去排队买票看我的表演，　　大声点我听不见，　　皮影似神仙 我身轻如燕，　　你面前忽隐又忽现，　　飘逸在云和雾里面，　　傲气贯山巅，　　随性唱一遍变世代传承的经典', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (116, '116', '11', '超跑女神', '周杰伦', '方文山', '林迈可', '电子/舞曲 (Electronic/Dance)', '节奏强劲，为汽车广告创作，充满速度与激情', '十一', '2011-11-11', '惊叹号', '音乐在激动 舞步在骚动 你的心我掌控掌控 懂不懂，引擎声 划夜空 座椅上的安全带 在紧绷 我打开了敞篷，煞车踏板一松 这时空 就像是快转的钟，嘿我速度由自信驱动 请你专门来看一场会飙泪的感动，你专心在画睫毛 我专心在等你笑，你唇膏 涂抹少少 撒娇 讨好 我收到，长腿窄裙 太高调 下车姿势 太闪耀，这会让我的心跳 又叫 叫 叫，Oh oh 你的口红 颜色太过主动，我降下了车窗 呼吸放松，Oh oh 你的眼影 烟熏妆这么浓，不要 诱惑 诱惑 我，Oh oh 你的笑容 微甜让我心动，我踩下了油门 直往前冲，Oh oh 穿高跟鞋 的你即将受宠，排队追你的 最后一个 是我，你的水晶指甲 上面画着爱心 挑开了长发 想要对我说话，真的吗 真的吗 我竟在结巴 老半天 嘴里蹦不出 一句话，手握方向盘 跟着你发香 发烫排气管 说我太紧张，太紧张 打开天窗 不说亮话（Oh oh oh oh oh～） 只听你说才是最美的那一幅画，你专心在画睫毛 我专心在等你笑，你唇膏 涂抹少少 撒娇 讨好 我收到，长腿窄裙 太高调 下车姿势 太闪耀，这会让我的心跳 又叫 叫 叫，Oh oh 你的口红 颜色太过主动，我降下了车窗 呼吸放松，Oh oh 你的眼影 烟熏妆这么浓，不要 诱惑 诱惑 我，Oh oh 你的笑容 微甜让我心动，我踩下了油门 直往前冲，Oh oh 穿高跟鞋 的你即将受宠，排队追你的 最后一个 是我，Oh oh Oh oh 最后一个 是我，Oh oh Oh oh 最后一个 是我', '2025-10-29 20:21:10', '2025-10-30 20:54:47');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (117, '117', '1', '四季列车', '周杰伦', '方文山', '周杰伦', '流行/抒情 (Pop/Ballad)', '旋律温暖，以“四季”比喻人生旅程，是充满希望的抒情曲', '十二', '2012-12-28', '12新作', '远方的山 花开的声音 属于春天\n下一节车厢 盛夏 友情客串上演\n就好像连续快速弹奏黑白琴键\n车窗外一幕幕的风景比你还要善变\n我跟踪你的香水味中的那微甜\n寻找线索为了证明你依然鲜艳\n列车它继续向前 落叶它泪洒秋天\n越是接近你身边 景色就越像寒冷冬天\n噗噗 汽笛响 迎接神秘的雾\n准备到你面前却迷了路\nOh嘟嘟 你嘟嘴 表情有点糊涂\n你说你忘了我身上的温度\n噗噗 你眼神里有猫的孤独\n靠近你会危险我不在乎\nOh嘟嘟 转个圈 甩掉我的速度\n像猫一样的舞步我会记住\n踢开门后周围马上充满了敌意的脸\n每一张脸都紧绷带有着威胁的拳\n所有的英雄想在你面前有所表现\n你踮起了脚尖嘴唇烙印我鼻尖\n我跟踪你的香水味中的那微甜\n寻找线索为了证明你依然鲜艳\n列车它继续向前 落叶它泪洒秋天\n越是接近你身边 景色就越像寒冷冬天\n噗噗 汽笛响 迎接神秘的雾\n准备到你面前却迷了路\nOh嘟嘟 你嘟嘴 表情有点糊涂\n你说你忘了我身上的温度\n噗噗 你眼神里有猫的孤独\n靠近你会危险我不在乎\nOh嘟嘟 转个圈 甩掉我的速度\n像猫一样的舞步我会记住', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (118, '118', '2', '手语', '周杰伦', '周杰伦', '林迈可', '抒情流行 (Ballad Pop)', '情感细腻，旋律优美，表达无法言说的爱意', '十二', '2012-12-28', '12新作', '看着你我开不了口\n就算用手语也找不到字句来形容\n你的美太过梦幻太过迷人\n太多太多太多我说不完\n看着我你眼里闪烁\n那甜甜的傻笑\n准备接受我给你的酒窝\n放胸口请你相信不要怀疑\n这片星空就只有你拥有\n嘿Girl牵你的右手\n这不是在握手\n嘿Girl牵你的左手\n你可以想太多\n哎呦哎呦哎呦哎呦不错\n爱我先别开口\nOne more time\n嘿Girl牵你的右手\n亲你我会先漱口\n嘿Girl牵你的左手\n钻戒要套哪只手喔喔\n哎呦哎呦哎呦哎呦不错\n幸福只要点头\n喔我的手语你始终假装不懂\n我爱你要比好多遍\nFa So La Si Do Fa Fa So La Si Do Fa\n没办法逃离你的魔法\n喔为何我的唇语那么蠢\n你竟然会读不出来\nFa So La Si Do Fa Fa So La Si Do Fa\n我只好再亲吻你一遍\n看着你我开不了口\n就算用手语也找不到字句来形容\n你的美太过梦幻太过迷人\n太多太多太多我说不完\n看着我你眼里闪烁\n那甜甜的傻笑\n准备接受我给你的酒窝\n放胸口请你相信不要怀疑\n这片星空就只有你拥有\n嘿Ｇirl牵你的右手\n这不是在握手\n嘿Ｇirl牵你的左手\n你可以想太多\n哎呦哎呦哎呦哎呦不错\n爱我先别开口\nOne more time\n嘿Ｇirl牵你的右手\n亲你我会先漱口\n嘿Ｇirl牵你的左手\n钻戒要套哪只手喔喔\n哎呦哎呦哎呦哎呦不错\n幸福只要点头\n喔我的手语你始终假装不懂\n我爱你要比好多遍\nFa So La Si Do Fa Fa So La Si Do Fa\n没办法逃离你的魔法\n喔为何我的唇语那么蠢\n你竟然会读不出来\nFa So La Si Do Fa Fa So La Si Do Fa\n我只好再亲吻你一遍\n你的手指比划着爱心\n你说就让它放在我的掌心\n我会握紧请你要放心\n有我在一定一定不会出现伤心\n你抬起头看到那颗流星\n就像我遇见你的那时机\n嘿Ｇirl 嘿Ｇirl Girl 嘿Ｇirl\nWoo Baby\n你左手和我右手\n比出无限形状\n在黑键白键上创造幸福的音符\n喔我的手语你始终假装不懂\n我爱你要比好多遍\nFa So La Si Do Fa Fa So La Si Do Fa\n没办法逃离你的魔法\n喔为何我的唇语那么蠢\n你竟然会读不出来\nFa So La Si Do Fa Fa So La Si Do Fa\n我只好再亲吻你一遍\n我只好再亲吻你一遍', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (119, '119', '3', '公公偏头痛', '周杰伦', '方文山', '周杰伦', '中国风/嘻哈 (Chinese Style/Hip-Hop)', '以宫廷太监为题材，节奏感强，歌词幽默讽刺，融合戏曲元素', '十二', '2012-12-28', '12新作', '你这个笑话\n有够难笑\n来人啊\n把他给我拖出去斩啦\n公公 公公 公公\n公公他偏头痛\n公公他偏头痛\n说银两不够重\n公公公 公公公 公公\n公公贪污很凶\n公公贪污很凶\n那军饷被掏空\n后宫有 佳丽三千 却不能碰\n紧挨着灯笼\n这十年苦读无人能懂\n春夏秋冬\n无奈这夜晚寒风却穿透了屏风\n吹几页刺客列传我淡定背诵\n平仄先搞懂诗词歌赋才能够通\n书法的篆隶楷行草乃是基本功\n过眼的繁华朝代更迭来去匆匆\n法家的内容\n道家的从容\n儒家的宽容\n这些都该懂\n我是个穷秀才\n中状元考进来\n却一直状况外\n被宦官所陷害\n那公公的人脉\n遍五湖通四海\n大内的高手坏\n砸朝廷的招牌\n公公他偏头痛\n公公他偏头痛\n说银两不够重\n公公公 公公公 公公\n公公贪污很凶\n公公贪污很凶\n那军饷被掏空\n后宫有 佳丽三千 却不能碰\n我进京赶考\n免不了学而时习之的 摇头晃脑\n东方的琴棋书画比西方有情调\n弹琵琶古筝我的调调给力重要\n再感谢各位乡亲还有父父老\n提供我盘缠设宴款待外加水饺\n老子我读了老子老聃出关逍遥\n我说道可道\n你说非常道\n我说风萧萧\n你说你知道\n我是个穷秀才\n说道理明黑白\n在朝中如尘埃\n没人理有人爱\n不畏惧当权派\n上奏折硬着来\n那公公站起来\n整个人快气坏\n公公他偏头痛\n公公他偏头痛\n说银两不够重\n公公公 公公公 公公\n公公贪污很凶\n公公贪污很凶\n那军饷被掏空\n后宫有 佳丽三千 却不能碰\n公公公 公公公 公公公他不靠谱\n百姓们在歌颂\n他下台一鞠躬 躬\n公公公 公公公 公公公他不靠谱\n百姓们在歌颂\n他下台一鞠躬\n他下台一鞠躬\n他下台一鞠躬', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (120, '120', '4', '明明就', '周杰伦', '方文山', '黄雨勋', '抒情流行 (Ballad Pop)', '旋律悲伤，讲述异地恋的无奈与心碎，是经典的失恋情歌', '十二', '2012-12-28', '12新作', '糖果罐里好多颜色\n微笑却不甜了\n你的某些快乐\n在没有我的时刻\n中古世纪的城市里\n我想就走到这\n海鸥不再眷恋大海\n可以飞更远\n远方传来风笛\n我只在意有你的消息\n城堡为爱守着秘密\n而我为你守着回忆\n明明就 不习惯 牵手\n为何却主动把手勾\n你的心事太多\n我不会戳破\n明明就 他比较 温柔\n也许他能给你更多\n不用抉择 我会自动变朋友\n糖果罐里好多颜色\n微笑却不甜了\n你的某些快乐\n在没有我的时刻\n中古世纪的城市里\n我想就走到这\n海鸥不再眷恋大海\n可以飞更远\n远方传来风笛\n我只在意有你的消息\n城堡为爱守着秘密\n而我为你守着回忆\n明明就 不习惯 牵手\n为何却主动把手勾\n你的心事太多 我不会戳破\n明明就 他比较 温柔\n也许他能给你更多\n不用抉择 我会自动变朋友\n明明就 明明就\n明明就 他比较 温柔\n也许他能给你更多\n不用抉择 我会自动变朋友', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (121, '121', '5', '傻笑', '周杰伦', '方文山', '黄雨勋', '流行/小品 (Pop/Ditty)', '轻快的流行曲，表达恋爱中的甜蜜与傻气', '十二', '2012-12-28', '12新作', '眼看着手机里没讯号\n担心你的回信我收不到\n哪怕只传来\n一个微笑的符号\n我都会舍不得删掉\n电台传来天气的预报\n想起你为我遮雨的外套\n客厅的电视播放偶像剧频道\n羡慕他们为爱在争吵\n你在我的面前微笑装不知道\n其实你告白的简讯我有收到\n为何你爱要晚到\n只能像朋友般拥抱Yeah\n你说他的用心付出比我早到\n对你的温柔只能放心里收好\n为何你爱要晚到\n怎么做\n我们彼此才不会伤到\n我记得你爱喝的饮料\n的饮料\n也排队买你爱吃的面包\n的面包\n却只能对你远远\n的会心一笑\n连你的手都牵不到\n你说你有多的电影票\nYeah\n你知道\n事情没有\n那么巧\n但很窝心的是你怕我无聊\n你比他清楚我的心跳\n你在我的面前微笑装不知道\n其实你告白的简讯我有收到\n为何你爱要晚到\n只能像朋友般拥抱Yeah\n你说他的用心付出比我早到\n对你的温柔只能放心里收好\n为何你爱要晚到\n怎么做\n我们彼此才不会伤到\n你在我的面前微笑装不知道\n他没有不好只是话越聊越少\n为何你爱要晚到\n错过了幸福的味道Yeah\n用记忆在对你拍照让人难熬\n其实我对于你的好也曾动摇\n为何你爱要晚到\n对的人不对的时间\n却放不掉', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
