INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (123, '123', '7', '爱你没差', '周杰伦', '黄凌嘉', '黄雨勋', '流行/舞曲 (Pop/Dance)（与派伟俊合唱）', '节奏轻快，电子元素突出，表达无条件的爱', '十二', '2012-12-28', '12新作', '没有圆周的钟\n失去旋转意义\n下雨这天 好安静\n远行没有目的\n距离不是问题\n不爱了 是你的谜底\n我占据格林威治守候着你\n在时间标准起点回忆过去\n你却在永夜了的极地旅行\n等爱在失温后渐渐死去\n喔 对不起\n这句话 打乱了时区\n喔 你要我 在最爱的时候睡去\n我越想越清醒\n喔 爱你没差 那一点时差 喔\n你离开这一拳给的太重\n我的心找不到\n换日线它在哪\n我只能不停的飞\n直到我将你挽回\n爱你不怕 那一点时差 喔\n就让我静静一个人出发\n你的心总有个\n经纬度会留下\n我会回到你世界\n跨越爱的时差\n没有圆周的钟\n失去旋转意义\n下雨这天 好安静\n远行没有目的\n距离不是问题\n不爱了 是你的谜底\n我占据格林威治守候着你\n在时间标准起点回忆过去\n你却在永夜了的极地旅行\n等爱在失温后渐渐死去\n喔 对不起 这句话\n打乱了时区\n喔 你要我 在最爱的时候睡去\n我越想越清醒\n喔 爱你没差\n那一点时差 喔\n你离开这一拳给的 太重\n我的心找不到\n换日线它在哪\n我只能不停的飞\n直到我将你挽回\n那一点时差 喔\n就让我静静一个人出发\n你的心总有个\n经纬度会留下\n我会回到你世界\n跨越爱的时差', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (124, '124', '8', '红尘客栈', '周杰伦', '方文山', '黄雨勋', '中国风 (Chinese Style)', '以武侠客栈为背景，歌词充满江湖气息，旋律悠扬', '十二', '2012-12-28', '12新作', '天涯 的尽头是风沙\n红尘 的故事叫牵挂\n封刀隐没在寻常人家 东篱下\n闲云 野鹤 古刹\n快马 在江湖里厮杀\n无非 是名跟利放不下\n心中有江山的人岂能快意潇洒\n我只求与你共 华发\n剑出鞘 恩怨了 谁笑\n我只求今朝 拥你入 怀抱\n红尘客栈风似刀\n骤雨落 宿命敲\n任武林谁领风骚我却 只为你 折腰\n过荒村野桥 寻世外 古道\n远离人间尘嚣 柳絮飘执子之手逍遥\n檐下 窗棂斜映枝桠\n与你 席地对座饮茶\n我以工笔画将你牢牢 的记下\n提笔 不为风雅\n灯下 叹红颜近晚霞\n我说缘份 一如参禅不说话\n你泪如梨花洒满了纸上的天下\n爱恨如写意 山水画\n剑出鞘 恩怨了 谁笑\n我只求今朝 拥你入 怀抱\n红尘客栈风似刀\n骤雨落 宿命敲\n任武林谁领风骚我却 只为你 折腰\n过荒村野桥 寻世外 古道\n远离人间尘嚣 柳絮飘执子之手逍遥\n任武林谁领风骚我却 只为你 折腰\n你回眸多娇 我泪中 带笑\n酒招旗风中萧萧 剑出鞘 恩怨了', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (125, '125', '9', '梦想启动', '周杰伦', '林义杰', '林迈可', '励志嘻哈 (Inspirational Hip-Hop)（与杨瑞代、弹头、宇豪合唱）', '节奏强劲，歌词励志，鼓励追逐梦想', '十二', '2012-12-28', '12新作', 'Come on go go go让梦重新启动\n不同的汗水流着那不同的梦\n当你还在继续 我当然也不能够说放弃\n因为坚持 所以我们越要相信\n你说你的奔跑总是想要超越自己\n我说我的音乐努力想要跨越时代\n把所有的失败挫折全部抛在脑后\n我即将看见世界的地图从你脚下过\n慢慢的睁开 慢慢的睁开\n仰望着天空就算努力也许孤独\n把心都打开 把心都打开\n如果那机会降临你能够追的上吗\n微笑吧 就算不断失败\n站起来 再重来 把脆弱推开\n信心在脑海别让灵魂空白\n在现在 在未来 我为你喝采\nOh oh oh oh oh Oh oh oh oh\nOh oh oh oh oh\nOh oh oh oh oh\nOh oh oh oh oh\nCome on go go go让梦重新启动\n不同的汗水流着那不同的梦\n当你还在继续 我当然也不能够说放弃\n因为坚持 所以我们越要相信\n你奔跑总是想要超越自己\n我音乐努力想要跨越时代\n所有失败挫折全部抛脑后\n即将看世界的地图从你脚下过\n慢慢的睁开 慢慢的睁开\n仰望着天空就算努力也许孤独\n把心都打开 把心都打开\n如果那机会降临你能够追的上吗\n微笑吧 就算不断失败\n站起来 再重来 把脆弱推开\n信心在脑海别让灵魂空白\n在现在 在未来 我为你喝采\n微笑吧 就算不断失败\n站起来 再重来 把脆弱推开\n信心在脑海别让灵魂空白\n在现在 在未来 我为你喝采', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (126, '126', '10', '大笨钟', '周杰伦', '周杰伦', '黄雨勋', '英伦摇滚/流行 (Britpop/Pop)', '受英国大笨钟启发，旋律带有英伦摇滚的慵懒与浪漫', '十二', '2012-12-28', '12新作', '你说我比大笨钟还笨要怎么比\n吵架我太安静钟至少还有声音\n要我离开我早就打包好行李\n喝完这杯咖啡我就走答应你\n过这么久怎么还没叫我还你DVD\n再不打给我我就不打算追回你\n我走在你喜欢的电影场景里\n你却不在我想要的场景里\n耍什么嘴硬 耍 耍什么嘴硬\n有什么毛病 有 有什么毛病\n我很大器 我没你小气\n我会原谅你 你仔细听\n我从未爱过你 怎么会想念你\n发什么神经 有理说不清\n只是脑袋还不清醒\n其实还爱着你 其实还想着你 Yeah\n请你别太得意\n你说我比大笨钟还笨要怎么比\n吵架我太安静钟至少还有声音\n要我离开我早就打包好行李\n喝完这杯咖啡我就走答应你\n过这么久怎么还没叫我还你DVD\n再不打给我我就不打算追回你\n我走在你喜欢的电影场景里\n你却不在我想要的场景里\n耍什么嘴硬 耍 耍什么嘴硬\n有什么毛病 有 有什么毛病\n我很大器 我没你小气\n我会原谅你 你仔细听\n我从未爱过你 怎么会想念你\n发什么神经 有理说不清\n只是脑袋还不清醒\n其实还爱着你 其实还想着你 Yeah\n请你别太得意\nOoh wah Ooh wah Baby\n我从未爱过你 怎么会想念你 Yeah\n只是脑袋还不清醒\n其实还爱着你 其实还想着你 Yeah\n请你别太得意', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (127, '127', '11', '哪里都是你', '周杰伦', '周杰伦', '黄雨勋', '电子/舞曲 (Electronic/Dance)', '节奏感强，电子音效密集，表达对爱人的无尽思念', '十二', '2012-12-28', '12新作', '把她忘记\n重复告诉自己\n熟悉不再熟悉\n但清晰却还是一样清晰\n喔～去吧\n随着右手旋律\n忘了左手的委屈\n就算没伴奏也可以继续\n前进 找寻新的记忆和空气\n放晴 等雨说放弃\n在有眼泪的雨里\n哪里都是你\n擦干是否就看不见你\n脑海里 你的笑容太彻底\n彻底把我囚禁在你的呼吸\n我跟着哭泣\n在有眼泪的雨里\n哪里都是你\n抱紧你是我逃离的距离\n太拥挤 我在你的世界里\n看不清楚的是你还是自己\n我们都在等雨停\n把她忘记\n重复告诉自己\n熟悉不再熟悉\n但清晰却还是一样清晰\n喔～去吧\n随着右手旋律\n忘了左手的委屈\n就算没伴奏也可以继续\n前进 找寻新的记忆和空气\n放晴 等雨说放弃\n在有眼泪的雨里\n哪里都是你\n擦干是否就看不见你\n脑海里 你的笑容太彻底\n彻底把我囚禁在你的呼吸\n我跟着哭泣\n在有眼泪的雨里\n哪里都是你\n抱紧你是我逃离的距离\n太拥挤 我在你的世界里\n看不清楚的是你还是自己\n我们都在等雨停', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (128, '128', '12', '乌克丽丽', '周杰伦', '周杰伦', '林迈可', '夏威夷/流行 (Hawaiian/Pop)', '使用尤克里里（Ukulele）为主要乐器，风格轻松阳光，充满度假风情', '十二', '2012-12-28', '12新作', '穿花衬衫要配上一把乌克丽丽\n不然看起来会像流氓兄弟\n穿西装要记得带个带个女伴\n不然看起来会像泊车小弟\n一般我是不会\n随便就载着花瓶兜风\n我不是说你是个花瓶\n你你你别发疯\n你说你很容易碎\n叮咚叮咚\n让我来保护你\n你懂我懂\n你要我小心你的坏脾气\n我说我刚好有一点耐心\n你始终改变不了的任性\n我当它是一种可爱的个性\n你就是海滩下的那乌克丽丽\n寻找着逆光让暧昧变成剪影\n浪漫不一定要在那夏威夷\n沙滩上有你的脚印\n是一辈子美景\n别剪短你的发让它飘逸\n刚好配上我的八块肌\n别再不吃东西\n瘦到不行\n乌克丽丽在你身上\n就像一把放大的Guitar\n迷人不一定要比基尼\n你的笑容已经非常卡哇伊\n想要度假不用去到Hawaii\n椰子树刚好种在我家院子里\n想要买醉 买醉 买醉 买醉\n不一定要喝酒 喝酒\n一起干杯 干杯 干杯 干杯\n用音乐来灌醉你\n怎么能够\n你就是海滩下的那乌克丽丽\n寻找着逆光让暧昧变成剪影\n浪漫不一定要在那夏威夷\n沙滩上有你的脚印\n是一辈子美景\n你就是海滩下的那乌克丽丽\n寻找着逆光让暧昧变成剪影\n浪漫不一定要在那夏威夷\n沙滩上有你的脚印\n是一辈子美景\n怎么能够\n你就是海滩下的那乌克丽丽\n寻找着逆光让暧昧变成剪影\n浪漫不一定要在那夏威夷\n沙滩上有你的脚印\n是一辈子美景', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (129, '129', '1', '阳明山', '周杰伦', '方文山', '林迈可', '爵士/嘻哈 (Jazz/Hip-Hop)', '慵懒的爵士鼓点与即兴说唱结合，描绘台北阳明山的浪漫约会', '十三', '2014-12-25', '哎呦，不错哦', '我找 找 找你不到\n要怎么抱 抱 抱你的腰\n你终于笑笑笑笑\n我知道\n小指勾 点头 牵手 朋友\nGO\n是男生都想要载校花\n（载校花）\n绝不能让别人看笑话\n（看笑话）\n来场抽钥匙的复古趴\n（复古趴）\n叭叭叭 叭啦叭啦叭\nEverybody\n跟着我\n谁说夜店才有Party\nHey Hey\n把你的手放胸口\n我是说放我的胸口\nHey Hey\n我喜欢爱笑的你\n但是这一句太俗气\nHey Hey\n改换文青的造句\n你一抹微笑如茉莉\n我摇 摇 摇杯饮料\n阳明山要 要 要点热闹\n你低头笑笑笑笑 说好巧\n跳个舞再走 快乐在我\nGO\n迎着风一路欣赏海芋\n（赏海芋）\n你紧抱我这一场花季\n（场花季）\n你说是不能说的秘密\n（的秘密）\n嘘\n从你暧昧的眼神里\n心事好拥挤好像有话传递\n背对背煮着温泉蛋\n滚烫的热情让爱情变神秘\n哒啦哒哒啦哒\n（快熟了）\n哒啦哒哒啦哒\n（要熟了）\n啊煮到我的手啦\nEverybody\n跟着我\n谁说夜店才有Party\nHey Hey\n把你的手放胸口\n我是说放我的胸口\nHey Hey\n我喜欢爱笑的你\n但是这一句太俗气\nHey Hey\n改换文青的造句\n你一抹微笑如茉莉\nEverybody\n跟着我\n谁说夜店才有Party\nHey Hey\n有人心情坏天气\n轮胎就故意偷漏气\nHey Hey\n为赋新词装忧郁\n雾满楼春雨添瓦绿\nHey Hey\n白话一点也可以\n我心里满满都是你 你 你', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (130, '130', '2', '窃爱', '周杰伦', '黄俊郎', '黄雨勋', 'R&B/抒情 (R&B/Ballad)（与阿信合唱）', '旋律忧郁，讲述一段不被祝福的隐秘爱情', '十三', '2014-12-25', '哎呦，不错哦', '接近你偷偷轻轻悄悄\n比深幽的星空还低调\n你永远不会知道\n你的香味盗走了我的骄傲\n街灯在河岸垂钓\n萤火为孤单闪耀\n都没有窃爱美妙\n我窃来了深夜\n使你能好睡\n盗走了岁月\n让你永不枯萎\n关于爱你的一切\n我做什么都对\n我窃来了安慰\n使你忘了流泪\n盗走了懊悔\n让你永远无邪\n关于爱上的一切\n我开始无路可退\n看你的你的俏广场的石雕\n都想舞蹈\n看你的笑城墙的号角\n忘了吵闹\n多美的爱情美的爱情\n爱 情来临\n来来临来 临\n我在画里的桥吹着口哨\n烟火城堡还空一角等\n你的拥抱\n多美的爱情美的爱情\n为了它神魂颠倒\n接近你偷偷轻轻悄悄\n比深幽的星空还低调\n你永远不会知道\n你的香味盗走了我的骄傲\n街灯在河岸垂钓\n萤火为孤单闪耀\n都没有窃爱美妙\n我窃来了深夜使你能好睡\n盗走了岁月让你永不枯萎\n关于爱你的一切\n我做什么都对\n我窃来了安慰\n使你忘了流泪\n盗走了懊悔让你永远无邪\n关于爱上的一切\n我开始无路可退\n看你的你的俏广场的石雕\n都想舞蹈\n看你的笑城墙的号角\n忘了吵闹\n多美的爱情美的爱情\n爱 情来临\n来来临来 临\n我在画里的桥吹着口哨\n烟火城堡还空一角等你的拥抱\n多美的爱情美的爱情\n为了它神魂颠倒\n我在画里的桥吹着口哨\n烟火城堡还空一角等\n你的拥抱\n多美的爱情美的爱情\n为了它神魂颠倒', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (131, '131', '3', '算什么男人', '周杰伦', '周杰伦', '黄雨勋', '抒情摇滚 (Ballad Rock)', '情感爆发力强，充满自责与忏悔，是典型的失恋摇滚情歌', '十三', '2014-12-25', '哎呦，不错哦', '亲吻你的手\n还靠着你的头\n让你躺胸口\n那个人已不是我\n这些平常的举动现在叫做难过\n喔 难过\n日子开始过\n我没你照样过\n不会很难受\n我会默默的接受\n反正在一起时你我都有开心过\n就足够\n我的温暖你的冷漠让爱起雾了\n如果爱心画在起雾的窗是模糊\n还是更清楚\n你算什么男人\n算什么男人\n眼睁睁看她走却不闻不问\n是有多天真 就别再硬撑\n期待你挽回你却拱手让人\n你算什么男人\n算什么男人\n还爱着她却不敢叫她再等\n没差 你再继续认份\n她会遇到更好的男人\n亲吻你的手\n还靠着你的头\n让你躺胸口\n那个人已不是我\n这些平常的举动现在叫做难过\n喔 难过\n日子开始过\n我没你照样过\n不会很难受\n我会默默的接受\n反正在一起时你我都有开心过\n就足够\n我的温暖你的冷漠让爱起雾了\n如果爱心画在起雾的窗是模糊\n还是更清楚\n你算什么男人\n算什么男人\n眼睁睁看她走却不闻不问\n是有多天真 就别再硬撑\n期待你挽回你却拱手让人\n你算什么男人\n算什么男人\n还爱着她却不敢叫她再等\n没差 你再继续认份\n她会遇到更好的男人\n你算什么男人\n算什么男人\n眼睁睁看她走却不闻不问\n是有多天真 就别再硬撑\n期待你挽回却拱手让人\n你算什么男人\n算什么男人\n还爱着她却不敢叫她再等\n没差 你再继续认份\n她会遇到更好的男人', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (132, '132', '4', '天涯过客', '周杰伦', '方文山', '黄雨勋', '中国风 (Chinese Style)', '以江湖浪子为视角，旋律苍凉，充满漂泊感', '十三', '2014-12-25', '哎呦，不错哦', '风起雁南下\n景萧萧 落黄沙\n独坐沏壶茶\n沏成一夜灯下\n你在几里外的人家想着他\n一针一线 绣着花\n晨霜攀黛瓦\n抖落霜 冷了茶\n抚琴欲对话 欲问琴声初落下\n弦外思念透窗花\n而你却什么也不回答\n琴弦断了 缘尽了 你也走了\n爱恨起落 故事经过 只留下我\n几番离愁 世事参透 都入酒\n问你是否 心不在这 少了什么\n琴弦断了 缘已尽了 你也走了\n你是过客 温柔到这沉默了\n拱桥斜坡 水岸码头 谁记得\n渡江扁舟 我伤依旧 临行回头\n远方谁挥手\n古刹山岚绕 雾散后 北风高\n禅定我寂寥 我身后风呼啸\n笛声半山腰\n而你在哪座桥\n远远对他 在微笑\n亭外芦苇花 白茫茫\n细雨轻轻打 秋风刮\n将笔搁下 画不出 谁在潇洒\n情愫竟短暂犹如\n骚人墨客笔下的烟花\n琴弦断了 缘已尽了 你也走了\n爱恨起落 故事经过 只留下我\n门前竹瘦 清风折柳 你要走\n风不停留 何苦绕来 摇晃灯火\n琴弦断了 缘已尽了 你也走了\n你是过客 温柔到这 沉默了\n轻解绳索 红尘放手 面对着\n随我摆渡 离岸东流 蓦然回首\n你在渡船口\n琴弦断了 缘尽了 你也走了\n你是过客 温柔到这 沉默了\n拱桥斜坡 水岸码头 谁记得\n随我摆渡 离岸东流 蓦然回首\n你在渡船口', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (133, '133', '5', '怎么了', '周杰伦', '方文山', '林迈可', '抒情流行 (Ballad Pop)', '旋律悲伤，质问逝去的爱情，情感真挚', '十三', '2014-12-25', '哎呦，不错哦', '男：上车了收拾心情背上行李\n我走了一再重复听你喜欢听的歌\n甜蜜回忆太多 心乱了 真的结束了\n舍不得 你唱的生日快乐歌\n还记得 你的温柔方式终于我懂了\n话题聊到这里你笑了\n却也太迟了\n我用咖啡拉花拉出白色的线煮一杯眷恋\n你侧脸在咖啡表面形成了思念形成怀念\n你长发披肩我渐渐的勾划出你嘴角弧线\n所有的从前我慢慢的喝掉有你在的画面\n手中的寂寞续杯苦了谁\n清醒了当初离开你的感觉\n在不是冬天季节冷了离别\n合：我还想听你叫我宝贝\n怕你身边多了个谁\n失眠的夜独自面对\n花少了蝶树枯了叶\n还想听你叫我宝贝\n痛快心碎或许干脆\n两人世界漫天的风雪\n我爱过的谁\n女：怎么了（男：你说呢）\n女：为何沟通最后总是我哭了（男：不说了）\n女：承认犯错又能如何你选择（男：我认了）\n女：是不是我们都太自我（男：自我）\n合：借口要自由\n男：沉默了（女：离开了）\n男：明明彼此付出比谁都要多（女：我才多）\n男：却相爱的比谁都要不成熟（女：都怪我）\n男：是不是等伤口都愈合（女：愈合）\n合：才能再拥有\n我用咖啡拉花拉出白色的线煮一杯眷恋\n你侧脸在咖啡表面形成了思念形成怀念\n男：你长发披肩我渐渐的勾画出你嘴角弧线（女：有你在的画面）\n所有的从前我慢慢的喝掉有你在的画面\n手中的寂寞续杯苦了谁\n清醒了当初离开你的感觉\n在不是冬天季节冷了离别\n合：我还想听你叫我宝贝\n怕你身边多了个谁\n失眠的夜独自面对\n花少了蝶树枯了叶\n还想听你叫我宝贝\n痛快心碎或许干脆\n两人世界漫天的风雪\n我爱过的谁\n男：我还想听你叫我宝贝\n怕你身边多了个谁\n失眠的夜独自面对\n合：花少了蝶树枯了叶\n男：还想听你叫我宝贝\n痛快心碎或许干脆\n两人世界漫天的风雪\n合：我爱过的谁', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (134, '134', '6', '一口气全念对', '周杰伦', '方文山', '周杰伦', '快嘴说唱/嘻哈 (Fast Rap/Hip-Hop)', '语速极快，挑战中文发音极限，是技术性极强的说唱作品', '十三', '2014-12-25', '哎呦，不错哦', '这这谁 欢迎你来派对\n我的世界\n在宽敞的大街\n飙音乐\n再念一段碎嘴\n过来挑战就对\n鸣枪起跑预备\n就咪让咪压咪力咪\n喘咪一咪口咪气咪\n给咪它咪机咪会咪\n跟咪着咪音咪乐咪\n将咪爱咪写咪成咪\n一咪段咪过咪去咪\n只咪留咪下咪对咪的咪记咪忆\n嘿\n对对对对了\n一口气全念对\n对对对对了\n没事就动动嘴\n动动动动嘴\n动动嘴 动动嘴\n拍子要念准确\n才会抓到感觉\n你的香水 我的心跳\n搞得我很难思考\n窄裙线条 对我撒娇\n抚媚嘴角猜不到\n你抹香水 我摸心跳\n性感就快要破表\n扭水蛇腰 不吵不闹\n爱上你只需一秒\n这这谁 欢迎你来派对\n我的世界\n这里不用辛苦 戴尾戒\n没有嫉妒防备\n只有开心纯粹\n以及屌的音乐\n就咪让咪压咪力咪\n喘咪一咪口咪气咪\n给咪它咪机咪会咪\n跟咪着咪音咪乐咪\n将咪爱咪写咪成咪\n一咪段咪过咪去咪\n只咪留咪下咪对咪的咪记咪忆\n嘿\n对对对对了\n一口气全念对\n对对对对了\n没事就动动嘴\n动动动动嘴\n动动嘴 动动嘴\n拍子要念准确\n才会抓到感觉\n你的香水 我的心跳\n搞得我很难思考\n窄裙线条 对我撒娇\n抚媚嘴角猜不到\n你抹香水 我摸心跳\n性感就快要破表\n扭水蛇腰 不吵不闹\n爱上你只需一秒', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (135, '135', '7', '我要夏天', '周杰伦', '周杰伦', '黄雨勋', '流行/舞曲 (Pop/Dance)（与杨瑞代、派伟俊、崔惟楷、林秋离合唱）', '节奏欢快，充满夏日热情', '十三', '2014-12-25', '哎呦，不错哦', '伦：别怕晒的黑\n看起来很健康\n泳池旁的妹\n笑起来很阳光\n对你Say个Hey\n出水芙蓉加甩头\n你是哪位\n代：管他天多黑\n反正还有月光\n脚步继续追\n冲上沙滩的浪\n越High越不累\n音乐不停我们也停不下来\n合：举起手来 尖叫呐喊\n萤光棒 仙女棒\n管你还有什么棒都一起摇摆\n冲冲冲冲冲 冲向海边\nGo Go Go Go Go\n准备疯癫\n我要夏天 在我耳边碎碎念\n冲冲冲冲冲 冲向海边\nGo Go Go Go Go\n到你身边\n别说再见 我已经开始想念\nHey Hey Hey Hey Hey Hey\nHey Hey Hey Hey Hey Hey\n伦：（我说）别怕晒的黑\n看起来很健康\n泳池旁的妹\n笑起来很阳光\n对你Say个Hey\n出水芙蓉加甩头\n你（Hey） 是（Hey） 哪（Hey） 位（Hey）\n代：管他天多黑 反正还有月光\n脚步继续追 冲上沙滩的浪\n越High越不累\n音乐不停我们也停不下来\n合：举起手来 尖叫呐喊\n萤光棒 仙女棒\n管你还有什么棒都一起摇摆\n冲冲冲冲冲 冲向海边\nGo Go Go Go Go\n准备疯癫\n我要夏天\n在我耳边碎碎念\n冲冲冲冲冲 冲向海边\nGo Go Go Go Go\n到你身边\n别说再见 我已经开始想念\n冲冲冲冲冲 冲向海边\nGo Go Go Go Go\n准备疯癫\n我要夏天 在我耳边碎碎念\n冲冲冲冲冲 冲向海边\nGo Go Go Go Go\n到你身边\n别说再见 我已经开始想念\nHey Hey Hey\n已开始想念\nHey Hey Hey\n已开始想念', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (136, '136', '8', '手写的从前', '周杰伦', '方文山', '黄雨勋', '抒情流行 (Ballad Pop)', '怀念手写书信的年代，旋律温暖怀旧', '十三', '2014-12-25', '哎呦，不错哦', '这风铃跟心动很接近\n这封信还在怀念旅行\n路过的爱情都太年轻\n你是我想要 再回去的风景\n这别离被瓶装成秘密\n这雏菊美得像诗句\n而我在风中等你 的消息\n等月光落雪地\n等枫红染秋季等相遇\n我重温午后的阳光\n将吉他斜背在肩上\n跟多年前一样 我们轻轻地唱\n去任何地方\n我看着你的脸 轻刷着和弦\n情人节卡片 手写的永远\n还记得广场公园 一起表演\n校园旁糖果店 记忆里在微甜\n我看着你的脸 轻刷着和弦\n初恋是整遍 手写的从前\n还记得那年秋天 说了再见\n当恋情已走远\n我将你深埋在 心里面\n微风需要竹林 溪流需要蜻蜓\n乡愁般的离开 需要片片浮萍\n记得那年的雨季 回忆里特安静\n哭过后的决定 是否还能进行\n我傻傻等待 傻傻等春暖花开\n等终等于等明等白 等爱情回来\n青春属于表白 阳光属于窗台\n而我想我属于\n一个拥有你的未来\n纸上的彩虹 用素描画的钟\n我还在修改 回忆之中你的笑容\n该怎么去形容 为思念酝酿的痛\n夜空霓虹 都是我不要的繁荣\n或许去趟沙滩 或许去看看夕阳\n或许任何一个可以想心事的地方\n情绪在咖啡馆 被调成一篇文章\n彻底爱上你如诗一般透明的泪光\n我看着你的脸 轻刷着和弦\n情人节卡片 手写的永远\n还记得广场公园 一起表演\n校园旁糖果店 记忆里在微甜\n我看着你的脸 轻刷着和弦\n初恋是整遍 手写的从前\n还记得那年秋天 说了再见\n当恋情已走远\n我将你深埋在 心里面\n我重温午后的阳光\n将吉他斜背在肩上\n跟多年前一样 我们轻轻地唱\n去任何地方\n我看着你的脸 轻刷着和弦\n情人节卡片 手写的永远\n还记得广场公园 一起表演\n校园旁糖果店 记忆里在微甜\n我看着你的脸 轻刷着和弦\n初恋是整遍 手写的从前\n还记得那年秋天 说了再见\n当恋情已走远\n我将你深埋在 心里面', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (137, '137', '9', '鞋子特大号', '周杰伦', '方文山', '黄雨勋', '嘻哈/幽默说唱 (Hip-Hop/Humorous Rap)', '延续《双截棍》的幽默风格，调侃自己的大脚，节奏轻快', '十三', '2014-12-25', '哎呦，不错哦', '巨炮：喂\n杰伦：喂巨炮哦\n巨炮：欸欸\n杰伦：欸你有没有看过卓别林\n巨炮：卓别林哦\n杰伦：欸有看过吗\n巨炮：你是说他的电影是不是\n杰伦：我是说他本人啦\n巨炮：哈哈哈哈哈哈很难笑耶哈哈\n如如如如如 如果不小心跌倒\n马上就爬起来装没事\n幽默是这世上最好的礼物\n别只想要当那王子公主 公主\n别对人家冷漠耍帅装酷 装酷\n让一切的准备都完美演出\n让所有的努力都美好落幕\n哎哟喂啊 字典里没有收录\n差点跌倒 却不自觉会说出\n叽里咕噜 唏哩呼噜\n幽默是专业的行为艺术\n就算是跟猫打招呼\n或者是跟狗问路也要很专注\n听清楚什么呼噜\n绝不是形容东方鱼肚白的日出\n还有偶尔扮演一棵树\n你才知道当人类有多美妙\n我戴着圆顶礼帽 鞋子特大号\n我手拿拐杖留着胡子 大家好\n别什么你都想要快乐却找不到\n幽默是挫折中优雅的礼貌\n跟我一起\nHey Hey Hey Hey Hey Hey Hey Hey\nHey Hey Hey Hey Hey Hey Hey Hey\n完了没\n如果不小心跌倒\n马上就爬起来装没事\n幽默是这世上最好的礼物\n别只想要当那王子公主 公主\n别对人家冷漠耍帅装酷 装酷\n让一切的准备都完美演出\n让所有的努力都美好落幕\n哎哟喂啊 字典里没有收录\n差点跌倒 却不自觉会说出\n叽里咕噜 唏哩呼噜\n喜剧要百分之百的投入\n不管演动物或植物\n你一定都要演的让人家羡慕\n听清楚 不是葫芦\n我一身的打扮也不是在变魔术\n表情无辜 闯祸时无助\n让你开心 其实要一点头脑\n我戴着圆顶礼帽 鞋子特大号\n我动作逗趣所有人都笑翻掉\n若生活需要微笑\n请看着我就好\n将压力一股脑 全部释放掉\n我戴着圆顶礼帽 鞋子特大号\n我手拿拐杖留着胡子 大家好\n别什么你都想要快乐却找不到\n幽默是挫折中优雅的礼貌\n再来一遍\n叽里咕噜 唏哩呼噜\n喜剧要百分之百的投入\n不管演动物或植物\n你一定都要演的让人家羡慕\n听清楚不是葫芦\n我一身的打扮也不是在变魔术\n将压力一股脑释放掉\n若生活 要微笑 看着我就好', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (138, '138', '10', '听爸爸的话', '周杰伦', '周杰伦', '黄雨勋', '嘻哈/流行说唱 (Hip-Hop/Pop Rap)', '与《听妈妈的话》呼应，风格类似，劝导孩子要懂事', '十三', '2014-12-25', '哎呦，不错哦', '你听爸爸的话\n说我不是个好东西\n送给你的花\n不配放在你家花瓶里\n他要我越走越远越好\n不要在一起那最好\n但我听妈妈的话\n要我不能轻易放弃\n还喜欢的话让我再追回你求求你\n难道你要我不孝顺吗\n这是借口你应该懂吧\n你说 谁说 我说 我不爱了\n胡说 瞎说 我习惯了\n那烟 和酒 也都戒了\n证明有多在乎你了\n光上 一句 我想你懂\n我真的不太会说话\n你看你 笑了吧\n你说我 算了吧\n一个人 的爱情 很简单\n两个人的相爱\n为什么反而变得很难\n我受够我的爱你比较多\n也受够你的爱沉默很久\n承诺太多 多少会错\n你宁愿难过也不要有结果\n我受够我的爱你比较多\n倒不如回到从前的自由\n说好放手 谁先开口\n没有对错\n反正花开了终究会落\n你说 谁说 我说 我不爱了\n胡说 瞎说 我习惯了\n那烟 和酒 也都戒了\n证明有多在乎你了\n一个人 的爱情 很简单\n两个人的相爱\n为什么反而变得很难\n你听爸爸的话\n说我不是个好东西\n送给你的花\n不配放在你家花瓶里\n他要我越走越远越好\n不要在一起那最好\n但我听妈妈的话\n要我不能轻易放弃\n还喜欢的话让我再追回你求求你\n难道你要我不孝顺吗\n这是借口你应该懂吧\n我受够我的爱你比较多\n也受够你的爱沉默很久\n承诺太多 多少会错\n你宁愿难过也不要有结果\n我受够我的爱你比较多\n倒不如回到从前的自由\n说好放手 谁先开口\n没有对错\n反正花开了终究会落\n难道你要我不孝顺吗\n这是借口你应该懂吧', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (139, '139', '11', '美人鱼', '周杰伦', '罗宇轩、黄婕熙', '林迈可', '电子/舞曲 (Electronic/Dance)', '节奏感强，电子音效营造海底世界氛围', '十三', '2014-12-25', '哎呦，不错哦', '维京航海 日记簿 停留在甲板等日出\n瓶中信 被丢入 关于美人鱼的纪录\n中世纪 的秘密 从此后被塞入了瓶盖\n千年来 你似乎 为等谁而存在\n或许凄美 在暧昧 海与夕阳之间金黄的一切\n海岸线 在起雾 似乎是离别适合的季节\n雾散后 只看见 长发的你出现在岸边\n为了爱 忘了危险\n美人鱼的眼泪\n是一个连伤心都透明的世界\n地平线的远方一轮满月\n童话般感觉\n让我爱上有你的黑夜\n无声的眼泪\n水族玻璃里你一次次的来回\n思念成了仅存的那一切\n缺氧的感觉\n维京航海 日记簿 停留在甲板等日出\n瓶中信 被丢入 关于美人鱼的纪录\n中世纪 的秘密 从此后被塞入了瓶盖\n千年来 你似乎 为等谁而存在\n或许凄美 在暧昧 海与夕阳之间金黄的一切\n海岸线 在起雾 似乎是离别适合的季节\n雾散后 只看见 长发的你出现在岸边\n为了爱 忘了危险\n美人鱼的眼泪\n是一个连伤心都透明的世界\n地平线的远方一轮满月\n童话般感觉\n让我爱上有你的黑夜\n无声的眼泪\n水族玻璃里你一次次的来回\n思念成了仅存的那一切\n缺氧的感觉\n美人鱼的眼泪\n是一个连伤心都透明的世界\n地平线的远方一轮满月\n童话般感觉\n让我爱上有你的黑夜\n无声的眼泪\n水族玻璃里你一次次的来回\n思念成了仅存的那一切\n缺氧的感觉', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (140, '140', '12', '听见下雨的声音', '周杰伦', '方文山', '黄雨勋', '抒情流行 (Ballad Pop)', '以雨声为引，旋律优美，充满诗意与感伤', '十三', '2014-12-25', '哎呦，不错哦', '竹篱上停留着蜻蜓\n玻璃瓶里插满小小森林\n青春嫩绿得很鲜明\n百叶窗折射的光影\n像有着心事的一张表情\n而你低头拆信\n想知道关于我的事情\n青苔入镜檐下风铃\n摇晃曾经\n回忆是一行行\n无从剪接的风景\n爱始终年轻\n而我听见下雨的声音\n想起你用唇语说爱情\n幸福也可以很安静\n我付出一直很小心\n终于听见下雨的声音\n于是我的世界被吵醒\n就怕情绪红了眼睛\n不舍的泪在彼此的脸上透明\n爱在过境缘份不停\n谁在担心\n窗台上滴落的雨滴\n轻敲着伤心凄美而动听\n而我听见下雨的声音\n想起你用唇语说爱情\n热恋的时刻最任性\n不顾一切的给约定\n终于听见下雨的声音\n于是我的世界被吵醒\n发现你始终很靠近\n默默的陪在我身边\n态度坚定', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (141, '141', '1', '床边故事', '周杰伦', '方文山', '黄雨勋', '哥特摇滚/电子 (Gothic Rock/Electronic)', '为女儿创作的“黑暗童话”，编曲阴森奇幻，融合电子与摇滚', '十四', '2016-06-24', '周杰伦的床边故事', '从前从前有只猫头鹰 它站在屋顶\n屋顶后面一片森林 森林很安静\n安静的钢琴在大厅 阁楼里 仔细听\n仔细听 叮叮叮 什么声音\n乖乖睡 不要怕 听我说\n乖乖睡 醒来就 吃苹果\n不睡觉 的时候 有传说\n会有人 咬你的 小指头\n这故事 继续翻页 再翻页\n你继续 不想睡 我却想睡\n然后我准备 去打开衣柜\n去看看 躲着谁 去看看 躲着谁\n纸上的 城堡卡片 发光的 立体呈现\n奇幻的 床边故事 动听的 令人称羡\n场景瞬间变化 我接着又施展魔法\n活过来说话 准备开始吧\n等天黑 一起倒数后关上灯\n三二一 入梦境 的缤纷\n我们并 非正常人 游戏怎么会 照剧本 Oh\n天黑 一起来关上灯\n三二一 进自由 的灵魂\nOhohohoh oh～come on～再回童年 敲敲门\n滴哒滴哒突然开始摆动 墙上老挂钟\n古董油画 出现诡异的笑容\n好的巫婆坏掉的苹果 愿望要跟谁说\n旋转的 音乐盒 我竖起 耳朵听\n这不会 是一场 梦Oh梦～\n一下子瞬间跳跃 我翻阅下个世界\n满满都是蝴蝶(森林满满蝴蝶 窗外纷飞着雪 一觉醒来旁边躺着是谁)\n这故事 继续翻页 再翻页\n你继续 不想睡 我却想睡\n然后我准备 去打开衣柜\n去看看 躲着谁 去看看 躲着谁\n纸上的 城堡卡片 发光的 立体呈现\n奇幻的 床边故事 动听的 令人称羡\n场景瞬间变化 我接着又施展魔法\n活过来说话 准备开始吧\n等天黑 一起倒数后关上灯\n三二一 入梦境 的缤纷\n我们并 非正常人 游戏怎么会 照剧本 Oh\n天黑 一起来关上灯\n三二一 进自由 的灵魂\nOhohohoh oh～come on～再回童年 敲敲门\n乖乖睡啊 不要害怕\n乖乖睡醒来就吃苹果啊\n不睡觉啊 有传说啊\n会有人咬你的小指头啊\n等天黑 一起倒数后关上灯\n三二一 入梦境 的缤纷\n我们并 非正常人 游戏怎么会 照剧本 Oh\n天黑 一起来关上灯\n三二一 进自由 的灵魂\nOhohohoh oh～come on～再回童年 敲敲门\n再回童年 敲敲门', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (142, '142', '2', '说走就走', '周杰伦', '方文山', '黄雨勋', '流行摇滚/舞曲 (Pop Rock/Dance)', '节奏强劲，充满旅行的冲动与自由感', '十四', '2016-06-24', '周杰伦的床边故事', '伸出手 搭便车 唱着歌 弹着斑鸠\n不远处沙漠 我们才刚刚经过\n路两旁是单调的颜色\n却有种辽阔的快乐 我还记得\n边走边说边牵着你手\n边弹边唱边微笑看我\n你的侧脸逆着光 背对夕阳\n你轮廓像幅画 看久会融化\nWhat\'s up 开始牵挂\n我将所有的感觉用诗写下\n细腻描述你的长发\n以及歌词里要对你说的话\n当暧昧慢慢酝酿 心动的频率抽象\n我的心 只能够 容纳你的模样\n真爱让人拥有力量\n你我都该勇敢 率性放下一切别管 Oh\n跟着我 对天上星星 喊爱你的证明\n这就是年轻 该潇洒一次的决定\n说走就走的旅行 Oh\n跟着我 数天上星星 再一起等黎明\n无边的风景 风呼啸的声音 爱\n一路守护着约定\n伸出手 搭便车 唱着歌 弹着斑鸠\n不远处沙漠 我们才 刚刚经过\n路两旁是单调的颜色\n却有种辽阔的快乐 我还记得\n边走边说边牵着你手\n边弹边唱边微笑看我\n你的侧脸逆着光 背对夕阳\n你轮廓像幅画 看久会融化\nWhat\'s up 开始牵挂\n我将所有的感觉用诗写下\n细腻描述你的长发\n以及歌词里要对你说的话\n当暧昧慢慢酝酿 心动的频率抽象\n我的心 只能够 容纳你的模样\n真爱让人拥有力量\n你我都该勇敢 率性放下一切别管 Oh\n跟着我 对天上星星 喊爱你的证明\n这就是年轻 该潇洒一次的决定\n说走就走的旅行 Oh\n跟着我 数天上星星 再一起等黎明\n无边的风景 风呼啸的声音 爱\n一路守护着约定\n跟着我 对天上星星 喊爱你的证明\n这就是年轻 该潇洒一次的决定\n说走就走的旅行 Oh\n跟着我 数天上星星 再一起等黎明\n无边的风景 风呼啸的声音 爱\n一路守护着约定 Oh', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (143, '143', '3', '一点点', '周杰伦', '方文山', '黄雨勋', '抒情流行 (Ballad Pop)（与A-Lin合唱）', '旋律温柔，表达爱情中细微的感动与累积', '十四', '2016-06-24', '周杰伦的床边故事', '几次争辩 几次的失眠\n而我却 视而不见\n从不 先说抱歉\n工作优先 跟朋友见面\n永远多过给你 的时间\n那亏欠 一直 放在心里面\n没能说出口 你已走远\n抱紧你 却抓不住 你的爱剩 一点点\n那一天 你几乎带走我 所有 的从前\n你说我 根本没有因为爱你 而改变\n我始终听不进 你的劝\n想吃甜点 想去电影院\n而我却 都嫌太远\n你在 委曲埋怨\n我连生日 都忘记敷衍\n却只会要你乖 一点点\n那亏欠 一直 放在心里面\n没能说出口 你已走远\n抱紧你 却抓不住 你的爱剩 一点点\n那一天 你几乎带走我 所有 的从前\n故事里 不再出现与你相关 的画面\n一个人的幸福 怎么编\n面对面 泪滑落在彼此的脸 那瞬间\n不再让你离开 我身边', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (144, '144', '4', '前世情人', '周杰伦、Hathaway', '黄俊郎', '黄雨勋', '古典/流行 (Classical/Pop)', '为女儿创作，前奏改编自肖邦《降E大调夜曲》，旋律优美纯净', '十四', '2016-06-24', '周杰伦的床边故事', '松鼠陪着核桃\n在庭院捉迷藏\n葡萄躲进橡木桶\n酿出时光\n夏日在玉米齿缝中游荡\n我为妳准备的四季\n正在生长\n炼金师从故事炼出土壤\n我阖上书也闻到了花香\n草地上的你比果实芬芳\n妳就像天使手里的糖\n小男孩害羞没想起\n自己是个雕像\n沉浸在芦苇跟风合奏\n用美妙歌声赞扬\n世界因为你而露出\n阳光灿烂的形状\n谢谢妳不然纯真是什么\n我早已经遗忘\n什么爱 不说 就已经存在\n什么爱 望着 就全都明白\n妳笑 一点一点一滴漾开\n一字一句形容不来\n是星空上的银海\n月晕下的双手\n越来越来越来 越依靠\n从来从来从来 不知道\n原来原来原来 有妳很骄傲\n小公主\n过来过来过来 约定好\n未来未来未来 的城堡\n将来将来将来 我们一起造\n我会当你昼夜骑士\n烈阳的树荫\n让花朵为妳吟游的魔术师\n每一道有妳风景\n帮妳按下快门的秘密情人\n什么爱 不说 就已经存在\n什么爱 望着 就全都明白\n妳笑 一点一点一滴漾开\n一字一句形容不来\n是星空上的银海\n我后来 会在 纯白的礼堂\n牵好久 的手 交给另个他\n眼泪一点一点一滴流下\n感动也会跟着留下\n远远看着妳们幸福\n像前世我们有过的模样', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (145, '145', '5', '英雄', '周杰伦', '周杰伦', '黄雨勋', '游戏主题曲/流行摇滚 (Game Theme/Pop Rock)', '为游戏《英雄联盟》创作，编曲宏大，充满英雄气概', '十四', '2016-06-24', '周杰伦的床边故事', '人生不是一个人的游戏\n一起奋斗一起超越\n一起杀吧sup兄弟\n好战好胜战胜逆命\n管他天赋够不够\n我们都还需要再努力\n你的剑就是我的剑\n艾希的箭可不可以准一点嘿\n你打野我来控兵线\n不要随便慌张就交闪现\n旋转跳跃你闭着眼\n卡特转完会让你闭上眼\n悟空盖伦也转圈圈\n盲僧李先生一脚把你踢回老家\n击杀 双杀 三杀\nPenta kill\n扛塔 偷拆 插眼让我传送\n击杀 双杀 三杀\nPenta kill\n迎接 胜利 最后让我收头\n剑圣易大师的冥想\n就像紧箍咒的碎念\n问你出门有没带眼\n不是骂你有没长眼\n皇子嘉文不就是我黄金甲\n那傲气的脸\n让你画面一直呈现\n卓别林的黑白默片\n请不要在观战模式偷窥着我\n我的专情不可能被那阿狸魅惑\n别学我跳牛仔很忙好吗狗头\n不要动不动逆风你们就20想投\n旋转跳跃你闭着眼\n卡特转完会让你闭上眼\nEZ EZ 要你easy\n小鱼人再跳\n我就把你\n切成生鱼片\n击杀 双杀 三杀\nPenta kill\n扛塔 偷拆 插眼让我传送\n击杀 双杀 三杀\nPenta kill\n迎接 胜利 最后让我收头\n击杀 双杀 三杀\nPenta kill\n扛塔 偷拆 插眼让我传送\n击杀 双杀 三杀\nPenta kill\n迎接 胜利 最后让我收头', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (146, '146', '6', '不该', '周杰伦', '方文山', '黄雨勋', '抒情流行 (Ballad Pop)（与张惠妹合唱）', '两位天王天后对唱，旋律悲伤，讲述一段不该开始的爱情', '十四', '2016-06-24', '周杰伦的床边故事', '假装我们还在 一块\n我真的演 不出来\n还是不习惯你 不在\n这身份转变 太快\n画面里不需要 旁白\n却谁都看 的出来\n是我情绪涌了 上来\n想哭却一遍 空白\n雪地里相爱\n他们说零下\n已结晶的誓言 不会坏\n但爱的状态\n却不会永远\n都冰封而透明 的存在\n轻轻飘 落下来\n许下的梦 融化的太快\n或许我们都 不该醒来\n你还是住在我的回忆里 不出来\n让我们微笑离开\n让故事 留下来\n放手后 爱依然在\n雪融了 就应该花开\n缘若尽了 就不该再重来\n你依旧住在我的回忆里 不出来\n我离开将你的手\n交给下个 最爱\n纠缠与 固执等待\n反而是 另一种伤害\n彼此紧握的手松开\n去拥抱更多未来\n错过的时间怎 么买\n谁都付 不出来\n或许我们学会 释怀\n让过去安静 下来\n雪地里相爱\n他们说零下\n已结晶的誓言 不会坏\n但爱的状态\n却不会永远\n都冰封而透明 的存在\n轻轻飘 落下来\n许下的梦 融化的太快\n或许我们都 不该醒来\n你还是住在我的回忆里 不出来\n让我们微笑离开\n让故事 留下来\n放手后 爱依然在\n雪融了 就应该花开\n缘若尽了 就不该再重来\n你依旧住在我的回忆里 不出来\n我离开将你的手\n交给下个 最爱\n纠缠与 固执等待\n反而是 另一种伤害\n彼此紧握的手松开\n去拥抱更多未来', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (147, '147', '7', '土耳其冰淇淋', '周杰伦', '周杰伦', '周杰伦', '世界音乐/放克 (World Music/Funk)', '融合土耳其音乐元素与放克节奏，展现高超的音乐技巧与玩乐精神', '十四', '2016-06-24', '周杰伦的床边故事', 'OS：\nHello 我是DJ巨炮\n接下来为您播放的是\n舞曲也可以很有音乐性的\nMara? dondurmas?\n土耳其冰淇淋 就像是女人的心\n在你的面前转来转去 却捉摸不定\n这音乐跳Waacking也可以跳Locking\n我耍你耍的就像土耳其的冰淇淋\n几个高级和弦 几个切分音\n我写的舞曲也可以很有音乐性\n就像卖个冰 还能秀杂技\n你最好期许如果你跟我一样努力\n换个乐器就像换个兵器\n电吉它这个时候出来干嘛 到底\n你猜不透也想不到摸不着头绪\n我总是为了什么出奇不意 到底\n谁说拍中国风 一定要配灯笼\n谁说写中国风 一定要商角徵羽宫\n我干脆自己下车 指挥乐坛的交通\n管他管他什么曲风\n土耳其冰淇淋\n土耳其冰淇淋\n土耳其冰淇淋\n土耳其冰淇淋\n加一点 土耳其进行曲 太丰富的编曲\n吃一口冰淇淋来融化你的伤心\n仔细听 几个半音 有点拉丁 有点热情\n那是我想要给的惊喜\n几个高级和弦 几个切分音\n我写的舞曲也可以很有音乐性\n就像卖个冰 还能秀杂技\n你最好期许如果你跟我一样努力\n换个乐器就像换个兵器\n电吉它这个时候出来干嘛 到底\n你猜不透也想不到摸不着头绪\n我总是为了什么出奇不意 到底\n谁说拍中国风 一定要配灯笼\n谁说写中国风 一定要商角徵羽宫\n我干脆自己下车 指挥乐坛的交通\n管他管他什么曲风\n土耳其冰淇淋\n土耳其冰淇淋\n土耳其冰淇淋\n土耳其冰淇淋\n土耳其冰淇淋\n土耳其冰淇淋\n土耳其冰淇淋\n土耳其冰淇淋', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (148, '148', '8', '告白气球', '周杰伦', '方文山', '林迈可', '法式香颂/流行 (French Chanson/Pop)', '旋律浪漫轻盈，描绘巴黎街头的甜蜜告白，是周杰伦最流行的“小甜歌”之一', '十四', '2016-06-24', '周杰伦的床边故事', '塞纳河畔 左岸的咖啡\n我手一杯 品尝你的美\n留下唇印的嘴\n花店玫瑰 名字写错谁\n告白气球 风吹到对街\n微笑在天上飞\n你说你有点难追\n想让我知难而退\n礼物不需挑最贵\n只要香榭的落叶\n喔 营造浪漫的约会\n不害怕搞砸一切\n拥有你就拥有全世界\n亲爱的 爱上你\n从那天起\n甜蜜的很轻易\n亲爱的 别任性\n你的眼睛\n在说我愿意\n塞纳河畔 左岸的咖啡\n我手一杯 品尝你的美\n留下唇印的嘴\n花店玫瑰 名字写错谁\n告白气球 风吹到对街\n微笑在天上飞\n你说你有点难追\n想让我知难而退\n礼物不需挑最贵\n只要香榭的落叶\n喔 营造浪漫的约会\n不害怕搞砸一切\n拥有你就拥有 全世界\n亲爱的 爱上你\n从那天起\n甜蜜的很轻易\n亲爱的 别任性\n你的眼睛\n在说我愿意\n亲爱的 爱上你\n恋爱日记\n飘香水的回忆\n一整瓶 的梦境\n全都有你\n搅拌在一起\n亲爱的别任性\n你的眼睛\n在说我愿意', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (149, '149', '9', 'Now You See Me', '周杰伦', '方文山', '黄雨勋', '电子/舞曲 (Electronic/Dance)', '为电影《惊天魔盗团》创作，节奏神秘快速，营造魔术氛围', '十四', '2016-06-24', '周杰伦的床边故事', '我的幻术是超能力\n我天生神力\n你的魔术要靠道具\n还真不给力\n你话术耍耍嘴皮\n声东击西\n分散注意\n我根本不理\n省点力气\n你还真有耐性\n啊玩一玩纸牌\n消失了钱币\n手里变出白鸽都是小朋友的把戏\n猜你应该使用了障眼的把戏\n不然你看一看你旁边的观众\n他们都跑到哪去\n出神入化\n雾里看花\n跟我拼命你会输掉所有筹码\n出神入化\n浪迹天涯\n认真起来我连我自己都害怕\nNow you see me cuz I let it be\nWanna find the key you gotta follow my beat\nNow you see me cuz I let it be\n我的幻术存在但看不见证据\nNow you see me cuz I let it be\nWanna find the key you gotta follow my beat\nNow you see me cuz I let it be\n我的幻术让你沉迷看穿你\nOne two three four\nOne two three four\n倒数计时\n睁开眼\n置身在不同的城市\nOne more two more\nOne more two more\n你看不见我\n看不见我\n看不见我\n看不见我\n看不见我\n难度就像乌龟翻跟斗\n看不见我\n你就是扶不起的阿斗\n看不见我\n不然你早已跟我握手\n看不见我\n万一看见的人是只小狗\n出神入化\n雾里看花\n跟我拼命你会输掉所有筹码\n出神入化\n浪迹天涯\n认真起来我连我自己都害怕\nNow you see me cuz I let it be\nWanna find the key you gotta follow my beat\nNow you see me cuz I let it be\n我的幻术存在但看不见证据\nNow you see me cuz I let it be\nWanna find the key you gotta follow my beat\nNow you see me cuz I let it be\n我的幻术让你沉迷看穿你', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (150, '150', '10', '爱情废柴', '周杰伦', '周杰伦', '黄雨勋', '抒情流行 (Ballad Pop)', '自嘲在爱情中无能，旋律悲伤，情感真挚', '十四', '2016-06-24', '周杰伦的床边故事', '圣诞节 剩下单人的剩单节\n过条街 最好又给我下起雪\n这么衰 这么刚好 这么狼狈\n要不要拍成MV干脆\n淡淡忧伤还是最美\n剧情是你在写 有点无解 我们之间\n踏着雪 不知不觉走了很远\n绕着圈 我叛逆点起一根烟\n一整天 我旋律哼了一千遍\n千遍一律我不醉不归\n没有你的冬天\n我会一直唱着唱着\n直到你出现\n为你封麦 只唱你爱\nGoodbye Don\'t Cry 哭个痛快\n曲终人散 你也走散\n我承认我是爱情里的废柴\n你的离开 喊得太快\n我的依赖 还在耍赖\n眼泪打转 转不回来\n你的笑容灿烂\n踏着雪 不知不觉走了很远\n绕着圈 我叛逆点起一根烟\n一整天 我旋律哼了一千遍\n千遍一律我不醉不归\n没有你的冬天\n我会一直唱着唱着\n直到你出现\n为你封麦 只唱你爱\nGoodbye Don\'t Cry 哭个痛快\n曲终人散 你也走散\n我承认我是爱情里的废柴\n你的离开 喊得太快\n我的依赖 还在耍赖\n眼泪打转 转不回来\n你的笑容灿烂\n为你封麦 只唱你爱\nGoodbye Don\'t Cry 哭个痛快\n曲终人散 你也走散\n我承认我是爱情里的废柴\n你的离开 喊得太快\n我的依赖 还在耍赖\n眼泪打转 转不回来\n你的笑容灿烂', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (151, '151', '1', 'Intro', '周杰伦', '/', '黄雨勋', '纯音乐/氛围 (Instrumental/Ambient)', '专辑《周杰伦的床边故事》的开场，营造神秘氛围', '十五', '2022-07-14', '最伟大的作品', NULL, '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (152, '152', '2', '最伟大的作品', '周杰伦', '黄俊郎、谢迪', '黄雨勋', '古典/流行/说唱 (Classical/Pop/Rap)', '向艺术大师致敬，融合古典名曲采样、钢琴演奏与说唱，编曲复杂华丽', '十五', '2022-07-14', '最伟大的作品', '哥穿着复古西装\n拿着手杖 弹着魔法乐章\n漫步走在 莎玛丽丹\n被岁月 翻新的时光\n望不到边界的帝国\n用音符筑成的王座\n我用琴键穿梭 1920错过的不朽\n啊 偏执是那马格利特\n被我变出的苹果\n超现实的是我\n还是他原本想画的小丑\n不是烟斗的烟斗\n脸上的鸽子没有飞走\n请你记得\n他是个画家不是什么调酒\n达利翘胡是谁给他的思索\n弯了汤匙借你灵感不用还我\n融化的是墙上时钟还是乳酪\n龙虾电话那头你都不回我\n浪荡是世俗画作里最自由不拘的水墨\n花都优雅的双腿是这宇宙笔下的一抹\n飘洋过海的乡愁种在一无所有的温柔\n寂寞的枝头才能长出 常玉要的花朵\n小船静静往返\n马谛斯的海岸\n星空下的夜晚\n交给梵谷点燃\n梦美的太短暂\n孟克桥上呐喊\n这世上的热闹\n出自孤单\n花园流淌的阳光\n空气摇晃着花香\n我请莫内帮个忙\n能不能来张自画像\n大师眺望着远方\n研究色彩的形状\n突然回头要我说说\n我对我自己的印象\n世代的狂\n音乐的王\n万物臣服在我乐章\n路还在闯\n我还在创\n指尖的旋律在渴望\n世代的狂\n音乐的王\n我想我不需要画框\n它框不住\n琴键的速度\n我的音符\n全部是未来艺术\n日出在印象的港口来回\n光线唤醒了睡着的花叶\n草地正为一场小雨欢悦\n我们彼此深爱这个世界\n停在康桥上的那只蝴蝶\n飞往午夜河畔的翡冷翠\n遗憾被偶然藏在了诗页\n是微笑都透不进的世界\n巴黎的鳞爪\n感伤的文法\n要用音乐翻阅\n晚风的灯下\n旅人的花茶\n我换成了咖啡\n之后他就\n爱上了苦涩这个复杂词汇\n因为这才是挥手\n向云彩道别的滋味\n小船静静往返\n马谛斯的海岸\n星空下的夜晚\n交给梵谷点燃\n梦美的太短暂\n孟克桥上呐喊\n这世上的热闹\n出自孤单', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (153, '153', '3', '还在流浪', '周杰伦', '方文山', '黄雨勋', '中国风/抒情 (Chinese Style/Ballad)（与派伟俊合唱）', '延续江湖漂泊主题，旋律苍凉，充满沧桑感', '十五', '2022-07-14', '最伟大的作品', '老书摊 和啤酒空罐\n散落地上\n报废的回忆在路旁\n有了锈斑\n有某种无所谓\n在这小镇弥漫\n这个城市步调\n是如此的缓慢\n霓虹灯闪烁的倒影\n靠在窗上\n错过美好的那时光\n能否再遇上\n老旧的车站 空旷的车厢\n怀念从前的人来人往\n招牌的灯泡 在夜里微亮\n过去的背包 就留在异乡\n于是我决定 离开这个地方\n当你收到信 我还在流浪\n那年的约定 都放在心上\n随身的照片里\n你微笑的模样\n亲爱的 你现在怎么样\n当你收到信 我还在流浪\n想起牵着手 走过的小巷\n我依然记得\n年少初吻的那教堂\n还有一起画爱心的那道墙\n霓虹灯闪烁的倒影\n靠在窗上\n错过美好的那时光\n能否再遇上\n老旧的车站 空旷的车厢\n怀念从前的人来人往\n招牌的灯泡 在夜里微亮\n过去的背包 就留在异乡\n于是我决定 离开这个地方\n当你收到信 我还在流浪\n那年的约定 都放在心上\n随身的照片里\n你微笑的模样\n亲爱的 你现在怎么样\n当你收到信 我还在流浪\n想起牵着手 走过的小巷\n我依然记得\n年少初吻的那教堂\n还有一起画爱心的那道墙\n当你收到信 我还在流浪\n那年的约定 都放在心上\n随身的照片里\n你微笑的模样\n亲爱的 你现在怎么样\n当你收到信 我还在流浪\n想起牵着手 走过的小巷\n我依然记得\n年少初吻的那教堂\n还有一起画爱心的那道墙', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (154, '154', '4', '说好不哭', '周杰伦', '方文山', '黄雨勋', '抒情流行 (Ballad Pop)（与五月天阿信合唱）', '旋律抓耳，讲述成全与遗憾的爱情故事，引发巨大共鸣', '十五', '2022-07-14', '最伟大的作品', '周杰伦：\n没有了联络 后来的生活\n我都是听别人说\n说你怎么了 说你怎么过\n放不下的人是我\n人多的时候 就待在角落\n就怕别人问起我\n你们怎么了 你低着头\n护着我连抱怨都没有\n电话开始躲 从不对我说\n不习惯一个人生活\n离开我以后 要我好好过\n怕打扰想自由的我\n都这个时候 你还在意着\n别人是怎么怎么看我的\n拼命解释着 不是我的错 是你要走\n眼看着你难过 挽留的话却没有说\n你会微笑放手 说好不哭让我走\n阿信：\n电话开始躲 从不对我说\n不习惯一个人生活\n离开我以后 要我好好过\n怕打扰想自由的我\n都这个时候 你还在意着\n别人是怎么怎么看我的\n拼命解释着 不是我的错 是你要走\n合：\n眼看着你难过 挽留的话却没有说\n你会微笑放手 说好不哭让我走\n周杰伦：\n你什么都没有 却还为我的梦加油\n阿信：\n心疼过了多久\n周杰伦：\n过了多久\n合：\n还在找理由等我', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (155, '155', '5', '红颜如霜', '周杰伦', '方文山', '黄雨勋', '中国风 (Chinese Style)', '融合京剧元素，歌词文雅，旋律凄美，是“宇谋联姻”单曲', '十五', '2022-07-14', '最伟大的作品', '信札拆封谁为难 不过寥寥数行\n娟秀字迹温柔 却感伤\n妳将心事 上了淡妆\n该说的话 却被仔细收藏\n暮色望垂杨 拱桥粼粼月光\n忆往事我走笔 也阑珊\n红颜如霜 凝结了过往\n芦苇花开岁已寒\n若霜又降路遥漫长\n墙外是谁在吟唱 凤求凰\n梨园台上 西皮二黄\n却少了妳 无人问暖\n谁在彼岸 天涯一方\n一句甚安勿念 妳说落笔太难\n窗外古琹幽兰 琴声平添孤单\n我墨走了几行 泪潸然落了款\n思念徒留纸上 一整篇被晕染\n一句甚安勿念 妳说落笔太难\n何故远走潇湘 妳却语多委婉\n走过萧瑟秋凉 等来芒草催黄\n而我遥望轻轻叹\n信札拆封谁为难 不过寥寥数行\n娟秀字迹温柔 却感伤\n妳将心事 上了淡妆\n该说的话 却被仔细收藏\n捎来的他乡 到底隔几条江\n一封信到底转了 几道弯\n缘分飘落 在山外山\n芦苇花开岁已寒\n若霜又降路遥漫长\n墙外是谁在吟唱 凤求凰\n梨园台上 西皮二黄\n却少了妳 无人问暖\n谁在彼岸 天涯一方\n一句甚安勿念 妳说落笔太难\n窗外古琹幽兰 琴声平添孤单\n我墨走了几行 泪潸然落了款\n思念徒留纸上 一整篇被晕染\n一句甚安勿念 妳说落笔太难\n何故远走潇湘 妳却语多委婉\n走过萧瑟秋凉 等来芒草催黄\n而我遥望轻轻叹\n一句甚安勿念 妳说落笔太难\n妳说落笔太难\n窗外古琹幽兰 琴声平添孤单\n琴声平添孤单\n我墨走了几行 泪潸然落了款\n泪潸然落了款\n思念徒留纸上 一整篇被晕染\n一句甚安勿念 妳说落笔太难\n何故远走潇湘 妳却语多委婉\n走过萧瑟秋凉 等来芒草催黄\n而鱼雁不再往返', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (156, '156', '6', '不爱我就拉倒', '周杰伦', '周杰伦、宋健彰', '陈思翰、黄雨勋', 'R&B/流行 (R&B/Pop)', '歌词直白，带有美式R&B的慵懒与随性', '十五', '2022-07-14', '最伟大的作品', '寒流来了 刚好\n刚好可以 把你手放外套\n把安全帽戴好\n不让你在 爱情路上跌倒\n加速狂飙 你说不要\n爱的险你不想冒\n不想被套牢\n他的怀抱 真比我好\n你幸福就好\n不爱我就拉倒\n离开之前\n不要爱的抱抱\n反正 我又不是没有人要\n哥练的胸肌\n如果你还想靠\n好胆你就麦造\n寒流来了 刚好可以把你手放外套\n把安全帽戴好\n不要在爱情路上跌倒\n加速狂飙 你 你说不要\n爱的险你不想冒\n不想被我给套牢\n反正我又不是没有人要\n哥练的胸肌如果你还想靠\n算了 你幸福你幸福就好\n寒流来了 刚好\n刚好可以 把你手放外套\n把安全帽戴好\n不让你在 爱情路上跌倒\n加速狂飙 你说不要\n爱的险你不想冒\n不想被套牢\n他的怀抱 真比我好\n你幸福就好\n不爱我就拉倒\n离开之前\n不要爱的抱抱\n反正 我又不是没有人要\n哥练的胸肌\n如果你还想靠\n好胆你就麦造\n你幸福就好\n不爱我就拉倒\n离开之前\n不要爱的抱抱\n反正 我又不是没有人要\n哥练的胸肌\n如果你还想靠\n好胆你就麦造', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (157, '157', '7', 'Mojito', '周杰伦', '黄俊郎', '黄雨勋', '拉丁/爵士 (Latin/Jazz)', '以古巴鸡尾酒Mojito为灵感，充满拉丁节奏与爵士风情，轻松欢快', '十五', '2022-07-14', '最伟大的作品', '麻烦给我的爱人来一杯Mojito\n我喜欢阅读她微醺时的眼眸\n而我的咖啡 糖不用太多\n这世界已经因为她甜得过头\n没有跟她笑容一样浓郁的雪茄\n就别浪费时间介绍收起来吧\n拱廊的壁画 旧城的涂鸦\n所有色彩都因为她说不出话\n这爱不落幕 忘了心事的国度\n你所在之处 孤单都被征服\n铁铸的招牌 错落着就像\n一封封城市 献给天空的情书\n当街灯亮起 Havana漫步\n这是世上最美丽的那双人舞\n缤纷的老爷车 跟着棕榈摇曳\n载着海风私奔漫无目的\n古董书摊漫着时光香气\n我想 上辈子 是不是就遇过你\n喧嚣的海报躺在 慵懒的阁楼阳台\n而你是文学家笔下的那一片海\n麻烦给我的爱人来一杯Mojito\n我喜欢阅读她微醺时的眼眸\n而我的咖啡 糖不用太多\n这世界已经因为她甜得过头\n这爱不落幕 忘了心事的国度\n你所在之处 孤单都被征服\n铁铸的招牌 错落着就像\n一封封城市 献给天空的情书\n当街灯亮起 Havana漫步\n这是世上最美丽的那双人舞\n铁铸的招牌 错落着就像\n一封封城市 献给天空的情书\n当街灯亮起 Havana漫步\n这是世上最美丽的那双人舞', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (158, '158', '8', '错过的烟火', '周杰伦', '方文山', '黄雨勋', '抒情流行 (Ballad Pop)', '旋律优美，表达对逝去时光与爱情的追忆', '十五', '2022-07-14', '最伟大的作品', '明信片的邮戳 就当纪念过往的生活\n那夕阳像野火 在地平线远方燃烧着\n执着 懦弱 其实都是一部分的我\n而你却说我不够洒脱 或许该放手\n一路上我开着车 迎风横越了沙丘\n偏僻的山路我走 望着峡谷的天空\n还有什么 还 还有还有什么\n风景还没写 还没写成小说\n风呼啸而过 却没有带走寂寞\n这条路没有尽头 我还是会继续走\n许下的承诺 或许在多年以后\n我还在漂泊 你是错过的烟火\n等风沙过后 才知道失去什么\n世界太辽阔 将你的消息淹没\n空旷的沙漠 只剩下回忆经过\n属于谁的自由\n明信片的邮戳 就当纪念过往的生活\n那夕阳像野火 在地平线远方燃烧着\n执着 懦弱 其实都是一部分的我\n而你却说我不够洒脱 或许该放手\n一路上我开着车 迎风横越了沙丘\n偏僻的山路我走 望着峡谷的天空\n还有什么 还 还有还有什么\n风景还没写 还没写成小说\n风呼啸而过 却没有带走寂寞\n这条路没有尽头 我还是会继续走\n许下的承诺 或许在多年以后\n我还在漂泊 你是错过的烟火\n等风沙过后 才知道失去什么\n世界太辽阔 将你的消息淹没\n空旷的沙漠 只剩下回忆经过\n属于谁的自由\n我还在漂泊 你是错过的烟火\n等风沙过后 才知道失去什么\n世界太辽阔 将你的消息淹没\n空旷的沙漠 只剩下回忆经过\n属于谁的自由', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (159, '159', '9', '等你下课', '周杰伦', '周杰伦', '黄雨勋', '校园民谣/流行 (School Folk/Pop)（与杨瑞代合唱）', '描绘校园暗恋，旋律清新，充满青春气息', '十五', '2022-07-14', '最伟大的作品', 'Jay：你住的 巷子里\n我租了一间公寓\n为了想与你不期而遇\n高中三年 我为什么\n为什么不好好读书\n没考上跟你一样的大学\n我找了份工作\n离你宿舍很近\n当我开始学会做蛋饼\n才发现你 不吃早餐\n喔 你又擦肩而过\n你耳机听什么\n能不能告诉我\n合：躺在你学校的操场看星空\n教室里的灯还亮着你没走\n记得 我写给你的情书\n都什么年代了\n到现在我还在写着\n总有一天总有一年会发现\n有人默默的陪在你的身边\n也许 我不该在你的世界\n当你收到情书\n也代表我已经走远\nGary：学校旁 的广场\n我在这等钟声响\n等你下课一起走好吗\nJay：弹着琴 唱你爱的歌\n暗恋一点都不痛苦\nGary：一点都不痛苦\nJay：痛苦的是你\n合：根本没看我\nJay：我唱这么走心\nGary：这么走心\nJay：却走不进你心里\nGary：进你心里\nJay：在人来人往\n合：找寻着你 守护着你\n不求结局\n合：喔\nGary：你又擦肩\n合：而过\nJay：我唱告白气球\n终于你回了头\n合：躺在你学校的操场看星空\n教室里的灯还亮着你没走\n记得 我写给你的情书\n都什么年代了\n到现在我还在写着\n总有一天总有一年会发现\n有人默默的陪在你的身边\n也许 我不该在你的世界\n当你收到情书\n也代表我已经走远', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (160, '160', '10', '粉色海洋', '周杰伦', '方文山', '黄雨勋', '流行/电子 (Pop/Electronic)', '轻快的电子流行曲，表达恋爱的幸福感', '十五', '2022-07-14', '最伟大的作品', 'O.S.：\nHi～小妞！ 要上我车吗？\n嗯～ 我很帅喔！\n准备好了吗？ 要去兜风吗？\n水面上蔚蓝色的船屋\n和长长的木板路\n像风景插图 细细描述\n旅行中的幸福\n喔你的微笑是我\n欣赏世界的角度\n我专注的记着\n此刻甜甜的感觉 永不落幕\n这岛上的公路\n那微笑的袋鼠\n我们一起呵护\n这场爱的旅途\n那告白的话说不清楚\n还在月球漫步\n你笑我这害羞的脸\n红通通像猴子光着屁股\n粉色海洋 你回头望\n笑得像天空里的棉花糖\n轻轻的尝 爱的模样\n我们的故事像梦一样\n粉色海洋 闪着夕阳\n那心动的时间被你拉长\n甜蜜果香 浓郁着愿望\n幸福就在有你的地方\n水面上蔚蓝色的船屋\n和长长的木板路\n像风景插图 细细描述\n旅行中的幸福\n喔你的微笑是我\n欣赏世界的角度\n我专注的记着\n此刻甜甜的感觉 永不落幕\n这岛上的公路\n那微笑的袋鼠\n我们一起呵护\n这场爱的旅途\n那告白的话说不清楚\n还在月球漫步\n你笑我这害羞的脸\n红通通像猴子光着屁股\n粉色海洋 你回头望\n笑得像天空里的棉花糖\n轻轻的尝 爱的模样\n我们的故事像梦一样\n粉色海洋 闪着夕阳\n那心动的时间被你拉长\n甜蜜果香 浓郁着愿望\n幸福就在有你的地方\n粉色海洋 你回头望\n笑得像天空里的棉花糖\n轻轻的尝 爱的模样\n我们的故事像梦一样\n粉色海洋 闪着夕阳\n那心动的时间被你拉长\n甜蜜果香 浓郁着愿望\n幸福就在有你的地方', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (161, '161', '11', '倒影', '周杰伦', '方文山', '黄雨勋', '抒情流行 (Ballad Pop)', '旋律悲伤，以“倒影”比喻逝去的爱情与自我反思', '十五', '2022-07-14', '最伟大的作品', '画框里的妳应该什么模样\n油画颜料散落在阁楼桌上\n与妳有关的一切我都画不完\n放下笔安静的想起一个地方\n午后庄园葡萄藤散发果香\n地窖的橡木桶酝酿起过往\n回忆年少有一种停格的美感\n想起了妳还有几年前的远方\n这石砌的老墙颜色斑驳着米黄\n当初的感觉已在石板路上走散\n推开了百叶窗\n妳剪影的背景有夕阳\n温暖柔美的光\n妳的倒影是我 带不走的风景\n就像居无定所 的云还在旅行\n这城墙外的世界 谁被放逐了眼泪\n我想再也没有谁 再也没有谁 能了解\n妳的倒影是我 带不走的风景\n故事只剩只剩 我一个人相信\n仰望天空之城 想起越走越远的我们\n午后庄园葡萄藤散发果香\n地窖的橡木桶酝酿起过往\n回忆年少有一种停格的美感\n想起了妳还有几年前的远方\n这石砌的老墙颜色斑驳着米黄\n当初的感觉已在石板路上走散\n推开了百叶窗\n妳剪影的背景有夕阳\n温暖柔美的光\n妳的倒影是我 带不走的风景\n就像居无定所 的云还在旅行\n这城墙外的世界 谁被放逐了眼泪\n我想再也没有谁 再也没有谁 能了解\n妳的倒影是我 带不走的风景\n故事只剩只剩 我一个人相信\n仰望天空之城 想起越走越远的我们\n妳的倒影是我 带不走的风景\n就像居无定所 的云还在旅行\n这城墙外的世界 谁被放逐了眼泪\n我想再也没有谁 再也没有谁 能了解\n妳的倒影是我 带不走的风景\n故事只剩只剩 我一个人相信\n仰望天空之城 想起越走越远的我们', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (162, '162', '12', '我是如此相信', '周杰伦', '方文山', '黄雨勋', '流行/励志 (Pop/Inspirational)', '为电影《天·火》创作，旋律激昂，充满信念感', '十五', '2022-07-14', '最伟大的作品', '鸟群离开了森林\n整座天空很灰心\n蝴蝶不再被吸引\n玫瑰盛开的很安静\n远方的风雨不停\n城市苍白而孤寂\n徘徊无助的人群\n焦虑着何时放晴\n故事里能毁坏的只有风景\n谁也摧毁不了我们的梦境\n弦月旁的流星划过了天际\n我许下 的愿望 该向谁 去说明\n陨石在浩瀚的宇宙间旅行\n璀璨的夜空里漫天的水晶\n我的祷告终于有了回音\n我是如此相信\n在背后支撑的是你\n一直与我并肩而行\n仰望等太阳升起\n听见鸟群回来的声音\n为我守候的人是你\n给了我坚定的信心\n双手弹奏出黎明\n原来爱如此的动听\n鸟群离开了森林\n整座天空很灰心\n蝴蝶不再被吸引\n玫瑰盛开的很安静\n远方的风雨不停\n城市苍白而孤寂\n徘徊无助的人群\n焦虑着何时放晴\n故事里能毁坏的只有风景\n谁也摧毁不了我们的梦境\n弦月旁的流星划过了天际\n我许下 的愿望 该向谁 去说明\n陨石在浩瀚的宇宙间旅行\n璀璨的夜空里漫天的水晶\n我的祷告终于有了回音\n我是如此相信\n在背后支撑的是你\n一直与我并肩而行\n仰望等太阳升起\n听见鸟群回来的声音\n为我守候的人是你\n给了我坚定的信心\n双手弹奏出黎明\n原来爱如此的动听\n我是如此相信\n在背后支撑的是你\n一直与我并肩而行\n仰望等太阳升起\n听见鸟群回来的声音\n为我守候的人是你\n给了我坚定的信心\n双手弹奏出黎明\n原来爱如此的动听', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (163, '163', '01', '世界末日', '周杰伦', '周杰伦', '周杰伦', '抒情摇滚 (Ballad Rock)', '早期创作，旋律悲伤，描绘世界末日下的孤独与绝望', 'e01', '2001-12-28', '范特西plus EP', '想笑 来伪装掉下的眼泪，点点头 承认自己会怕黑，我只求 能借一点的时间来陪，你却连同情都不给，想哭 来试探自己麻痹了没，全世界 好像只有我疲惫，无所谓 反正难过就敷衍走一回，但愿绝望和无奈远走高飞，天灰灰 会不会，让我忘了你是谁，夜越黑 梦违背，难追难回味，我的世界将被摧毁，也许事与愿违，累不累 睡不睡，单影无人相依偎，夜越黑 梦违背，有谁肯安慰，我的世界将被摧毁，也许颓废也是另一种美，想哭 来试探自己麻痹了没，全世界 好像只有我疲惫，无所谓 反正难过就敷衍走一回，但愿绝望和无奈远走高飞，天灰灰 会不会，让我忘了你是谁，夜越黑 梦违背，，难追难回味，我的世界将被摧毁，也许事与愿违，累不累 睡不睡，单影无人相依偎，夜越黑 梦违背，有谁肯安慰，我的世界将被摧毁，也许颓废也是另一种美……', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (164, '164', '02', '你比从前快乐', '周杰伦', '方文山', '周杰伦', '抒情流行 (Ballad Pop)', '关心 ex-lover 的近况，旋律温柔中带着感伤', 'e01', '2001-12-28', '范特西plus EP', '走在熙来攘往的街头\n你不再牵着我的手\n小心翼翼的将你小指勾\n泪也小心翼翼的流\n有些事情你在瞒着我\n你终于还是开了口\n淡淡一句 还是朋友\n泪也如刀割\n知道分手后你不难过\n你比从前快乐\n那祝福的话\n叫我如何能够说的出口\n那过往欢乐是否褪色\n想问你怎么舍得\n不要在耳边再说你会想我\n有些事情你在瞒着我\n你终于还是开了口\n小心翼翼的将你的小指勾\n我的手你不再牵着\n知道分手后\n你不难过\n你比从前快乐\n那祝福的话\n叫我如何能够说的出口\n过往的欢乐是否褪色\n想问你怎么舍得\n不要在耳边再说你会想我', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (165, '165', '03', '蜗牛', '周杰伦', '周杰伦', '周杰伦', '励志流行 (Inspirational Pop)', '为公益创作，旋律温暖，鼓励人们像蜗牛一样坚持前行', 'e01', '2001-12-28', '范特西plus EP', NULL, '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (166, '166', '01', '轨迹', '周杰伦', '黄俊郎', '钟兴民', '抒情流行 (Ballad Pop)', '旋律悲伤，是《寻找周杰伦》电影插曲，经典失恋情歌', 'e01', '2003-11-13', '寻找周杰伦 EP', '怎么隐藏 我的悲伤，失去你的地方，你的发香散得匆忙，我已经跟不上，闭上眼睛 还能看见，你离去的痕迹，在月光下一直找寻，那想念的身影，如果说分手是苦痛的起点，那在终点之前我愿意再爱一遍，想要对你说的不敢说的爱，会不会有人可以明白，我会发着呆然后忘记你，接着紧紧闭上眼，想着那一天会有人代替，让我不再想念你，我会发着呆然后微微笑，接着紧紧闭上眼，又想了一遍你温柔的脸，在我忘记之前，闭上眼睛 还能看见，你离去的痕迹，在月光下一直找寻，那想念的身影，如果说分手是苦痛的起点，那在终点之前我愿意再爱一遍，想要对你说的不敢说的爱，会不会有人可以明白，我会发着呆然后忘记你，接着紧紧闭上眼，想着那一天会有人代替，让我不再想念你，我会发着呆然后忘记你，接着紧紧闭上眼，想着那一天会有人代替，让我不再想念你，我会发着呆然后微微笑，接着紧紧闭上眼，又想了一遍你温柔的脸，在我忘记之前，心里的眼泪，模糊了视线，你已快看不见', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (167, '167', '02', '断了的弦', '周杰伦', '方文山', '钟兴民', '抒情流行 (Ballad Pop)', '旋律忧郁，表达爱情破裂后的痛苦', 'e02', '2003-11-13', '寻找周杰伦 EP', '断了的弦再怎么连，我的感觉你已听不见，你的转变像断掉的弦，再怎么接音都不对，你的改变我能够分辨，我沉默你的话也不多，我们之间少了什么不说 哎哟，微笑后表情终于有点难过，（握着你的手）问你决定了再走，我突然释怀地笑，笑声盘旋半山腰，随风在飘摇啊摇，来到你的面前绕，你泪水往下的掉说会记住我的好，我也弯起了嘴角笑，你的美已经给了谁，追了又追我要不回，我了解离开树的叶，属于地上的世界凋谢，断了的弦再弹一遍，我的世界你不在里面，我的指尖已经弹出茧，还是无法留你在我身边，断了的弦再怎么连，我的感觉你已听不见，你的转变像断掉的弦，再怎么接音都不对，你的改变我能够分辨，我沉默你的话也不多，我们之间少了什么不说 哎哟，微笑后表情终于有点难过，（握着你的手）问你决定了再走，我突然释怀的笑，笑声盘旋半山腰，随风在飘摇啊摇，来到你的面前绕，你泪水往下的掉说会记住我的好，我也弯着我嘴角笑，你的美已经给了谁，追了又追我要不回，我了解离开树的叶，属于地上的世界凋谢，断了的弦再弹一遍，我的世界你不在里面，我的指尖已经弹出茧，还是无法留你在我身边，断了的弦再怎么连，我的感觉你已听不见，你的转变像断掉的弦，再怎么接音都不对，你的改变我能够分辨', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (168, '168', '01', '漂移　（电影头文字D', '周杰伦', '方文山', '林迈可', '电子摇滚/舞曲 (Electro Rock/Dance)（电影《头文字D》插曲）', '同上文分析，节奏快，模拟赛车感', 'e03', '2005-06-24', '头文字D EP', '找支笔 写下日期 记录勇气，我可以 对着墙壁 让拳头叛逆，呼吸 天窗玻璃 打开我的身体，这里 引擎声就像是一种乐器，所以 风呼啸而过刺激，所以 我在转弯漂移，加足了马力 飚到底 看仔细，零到一百公里 谁敢与我为敌，我用第一人称 在漂移青春，输跟赢的分寸 计算得很精准，我踏上风火轮 在漂移青春，故事中的我们，在演自己的人生，(music)，胜败的对比 是残酷的可以，运气 从来就不在我这里，实力 没办法模拟，漂移 人车一体漂移，笑看后视镜的自己 啊，点火 继续 事关 荣誉，我除了第一 其他没有兴趣，得漂得漂得咿的漂，我安静地喝饮料轻松地笑，我用第一人称 在漂移青春，输跟赢的分寸 都计算得很准确，我踏上风火轮 在漂移青春，故事中的我们 在演自己的人生，得漂得漂得咿的漂，我绕过山腰雨声敲敲，得漂得漂得咿的漂，再开进隧道风声潇潇，我用第一人称 在漂移青春，输跟赢的分寸 都计算得很精准，我踏上风火轮 在漂移青春', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (169, '169', '02', '一路向北', '周杰伦', '方文山', '蔡科俊', '抒情摇滚 (Ballalad Rock)（电影《头文字D》插曲）', '同上文分析，悲情离别曲', 'e03', '2005-06-24', '头文字D EP', '后视镜里的世界，越来越远的道别，你转身向背，侧脸还是很美，　我用眼光去追，　竟听见你的泪，在车窗外面排徊，是我错失的机会，你站的方位，跟我中间隔着泪，街景一直在后退，你的崩溃在窗外零碎，我一路向北，离开有你的季节，你说你好累，已无法再爱上谁，　　风在山路吹，过往的画面，全都是我不对，细数惭愧我伤你几回，后视镜里的世界，越来越远的道别，你转身向背，侧脸还是很美，　我用眼光去追，　竟听见你的泪，在车窗外面排徊，是我错失的机会，你站的方位，跟我中间隔着泪，街景一直在后退，你的崩溃在窗外零碎，我一路向北，离开有你的季节，你说你好累，已无法再爱上谁，　　风在山路吹，过往的画面，全都是我不对，细数惭愧我伤你几回，　  我一路向北，离开有你的季节，方向盘周围，回转着我的后悔，我加速超越，却甩不掉紧紧跟随的伤悲，细数惭愧我伤你几回，停止狼狈就让错纯粹', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (170, '170', '01', '霍元甲', '周杰伦', '方文山', '洪敬尧', '中国风/嘻哈 (Chinese Style/Hip-Hop)', '融合京剧唱腔与说唱，展现民族气节，节奏强劲', 'e04', '2006-01-20', '霍元甲 EP', '呵 命有几回合 擂台等着 生死状 赢了什么 冷笑着<br>，天下谁的 第一又如何 止干戈 我辈尚武德<br>，我的 拳脚了得 却奈何 徒增虚名一个<br>，江湖难测 谁是强者 谁争一统武林的资格<br>，小城里岁月流过去 清澈的勇气<br>，洗涤过的回忆 我记得你 骄傲的活下去<br>，霍霍 霍霍霍 霍霍霍 霍家拳的套路招式灵活<br>，活活 活活活 活活活 活着生命就该完整渡过<br>，过过 过过过 过过过 过错软弱从来不属于我<br>，我我 我我我 我我我 我们精武出手无人能躲<br>，呵 命有几回合 擂台等着 生死状 赢了什么 冷笑着<br>，天下谁的 第一又如何 止干戈 我辈尚武德<br>，我的 拳脚了得 却奈何 徒增虚名一个<br>，江湖难测 谁是强者 谁争一统武林的资格<br>，小城里岁月流过去 清澈的勇气 <br>，洗涤过的回忆 我记得你 骄傲的活下去<br>，霍霍 霍霍霍 霍霍霍 霍家拳的套路招式灵活<br>，活活 活活活 活活活 活着生命就该完整渡过<br>，过过 过过过 过过过 过错软弱从来不属于我<br>，我我 我我我 我我我 我们精武出手无人能躲<br>，我以为世上的武术确实没有高低之分<br>，只有行为人才有强弱之别<br>，不过竞技我们可以发现和认识一个真正的自己<br>，因为我们真正的对手可能就是你自己<br>，霍霍 霍霍霍 霍霍霍 霍家拳的套路招式灵活<br>，活活 活活活 活活活 活着生命就该完整渡过<br>，过过 过过过 过过过 过错软弱从来不属于我<br>，我我 我我我 我我我 我们精武出手无人能躲<br>，霍霍 霍霍霍 霍霍霍 霍家拳的套路招式灵活<br>，活活 活活活 活活活 活着生命就该完整渡过<br>，过过 过过过 过过过 过错软弱从来不属于我<br>，我我 我我我 我我我 <br>，我们精武出手无人能躲 </p>', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (171, '171', '01', '献世（粤语Live版', '周杰伦', '林夕', '金培达', '摇滚/另类 (Rock/Alternative)（原唱', '周杰伦作曲，Live版编曲更重，充满压抑与爆发力', 'e04', '2006-01-20', '霍元甲 EP', '我没有胆挂念　你没有心见面　试问我可以去边，只要我出现　只怕你不便　亦连累你丢脸 ，你是我的秘密　我是你的废物　缺席也不算损失 ，今晚你生日　祝我有今日　地球上快消失，眼泪还是留给天抚慰　你是前度　何必听我吠，再不走　有今生　无下世　你是否想我　起这个毒誓，宁愿失恋亦不想失礼　难道要对着你力歇声嘶，即使不抵　都要眼闭　我这种身世　有甚么资格　献世，，我共你不够熟　眼泪也比较浊　也没气质对你哭，不介意孤独　比爱你舒服　别离就当祝福，，即使不抵　都要眼闭 ，我自卑不怕　有自尊只怕　怕献世', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (172, '172', '01', '黄金甲', '周杰伦', '方文山', '林迈可', '中国风/史诗摇滚 (Chinese Style/Epic Rock)（电影《满城尽带黄金甲》主题曲）', '同《菊花台》时期作品，气势恢宏', 'e05', '2006-12-07', '黄金甲 EP', '旌旗如虹 山堆叠如峰，这军队蜿蜒如龙 杀气如虹 血色如酒红，将军我傲气如冲 神色悍如凶，黄金甲如忠 铁骑剽悍我行如空，景色如冬 萧瑟如枫 攻势如弓，魂断犹如梦中 一静一动 如松 千年不变 如空 如空 如空，血染盔甲我挥泪杀，满城菊花谁的天下，宫廷之上狼烟风沙，生死不过一刀的疤，仇恨绵延如火，愁入眉头如锁，情感漂泊漂泊，漂泊一世如我，今生繁华如昨，兵戎相见如破，千军万马，万马万马奔腾那骨肉相残如错，陈年战事如酒，成败转眼入秋，遍地烽火烽火，烽火回忆如秋，那烽火回忆如秋，那杀缪过重如否，那烽火回忆如秋，皇室血脉如断流，血染盔甲我挥泪杀，满城菊花谁的天下，宫廷之上狼烟风沙，生死不过一刀的疤，血染盔甲我挥泪杀，横刀立马看谁倒下，爱恨对话历史留下，谁在乱箭之中潇洒', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (173, '173', '01', '不能说的秘密', '周杰伦', '方文山', '林迈可', '古典/流行 (Classical/Pop)（电影《不能说的秘密》主题曲）', '钢琴主导，旋律优美，充满时空穿越的奇幻感', 'e06', '2007-08-13', '不能说的秘密 EP', '冷咖啡离开了杯垫，我忍住的情绪在很后面，拼命想挽回的从前，在我脸上依旧清晰可见，最美的不是下雨天，是曾与你躲过雨的屋檐，回忆的画面，在荡著秋千 梦开始不甜，你说把爱渐渐 放下会走更远，又何必去改变 已错过的时间，你用你的指尖 阻止我说再见，想像你在身边 才完全失去之前，你说把爱渐渐 放下会走更远，或许命运的签 只让我们遇见，只让我们相恋 这一季的秋天，飘落后才发现 这幸福的碎片，要我怎麼捡，，冷咖啡离开了杯垫，我忍住的情绪在很后面，拼命想挽回的从前，在我脸上依旧清晰可见，最美的不是下雨天，是曾与你躲过雨的屋檐 oh，回忆的画面，在荡著秋千 梦开始不甜，你说把爱渐渐 放下会走更远，又何必去改变 已错过的时间，你用你的指尖 阻止我说再见，想像你在身边 才完全失去之前，你说把爱渐渐 放下会走更远，或许命运的签 只让我们遇见，只让我们相恋 这一季的秋天，飘落后才发现 这幸福的碎片，要我怎麼捡', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (174, '174', '01', '周大侠', '周杰伦', '方文山', '洪敬尧', '中国风/嘻哈 (Chinese Style/Hip-Hop)', '为电影《满城尽带黄金甲》宣传曲，风格类似《霍元甲》', 'e07', '2007-11-10', '周大侠 EP', '我一脚踢飞一串串红红的葫芦冰糖，我一拳打飞一幕幕的回忆散在月光，一截老老的老姜 一段旧旧的旧时光，我可以给你们一张签名照拿去想象，我说啊 屏风就该遮冰霜 屋檐就该挡月光，江湖就该开扇窗 平剧就该耍花枪，扎下马步我不摇晃，闷了慌了倦了我就穿上功夫装，我不卖豆腐（豆腐） 豆腐（豆腐），我在武功学校里学的那叫功夫，功夫（功夫）功夫（功夫），赶紧穿上旗袍免得你说我吃你豆腐，你就像豆腐（豆腐）豆腐（豆腐）吹弹可破的肌肤在试练我功夫，功夫（功夫） 功夫（功夫），赶紧穿上旗袍免得你说我吃你豆腐，杜国璋，我稍微伸展拳脚 你就滚到边疆，回旋踢太用力 画面就变的很荒凉，落花配对配夕阳 翻山越岭渡过江，我清一清嗓 清一清嗓 唱起秦腔，飞天飞敦煌 北方北大荒，谁在水一方我撑起一把纸伞回头望，周杰伦，啊这什么地方 这什么状况 啦啦啦啦，闷了慌了倦了我就踩在你肩膀，我不卖豆腐（豆腐） 豆腐（豆腐），我在武功学校里学的那叫功夫，功夫（功夫）功夫（功夫），赶紧穿上旗袍免得你说我吃你豆腐，你就像豆腐（豆腐） 豆腐（豆腐），吹弹可破的肌肤在试练我功夫，功夫（功夫) 功夫（功夫），赶紧穿上旗袍免得你说我吃你豆腐', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (175, '175', '01', '千山万水', '周杰伦', '方文山', '钟兴民', '励志中国风 (Inspirational Chinese Style)', '为北京奥运创作，旋律激昂，充满民族自豪感', 'e08', '2008-04-30', '千山万水 EP', '千山万水 无数黑夜 等一轮明月，梦的边陲 风吹不灭 从不感疲惫，东方无愧 第一是谁 让我们追求完美，我态度坚决 面朝北 平地一声雷，做好准备这一回 起跑后绝不撤退，痛快一起努力的感觉 我们拥有同样的机会，梦想夹带眼泪 咸咸的汗水，你我同个世界 爱从中穿越，梦与希望在飞 我向前去追，有目标就不累 等着我超越，东方无愧 第一是谁 让我们追求完美，我态度坚决 面朝北 平地一声雷，做好准备这一回(做好准备这一回)，起跑后绝不撤退(起跑后绝不撤退)，痛快一起努力的感觉 我们拥有同样的机会，梦想夹带眼泪 咸咸的汗水，你我同个世界 爱从中穿越，梦与希望在飞 我向前去追，有目标就不累 等着我超越，梦想夹带眼泪 咸咸的汗水，你我同个世界 爱从中穿越，梦与希望在飞 我向前去追，有目标就不累 等着我超越，远远抛开一切 过千山万水', '2025-10-29 20:21:10', '2025-10-30 20:54:48');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (176, '176', '01', ' 天地一斗', '周杰伦', '方文山', '林迈可', '嘻哈/励志 (Hip-Hop/Inspirational)', '为篮球公益活动创作，节奏感强，鼓励拼搏', 'e09', '2011-02-20', '乐酷·概念合辑 EP', '天地山雨欲来 因为一场胜败，连风都躲在长城之后 屏息而待，众人的喝采 已九霄云外，你们该害怕接下来 我还会更快，Jay Jay Jay Chou，Chou Chou Chou Jay，，Jay Jay Jay Jay Jay Jay Jay Chou，Ko Ko Ko Be，Be Be Be Ko，，Ko Ko Ko Ko Kobe Kobe，，Kobe: So you wanna play ball or sing first?，What What What What Whatever，What What What What Whatever，What What What What Whatever，What What What What Whatever，你是天 我是地 如果合而为一我们天下无敌，你要记 我的名 走路有风这叫做自信，，我深藏不露 我身影如梭 强悍如沙鸥只求 天地一斗，球场夜如墨 街灯亮如昼 只为了驰骋一宿 胜负不皱，我锐利如钩 你防如铁胄 用平分秋色幽了 天地一默，一笑泯恩仇 必争无王寇 我们快意且开阔 多年以后 喔~，，哼 一拳一脚打出自己招牌，别无分号如果你想要拆，首先你反应要比我更快，目前还没这样的人存在，再深的炼狱我都离的开，越热的考验越透心凉快，你想追求未来还是坐在场外，我用最炫的灵感自成一派，，What What What What Whatever，What What What What Whatever，What What What What Whatever，What What What What Whatever，你是天 我是地 如果合而为一我们天下无敌，你要记 我的名 走路有风这叫做自信，Kobe: Man  Jay: I\'m not your man，Kobe : YOU got spark!', '2025-10-29 20:21:10', '2025-10-30 20:53:20');
INSERT INTO `jay_songs` (`id`, `sn`, `song_no`, `song_name`, `composer`, `lyricist`, `arranger`, `style`, `synopsis`, `album_no`, `album_release_date`, `album_name`, `lyrics`, `created_at`, `updated_at`) VALUES (177, '177', '01', '麦烝玮', '周杰伦', '周杰伦', '周杰伦', '嘻哈/友情说唱 (Hip-Hop/Friendship Rap)（与小麦合唱）', '调侃好友小麦，风格幽默轻松', 'e10', '2011-06-07', '乐酷?概念合辑 EP', '我叫小麦 我不会乐器\n所以拿Lara的Kala乱唱\n谢谢gary 耐心帮我录音\n我唱了几百遍还是写不出\n像样的旋律 只好拜托jay\n即兴唱一遍竟然这么好听\n\n我的麦是麦当劳的麦\n我的烝不是蒸小笼包的蒸\n我的玮不是那哥哥爸爸真伟大的伟\n不是那哥哥爸爸真伟大的真伟\n\n我的麦是麦当劳的麦\n我的烝不是蒸小笼包的蒸\n我的玮不是那哥哥爸爸真伟大的伟\n不是那哥哥爸爸真伟大的真伟\n\n杰伦即兴的功力真让我傻眼\n真的没在脑海中考虑那半秒吗\n我真的不信 真的怀疑\n真屌 真强 真佩服\n好多的真真真却不是 麦烝玮的烝\n\n眼睛一样小却不同际遇\n只怪当初我没好好学琴\n反而去跳舞 有什么不对吗\n\n请记得大学那一年 我创了热舞社\n有一天回到了母校 学弟却说学长你好好笑\n我问他为什么好笑 他说他看了Mr.j频道\n各位朋友请记住 我不是那搞笑的 艺人\n\n我的麦是麦当劳的麦\n我的烝不是蒸小笼包的蒸\n我的玮不是那哥哥爸爸真伟大的伟\n不是那哥哥爸爸真伟大的真伟\n\n我的麦是麦当劳的麦\n我的烝不是蒸小笼包的蒸\n我的玮不是那哥哥爸爸真伟大的伟\n不是那哥哥爸爸真伟大的真伟\n\n请记得大学那一年 我创了热舞社\n有一天回到了母校 学弟却说学长你好好笑\n我问他为什么好笑 他说他看了Mr.j频道\n各位朋友请记住 我不是那搞笑的 艺人\n\n我不是搞笑的 我不是搞笑的\n我是练舞出身的 练舞出身的\n我不是搞笑的 我不是搞笑的', '2025-10-29 20:21:10', '2025-10-30 20:48:55');
